export interface ProjectMemoryRecord {
	path: string;
	content: string;
	exists: boolean;
}

export interface ProjectMemoryAdapter {
	getPath(): string;
	read(): string | Promise<string>;
	write(content: string): void | Promise<void>;
}

export const PROJECT_MEMORY_CLASSIFICATION = {
	disposition: "future_shared_capability",
	sharedContract: true,
	hostSpecificExecutor: true,
} as const;

export type ProjectMemoryDisposition = typeof PROJECT_MEMORY_CLASSIFICATION.disposition;

export function defineProjectMemoryAdapter(adapter: ProjectMemoryAdapter): ProjectMemoryAdapter {
	return adapter;
}
