export interface DevRpcBridge {
  call(method: string, args?: unknown): unknown;
}

export interface PieBridge {
  callHost?: (name: string, payload: unknown) => unknown;
  devRpc?: DevRpcBridge;
  getPersistentDataPath?: () => string;
  getProjectRoot(): string;
  isEditor?: boolean;
  log(level: string, message: string): void;
  sendToUnity(event: string, payload: unknown): void;
  getSessionsDirectory?: () => string;
}

interface DevRpcResponse {
  ok?: boolean;
  error?: unknown;
  resultJson?: string;
}

function parseDevRpcResponse(raw: unknown): DevRpcResponse {
  const parsed = typeof raw === "string" ? JSON.parse(raw || "null") : raw;
  return parsed && typeof parsed === "object" ? parsed as DevRpcResponse : {};
}

export function getPieBridge(): PieBridge {
  const bridge = (globalThis as { pieBridge?: PieBridge }).pieBridge;
  if (!bridge) {
    throw new Error("[pie] globalThis.pieBridge not found — was PieBridge.cs initialized?");
  }
  return bridge;
}

export function installDevRpcBridge(bridge: PieBridge): void {
  bridge.devRpc = {
    call(method: string, args: unknown = {}) {
      const raw = bridge.callHost?.("pie.dev_rpc", {
        method,
        argsJson: JSON.stringify(args ?? {}),
      });
      const response = parseDevRpcResponse(raw);
      if (!response?.ok) {
        throw new Error(String(response?.error || `pie.dev_rpc failed: ${method}`));
      }
      return response.resultJson ? JSON.parse(response.resultJson) : null;
    },
  };
}
