/**
 * Session persistence types
 */

import type { AgentMessage } from "@pie/agent-core";
import { formatCompactSummaryText } from "./compaction.js";

/**
 * Tree node entry - represents a message in the conversation tree
 * Has id/parentId for tree structure support
 */
export interface SessionEntry {
	/** Unique entry ID */
	id: string;

	/** Parent entry ID (null for root) */
	parentId: string | null;

	/** Entry type */
	type: "message" | "fork" | "compaction" | "system";

	/** Timestamp */
	timestamp: number;

	/** The message content (for type="message") */
	message?: AgentMessage;

	/** Fork metadata (for type="fork") */
	forkData?: {
		sourceEntryId: string;
		sessionId: string;
		name: string;
	};

	/** Compaction metadata (for type="compaction") */
	compactionData?: {
		summary: string;
		firstKeptEntryId: string;
		tokensBefore?: number;
	};
}

/**
 * Tree node for tree structure operations
 */
export interface SessionTreeNode {
	/** Entry ID */
	id: string;

	/** Parent entry ID */
	parentId: string | null;

	/** Entry data */
	entry: SessionEntry;

	/** Child nodes */
	children: SessionTreeNode[];

	/** Depth in tree */
	depth: number;

	/** Whether this node is on the current active path */
	isActive: boolean;
}

/**
 * Session metadata
 */
export interface SessionMetadata {
	/** Unique session ID */
	id: string;

	/** Display name */
	name: string;

	/** When the session was created */
	createdAt: number;

	/** When the session was last updated */
	updatedAt: number;

	/** Number of entries in the session (not just messages) */
	entryCount: number;

	/** Number of messages */
	messageCount: number;

	/** Current active entry ID (leaf of the tree) */
	activeEntryId: string | null;

	/** Root entry ID */
	rootEntryId: string | null;

	/** Optional: Tags for organization */
	tags?: string[];

	/** Optional: Custom metadata */
	[key: string]: unknown;
}

/**
 * Session data stored to disk (v2 - tree structure)
 */
export interface SessionData {
	/** Session metadata */
	metadata: SessionMetadata;

	/** Session entries (tree structure) */
	entries: SessionEntry[];

	/** 
	 * Linear message path from root to active leaf
	 * @deprecated Kept for backward compatibility, use entries tree instead
	 */
	messages?: AgentMessage[];

	/** Version for migration handling */
	version: number;
}

/**
 * Session store interface (v2 - tree structure)
 */
export interface SessionStore {
	/** Save a session with entries tree */
	save(sessionId: string, entries: SessionEntry[], metadata?: Partial<SessionMetadata>): Promise<void>;

	/** Load a session */
	load(sessionId: string): Promise<SessionData | null>;

	/** Delete a session */
	delete(sessionId: string): Promise<boolean>;

	/** Check if a session exists */
	exists(sessionId: string): Promise<boolean>;

	/** List all session IDs */
	list(): Promise<string[]>;

	/** List all session metadata */
	listMetadata(): Promise<SessionMetadata[]>;

	/** Get session metadata */
	getMetadata(sessionId: string): Promise<SessionMetadata | null>;

	/**
	 * @deprecated Use save with entries instead
	 */
	saveLegacy?(sessionId: string, messages: AgentMessage[], metadata?: Partial<SessionMetadata>): Promise<void>;
}

/**
 * Session manager options
 */
export interface SessionManagerOptions {
	/** Base directory for session storage */
	sessionsDir?: string;

	/** Auto-save interval in ms (0 to disable) */
	autoSaveInterval?: number;

	/** Maximum number of sessions to keep (oldest deleted) */
	maxSessions?: number;

	/** Data format version (2 = tree structure, 1 = legacy linear) */
	version?: number;
}

/**
 * Helper function to generate entry ID
 */
export function generateEntryId(): string {
	const timestamp = Date.now().toString(36);
	const random = Math.random().toString(36).substring(2, 8);
	return `entry-${timestamp}-${random}`;
}

/**
 * Build tree structure from flat entries array
 */
export function buildTree(
	entries: SessionEntry[],
	activeEntryId: string | null,
): SessionTreeNode[] {
	const byId = new Map<string, SessionEntry>();
	const childrenMap = new Map<string, string[]>();

	// Build lookup maps
	for (const entry of entries) {
		byId.set(entry.id, entry);
		if (entry.parentId) {
			const siblings = childrenMap.get(entry.parentId) ?? [];
			siblings.push(entry.id);
			childrenMap.set(entry.parentId, siblings);
		}
	}

	// Find root entries
	const rootIds = entries.filter((e) => e.parentId === null).map((e) => e.id);

	// Build active path
	const activePath = new Set<string>();
	if (activeEntryId) {
		let current: string | null = activeEntryId;
		while (current) {
			activePath.add(current);
			const entry = byId.get(current);
			current = entry?.parentId ?? null;
		}
	}

	// Recursive build function
	function buildNode(entryId: string, depth: number): SessionTreeNode {
		const entry = byId.get(entryId)!;
		const childIds = childrenMap.get(entryId) ?? [];
		return {
			id: entryId,
			parentId: entry.parentId,
			entry,
			children: childIds.map((id) => buildNode(id, depth + 1)),
			depth,
			isActive: activePath.has(entryId),
		};
	}

	return rootIds.map((id) => buildNode(id, 0));
}

/**
 * Flatten tree to linear message path (from root to active leaf)
 */
export function flattenTreeToMessages(
	entries: SessionEntry[],
	activeEntryId: string | null,
): AgentMessage[] {
	const byId = new Map(entries.map((e) => [e.id, e]));
	const messages: AgentMessage[] = [];

	// Build path from active entry to root
	const path: string[] = [];
	let current = activeEntryId;
	while (current) {
		path.unshift(current);
		const entry = byId.get(current);
		current = entry?.parentId ?? null;
	}

	const pathEntries = path
		.map((entryId) => byId.get(entryId))
		.filter((entry): entry is SessionEntry => Boolean(entry));

	const latestCompactionIndex = findLatestCompactionIndex(pathEntries);
	if (latestCompactionIndex === -1) {
		for (const entry of pathEntries) {
			if (entry.type === "message" && entry.message) {
				messages.push(entry.message);
			}
		}
		return messages;
	}

	const compactionEntry = pathEntries[latestCompactionIndex];
	const compactionData = compactionEntry.compactionData;

	if (!compactionData) {
		for (const entry of pathEntries) {
			if (entry.type === "message" && entry.message) {
				messages.push(entry.message);
			}
		}
		return messages;
	}

	messages.push(createCompactionSummaryMessage(compactionData.summary, compactionEntry.timestamp));

	let foundFirstKept = false;
	for (let i = 0; i < latestCompactionIndex; i++) {
		const entry = pathEntries[i];
		if (entry.id === compactionData.firstKeptEntryId) {
			foundFirstKept = true;
		}
		if (foundFirstKept && entry.type === "message" && entry.message) {
			messages.push(entry.message);
		}
	}

	for (let i = latestCompactionIndex + 1; i < pathEntries.length; i++) {
		const entry = pathEntries[i];
		if (entry.type === "message" && entry.message) {
			messages.push(entry.message);
		}
	}

	return messages;
}

function findLatestCompactionIndex(entries: SessionEntry[]): number {
	for (let i = entries.length - 1; i >= 0; i--) {
		if (entries[i].type === "compaction" && entries[i].compactionData) {
			return i;
		}
	}
	return -1;
}

function createCompactionSummaryMessage(summary: string, timestamp: number): AgentMessage {
	return {
		role: "user",
		content: [{ type: "text", text: formatCompactSummaryText(summary) }],
		timestamp,
	};
}

/**
 * Active session state
 */
export interface ActiveSession {
	/** Session ID */
	id: string;

	/** Session metadata */
	metadata: SessionMetadata;

	/** Whether the session has unsaved changes */
	isDirty: boolean;

	/** Last save time */
	lastSavedAt?: number;

	/** Current entries in the tree */
	entries: SessionEntry[];

	/** Current active entry ID */
	activeEntryId: string | null;
}
