/**
 * Node.js FileSystem implementation
 * Uses native Node.js fs and path modules
 *
 * NOTE: Node.js modules are loaded dynamically via require to avoid
 * bundler issues when packaging for non-Node platforms (e.g., Meta Quest).
 * Static imports would cause "Dynamic require not supported" errors.
 */

import type { FileSystem, FileSystemEntry, PlatformType } from "./types.js";
import { detectPlatform } from "./detector.js";
import { createRequire } from "node:module";
import { fileURLToPath } from "node:url";

// Create require function for ESM compatibility
// @ts-ignore - import.meta.url is available in ESM
const __filename = fileURLToPath(import.meta.url);
const require = createRequire(__filename);

// Lazy-loaded Node.js modules - only loaded when actually needed
let nodeFs: typeof import("fs") | null = null;
let nodePath: typeof import("path") | null = null;

function getNodeFs(): typeof import("fs") {
  if (!nodeFs) {
    nodeFs = require("fs");
  }
  return nodeFs!;
}

function getNodePath(): typeof import("path") {
  if (!nodePath) {
    nodePath = require("path");
  }
  return nodePath!;
}

/**
 * Convert Node.js Stats to FileSystemEntry
 */
function convertStats(stats: import("fs").Stats): FileSystemEntry {
  return {
    name: "", // Will be set by caller
    isDirectory: stats.isDirectory(),
    isFile: stats.isFile(),
    size: stats.size,
    mtime: stats.mtime,
  };
}

/**
 * Node.js FileSystem implementation
 */
export class NodeFileSystem implements FileSystem {
  readonly platform: PlatformType = "node";
  sep: string;

  constructor() {
    // Detect actual platform - could be "node" or fallback
    this.platform = detectPlatform();
    this.sep = getNodePath().sep;
  }

  // File operations
  async readFile(path: string, encoding: BufferEncoding = "utf-8"): Promise<string> {
    return getNodeFs().promises.readFile(path, encoding);
  }

  readFileSync(path: string, encoding: BufferEncoding = "utf-8"): string {
    return getNodeFs().readFileSync(path, encoding);
  }

  async writeFile(path: string, data: string, encoding: BufferEncoding = "utf-8"): Promise<void> {
    return getNodeFs().promises.writeFile(path, data, encoding);
  }

  writeFileSync(path: string, data: string, encoding: BufferEncoding = "utf-8"): void {
    getNodeFs().writeFileSync(path, data, encoding);
  }

  // Directory operations
  async mkdir(path: string, options?: { recursive?: boolean }): Promise<void> {
    await getNodeFs().promises.mkdir(path, options);
  }

  mkdirSync(path: string, options?: { recursive?: boolean }): void {
    getNodeFs().mkdirSync(path, options);
  }

  async readdir(path: string): Promise<string[]> {
    return getNodeFs().promises.readdir(path);
  }

  readdirSync(path: string): string[] {
    return getNodeFs().readdirSync(path);
  }

  // Path checks
  async exists(path: string): Promise<boolean> {
    try {
      await getNodeFs().promises.access(path);
      return true;
    } catch {
      return false;
    }
  }

  existsSync(path: string): boolean {
    return getNodeFs().existsSync(path);
  }

  async stat(path: string): Promise<FileSystemEntry> {
    const stats = await getNodeFs().promises.stat(path);
    const entry = convertStats(stats);
    entry.name = getNodePath().basename(path);
    return entry;
  }

  statSync(path: string): FileSystemEntry {
    const stats = getNodeFs().statSync(path);
    const entry = convertStats(stats);
    entry.name = getNodePath().basename(path);
    return entry;
  }

  async access(path: string, mode?: number): Promise<void> {
    await getNodeFs().promises.access(path, mode);
  }

  // File manipulation
  async unlink(path: string): Promise<void> {
    await getNodeFs().promises.unlink(path);
  }

  unlinkSync(path: string): void {
    getNodeFs().unlinkSync(path);
  }

  // Path utilities - delegate to Node.js path module
  join(...paths: string[]): string {
    return getNodePath().join(...paths);
  }

  dirname(path: string): string {
    return getNodePath().dirname(path);
  }

  basename(path: string, ext?: string): string {
    return getNodePath().basename(path, ext);
  }

  extname(path: string): string {
    return getNodePath().extname(path);
  }

  resolve(...paths: string[]): string {
    return getNodePath().resolve(...paths);
  }

  normalize(path: string): string {
    return getNodePath().normalize(path);
  }

  isAbsolute(path: string): boolean {
    return getNodePath().isAbsolute(path);
  }

  relative(from: string, to: string): string {
    return getNodePath().relative(from, to);
  }
}
