import type { Agent } from "@pie/agent-core";
import type { AgentSessionController } from "@pie/agent-framework";
import { clearTodoAfterAbort } from "./agent-event-forwarding.js";
import type { PieBridge } from "./pie-bridge.js";
import type { SessionRecord } from "./session-store.js";
import type { UnitySessionTraceWriter } from "./session-trace.js";
import type { LoopState } from "@pie/shared-headless-capabilities";
import type { createManageTodoListTool } from "./tools/manage-todo-list.js";

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function stringField(value: unknown, key: string): string | undefined {
  return isRecord(value) && typeof value[key] === "string" ? value[key] : undefined;
}

export interface UnityPublicApiHost {
  agent: Agent;
  agentSessionController: AgentSessionController;
  bridge: PieBridge;
  sessionTrace: UnitySessionTraceWriter;
  todoTool: ReturnType<typeof createManageTodoListTool>;
  applyModelSelectionSync(provider: string, modelId: string): void;
  emitSessionSync(): void;
  emitSkillsList(): void;
  getModelStatus(): { baseUrl: string; configured: boolean; modelId: string; provider: string; verboseLogs: boolean };
  getModelSelectionWarning(): string;
  handleLocalCommand(content: string): Promise<boolean>;
  hasConfiguredModelSelection(): boolean;
  loadSession(projectRoot: string, sessionId: string): Promise<SessionRecord | null>;
  persistCurrentSession(): Promise<void>;
  persistCurrentSessionForRecovery(): Promise<void>;
  persistCurrentSessionForRecoveryWithPendingUserMessage(content: string): Promise<void>;
  persistCurrentSessionSafely(): void;
  projectRoot: string;
  promptAgentWithRecovery(input: string): Promise<void>;
  rebuildAgentSurface(): void;
  restoreSessionRecord(record: SessionRecord): void;
  startFreshSession(): void;
  trimInterruptedTail(record: SessionRecord, lastUserText?: string): SessionRecord;
  getTodoLoopState(): LoopState | null;
  setTodoLoopState(loop: LoopState | null): void;
  setVerboseLogs(value: boolean): void;
  setModelSelection(provider: string, modelId: string, apiKey?: string, baseUrl?: string): void;
}

export function installUnityPublicApi(host: UnityPublicApiHost): void {
  (globalThis as { pie?: { handleCSharpMessage(action: string, data: unknown): Promise<void> } }).pie = {
    handleCSharpMessage: async function(action: string, data: unknown): Promise<void> {
      try {
        switch (action) {
          case "send_message": {
            if (!host.hasConfiguredModelSelection()) {
              host.bridge.sendToUnity("error", { message: host.getModelSelectionWarning() });
              break;
            }
            const content = stringField(data, "content") ?? String(data);
            host.sessionTrace.notePendingUserText(content);
            const reminder = host.todoTool.getReminder?.();
            const finalContent = reminder ? `${reminder}${content}` : content;
            if (await host.handleLocalCommand(content)) break;
            await host.persistCurrentSessionForRecoveryWithPendingUserMessage(content);
            host.emitSessionSync();
            host.sessionTrace.noteDispatchStart({ mode: "unity" });
            host.promptAgentWithRecovery(finalContent).catch((err: unknown) => {
              const msg = err instanceof Error ? err.message : String(err);
              host.bridge.log("error", `[pie/index] agent.prompt rejected: ${msg}`);
              host.bridge.sendToUnity("error", { message: msg });
              host.sessionTrace.noteStalled(msg, { mode: "unity" });
              host.sessionTrace.abortTurn(msg);
            }).finally(() => {
              host.sessionTrace.noteDispatchSettled({ mode: "unity" });
            });
            break;
          }
          case "set_config": {
            const apiKey = stringField(data, "apiKey");
            const provider = stringField(data, "provider") || "";
            const model = stringField(data, "model") || "";
            const baseUrl = stringField(data, "baseUrl");
            const verboseLogs = isRecord(data) && data.verboseLogs === true;
            if (isRecord(data) && data.verboseLogs !== undefined) host.setVerboseLogs(verboseLogs);
            host.setModelSelection(provider, model, apiKey, baseUrl);
            host.applyModelSelectionSync(provider, model);
            host.bridge.sendToUnity("config_applied", host.getModelStatus());
            host.persistCurrentSessionSafely();
            break;
          }
          case "new_session":
            await host.persistCurrentSession();
            host.startFreshSession();
            await host.persistCurrentSessionForRecovery();
            break;
          case "resume_session": {
            const sessionId = stringField(data, "sessionId")?.trim() || "";
            if (!sessionId) {
              host.bridge.log("warn", "[pie/index] resume_session called without sessionId");
              break;
            }
            host.bridge.log("info", `[pie/index] resume_session ${sessionId}`);
            const loaded = await host.loadSession(host.projectRoot, sessionId);
            if (loaded) {
              const recoverInterrupted = isRecord(data) && data.recoverInterrupted === true;
              const lastUserText = stringField(data, "lastUserText") || "";
              host.restoreSessionRecord(recoverInterrupted ? host.trimInterruptedTail(loaded, lastUserText) : loaded);
            } else {
              host.bridge.log("warn", `[pie/index] resume_session could not load ${sessionId}`);
            }
            break;
          }
          case "list_skills":
            host.emitSkillsList();
            break;
          case "reload_skills":
            host.rebuildAgentSurface();
            host.emitSkillsList();
            break;
          case "abort":
            host.bridge.log("info", `[pie/index] abort reason=${stringField(data, "reason") || "user"}`);
            host.agentSessionController.abort();
            clearTodoAfterAbort({
              todoTool: host.todoTool,
              getTodoLoopState: host.getTodoLoopState,
              setTodoLoopState: host.setTodoLoopState,
              persistCurrentSessionSafely: host.persistCurrentSessionSafely,
              emitSessionSync: host.emitSessionSync,
            });
            break;
          default:
            host.bridge.log("warn", `[pie/index] Unknown action: ${action}`);
        }
      } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : String(err);
        host.bridge.log("error", `[pie/index] Error in ${action}: ${msg}`);
        host.bridge.sendToUnity("error", { message: msg });
      }
    },
  };
}
