import type { Agent, AgentMessage, AgentToolResult } from "@pie/agent-core";
import {
  attachAgentEventsToSessionTrace,
  evaluateTodoClosureAfterAbort,
  evaluateTodoClosureAfterCompletedTurn,
  evaluateTodoClosureAfterFailedTurn,
  type ExecutionState,
  type LoopState,
} from "@pie/shared-headless-capabilities";
import type { PieBridge } from "./pie-bridge.js";
import type { UnitySessionTraceWriter } from "./session-trace.js";

interface UnityTodoTool {
  getExecutionState(): ExecutionState | null;
  reset(): void;
}

export interface UnityAgentEventForwardingHost {
  agent: Agent;
  bridge: PieBridge;
  sessionTrace: UnitySessionTraceWriter;
  todoTool: UnityTodoTool;
  getTodoLoopState(): LoopState | null;
  setTodoLoopState(loop: LoopState | null): void;
  buildUsagePayload(messages: AgentMessage[], message: AgentMessage, fallbackIndex?: number): unknown;
  collectMessageText(message: AgentMessage): string;
  extractEffectiveArgs(toolName: string, args: unknown, details: unknown): unknown;
  extractToolText(result: AgentToolResult<unknown>): string;
  emitSessionSync(): void;
  persistCurrentSessionSafely(): void;
  refreshTodoLoopState(): void;
  verboseLog(message: string): void;
}

function messageRole(message: AgentMessage): string {
  return typeof message === "object" && message !== null && "role" in message
    ? String((message as { role?: unknown }).role ?? "assistant")
    : "assistant";
}

function messageStopReason(message: AgentMessage, fallback: string): string {
  return typeof message === "object" && message !== null && "stopReason" in message
    ? String((message as { stopReason?: unknown }).stopReason ?? fallback)
    : fallback;
}

function messageErrorText(message: AgentMessage): string {
  return typeof message === "object" && message !== null && "errorMessage" in message
    ? String((message as { errorMessage?: unknown }).errorMessage ?? "Request failed")
    : "Request failed";
}

function textContentFromMessage(message: AgentMessage): string {
  const content = typeof message === "object" && message !== null && "content" in message
    ? (message as { content?: unknown }).content
    : undefined;
  if (!Array.isArray(content)) return "";
  return content
    .filter((block): block is { type: "text"; text?: string } => {
      return !!block && typeof block === "object" && (block as { type?: unknown }).type === "text";
    })
    .map((block) => block.text || "")
    .join("");
}

function assistantEventField(event: unknown, field: "delta" | "content"): string {
  return event && typeof event === "object" && field in event
    ? String((event as Record<string, unknown>)[field] ?? "")
    : "";
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === "object" && !Array.isArray(value);
}

function routeMetaFromToolResult(toolName: string, result: unknown): Record<string, unknown> | null {
  const details = isRecord(result) && isRecord(result.details) ? result.details : undefined;
  if (!details) return null;
  if (toolName === "web_search") {
    return {
      toolName,
      purpose: "web_search",
      providerMode: details.providerMode,
      agentModel: details.agentModel,
      toolModel: details.toolModel,
      routeSource: details.routeSource,
      sourceCount: details.sourceCount,
      failureCategory: details.failureCategory,
      attempts: Array.isArray(details.attempts) ? details.attempts.length : undefined,
    };
  }
  if (toolName === "read_file" && isRecord(details.understanding)) {
    const understanding = details.understanding;
    return {
      toolName,
      purpose: understanding.purpose,
      requiredCapability: understanding.requiredCapability,
      agentModel: understanding.agentModel,
      toolModel: understanding.toolModel,
      routeSource: understanding.routeSource,
      kind: understanding.kind,
      mimeType: understanding.mimeType,
      fallbackReason: understanding.fallbackReason,
    };
  }
  return null;
}

export function bindUnityAgentEventForwarding(host: UnityAgentEventForwardingHost): void {
  const {
    agent,
    bridge,
    sessionTrace,
    todoTool,
  } = host;

  attachAgentEventsToSessionTrace({ agent, trace: sessionTrace });

  agent.subscribe((event) => {
    try {
      switch (event.type) {
        case "agent_start":
          bridge.sendToUnity("state_event", { name: "agent_start", detail: "agent loop started" });
          break;
        case "turn_start":
          bridge.sendToUnity("state_event", { name: "turn_start", detail: "turn started" });
          break;
        case "message_start":
          bridge.sendToUnity("state_event", { name: "message_start", detail: `role=${messageRole(event.message)}` });
          break;
        case "message_update": {
          const msg = event.message;
          const text = textContentFromMessage(msg);
          if (event.assistantMessageEvent?.type === "thinking_start") {
            bridge.sendToUnity("thinking_event", { type: "start" });
          } else if (event.assistantMessageEvent?.type === "thinking_delta") {
            bridge.sendToUnity("thinking_event", {
              type: "delta",
              delta: assistantEventField(event.assistantMessageEvent, "delta"),
            });
          } else if (event.assistantMessageEvent?.type === "thinking_end") {
            bridge.sendToUnity("thinking_event", {
              type: "end",
              text: assistantEventField(event.assistantMessageEvent, "content"),
            });
          }
          bridge.sendToUnity("state_event", {
            name: "message_update",
            detail: `type=${event.assistantMessageEvent?.type ?? "text"} chars=${text.length}`,
          });
          if (text) bridge.sendToUnity("message_update", { type: "text_full", text });
          break;
        }
        case "message_end":
          if (messageRole(event.message) === "assistant") {
            bridge.sendToUnity("message_metrics", {
              role: "assistant",
              usage: host.buildUsagePayload(agent.state.messages || [], event.message),
            });
          }
          bridge.sendToUnity("state_event", { name: "message_end", detail: `role=${messageRole(event.message)}` });
          break;
        case "tool_execution_start":
          host.verboseLog(`[tool_start payload] ${JSON.stringify({
            name: event.toolName,
            callId: event.toolCallId,
            argsJson: JSON.stringify(event.args ?? {}).substring(0, 4000),
          })}`);
          bridge.sendToUnity("tool_start", {
            name: event.toolName,
            callId: event.toolCallId,
            argsJson: JSON.stringify(event.args ?? {}).substring(0, 4000),
          });
          break;
        case "tool_execution_end": {
          const effectiveArgs = host.extractEffectiveArgs(event.toolName, event.args, event.result?.details);
          const resultText = host.extractToolText(event.result).substring(0, 4000);
          const routeMeta = routeMetaFromToolResult(event.toolName, event.result);
          if (routeMeta) {
            sessionTrace.noteRuntimeEvent("tool_model_route_selected", routeMeta);
            if (event.toolName === "web_search") {
              sessionTrace.noteRuntimeEvent("web_search_attempts", routeMeta);
            } else if (event.toolName === "read_file") {
              sessionTrace.noteRuntimeEvent("read_file_understanding", routeMeta);
            }
          }
          bridge.sendToUnity("tool_end", {
            name: event.toolName,
            callId: event.toolCallId,
            argsJson: JSON.stringify(event.args ?? {}).substring(0, 4000),
            effectiveArgsJson: JSON.stringify(effectiveArgs ?? {}).substring(0, 4000),
            isError: event.isError,
            resultText,
            resultJson: JSON.stringify(event.result ?? "").substring(0, 4000),
            detailsJson: event.result?.details !== undefined ? JSON.stringify(event.result.details).substring(0, 4000) : "",
            error: event.isError
                ? resultText || "Tool returned an error result."
                : undefined,
          });
          break;
        }
        case "agent_end":
          bridge.sendToUnity("state_event", { name: "agent_end", detail: "agent loop finished" });
          bridge.sendToUnity("agent_end", {});
          break;
      }
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      bridge.log("error", `[pie/index] Event forwarding error: ${message}`);
    }
  });

  agent.subscribeSemantic((event) => {
    try {
      switch (event.type) {
        case "status_snapshot_changed":
          bridge.sendToUnity("status_snapshot", event.snapshot);
          break;
        case "turn_continues":
          host.persistCurrentSessionSafely();
          host.refreshTodoLoopState();
          bridge.sendToUnity("state_event", {
            name: "turn_continues",
            detail: `stopReason=${messageStopReason(event.message, "toolUse")}`,
          });
          break;
        case "turn_completed": {
          host.persistCurrentSessionSafely();
          host.refreshTodoLoopState();
          bridge.sendToUnity("turn_end", {
            role: messageRole(event.message),
            stopReason: messageStopReason(event.message, "stop"),
          });
          bridge.sendToUnity("state_event", {
            name: "turn_completed",
            detail: `stopReason=${messageStopReason(event.message, "stop")}`,
          });
          const executionState = todoTool.getExecutionState();
          const todoLoopState = host.getTodoLoopState();
          if (executionState && todoLoopState) {
            const assistantText = host.collectMessageText(event.message);
            const decision = evaluateTodoClosureAfterCompletedTurn(executionState, todoLoopState, {
              completedCount: executionState.steps.filter((step) => step.status === "completed").length,
              remainingCount: executionState.steps.filter((step) => step.status !== "completed").length,
              currentStepId: executionState.currentStepId,
              hasSuccessfulToolResult: (event.toolResults || []).some((result) => !result?.isError),
              hasAssistantText: assistantText.trim().length > 0,
              hasCompletionText: /完成|已完成|done|finished|completed|wrap[\s-]?up|all set|success/i.test(assistantText),
            });
            host.setTodoLoopState(decision.loop);
            if (decision.action === "continue" && decision.followUpPrompt) {
              agent.followUp({ role: "user", content: decision.followUpPrompt, timestamp: Date.now() });
              bridge.sendToUnity("state_event", { name: "todo_follow_up_queued", detail: "queued todo closure follow-up" });
            } else if (decision.action === "clear_completed") {
              todoTool.reset();
              host.setTodoLoopState(null);
              host.persistCurrentSessionSafely();
              host.emitSessionSync();
            } else if (decision.action === "clear_failed" || decision.action === "clear_stalled") {
              todoTool.reset();
              host.setTodoLoopState(null);
              host.persistCurrentSessionSafely();
              host.emitSessionSync();
              bridge.sendToUnity("error", {
                message: decision.action === "clear_stalled"
                  ? "Todo run stalled and was cleared."
                  : "Todo run failed and was cleared.",
              });
            }
          }
          break;
        }
        case "turn_failed": {
          const stopReason = messageStopReason(event.message, "error");
          const errMsg: string = messageErrorText(event.message);
          host.persistCurrentSessionSafely();
          const decision = evaluateTodoClosureAfterFailedTurn(host.getTodoLoopState());
          host.setTodoLoopState(decision.loop);
          if (decision.action === "clear_failed") {
            todoTool.reset();
            host.setTodoLoopState(null);
            host.persistCurrentSessionSafely();
            host.emitSessionSync();
          }
          bridge.sendToUnity("turn_end", { role: messageRole(event.message), stopReason });
          bridge.sendToUnity("state_event", { name: "turn_failed", detail: `stopReason=${stopReason}` });
          bridge.sendToUnity("error", { message: errMsg });
          break;
        }
      }
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : String(err);
      bridge.log("error", `[pie/index] Semantic event forwarding error: ${message}`);
    }
  });
}

export function clearTodoAfterAbort(host: Pick<UnityAgentEventForwardingHost, "getTodoLoopState" | "setTodoLoopState" | "todoTool" | "persistCurrentSessionSafely" | "emitSessionSync">): void {
  const decision = evaluateTodoClosureAfterAbort(host.getTodoLoopState());
  if (decision.action === "clear_aborted") {
    host.todoTool.reset();
    host.setTodoLoopState(null);
    host.persistCurrentSessionSafely();
    host.emitSessionSync();
  }
}
