import { Type, type TSchema } from "@sinclair/typebox";
import { getAvailableRoots, getDefaultRootName, type PathResolutionOptions } from "./path-utils.js";

function formatPrefixes(prefixes: string[] | undefined): string {
	if (!prefixes || prefixes.length === 0) {
		return "";
	}

	return prefixes
		.map((prefix) => {
			const trimmed = prefix.trim();
			return trimmed.endsWith("/") ? trimmed : `${trimmed}/`;
		})
		.join(", ");
}

export function buildRootParameterSchema(
	sandboxRoot: string,
	options?: PathResolutionOptions,
): TSchema | undefined {
	const roots = getAvailableRoots(options);
	if (roots.length === 0) {
		return undefined;
	}

	const defaultRoot = getDefaultRootName(sandboxRoot, options);
	const description = [
		`Optional root name to resolve the path against. Available roots: ${roots.map((root) => root.name).join(", ")}.`,
		defaultRoot ? `When omitted, the default root is '${defaultRoot}' unless a prefix rule matches first.` : "",
	]
		.filter(Boolean)
		.join(" ");

	if (roots.length === 1) {
		return Type.Optional(Type.Literal(roots[0].name, { description }));
	}

	return Type.Optional(
		Type.Union(
			roots.map((root) => Type.Literal(root.name)),
			{ description },
		),
	);
}

export function buildPathResolutionDescription(
	sandboxRoot: string,
	options?: PathResolutionOptions,
): string {
	const roots = getAvailableRoots(options);
	const allowlistedDirs = options?.allowlistedDirs ?? [];
	const hasGlobalAllowlist = allowlistedDirs.some((dir) => dir.trim() === "/");
	const allowlistSentence = hasGlobalAllowlist
		? "Absolute paths anywhere on the local filesystem are accepted in the current runtime mode."
		: allowlistedDirs.length > 0
			? `Absolute paths inside allowlisted directories are accepted: ${allowlistedDirs.join(", ")}.`
			: "";
	if (roots.length === 0) {
		return ["Relative paths resolve against the workspace root.", allowlistSentence].filter(Boolean).join(" ");
	}

	const rootSummaries = roots.map((root) => {
		const pieces = [`'${root.name}'`];
		if (root.description) {
			pieces.push(root.description);
		}
		const prefixes = formatPrefixes(root.defaultPrefixes);
		if (prefixes) {
			pieces.push(`prefixes: ${prefixes}`);
		}
		return pieces.join(" - ");
	});

	const defaultRoot = getDefaultRootName(sandboxRoot, options);
	const hasPrefixRules = roots.some((root) => (root.defaultPrefixes?.length ?? 0) > 0);
	const defaultSentence = defaultRoot
		? hasPrefixRules
			? `When root is omitted, prefix-matched roots win first; otherwise '${defaultRoot}' is used.`
			: `When root is omitted, '${defaultRoot}' is used.`
		: "";

	return `Available roots: ${rootSummaries.join("; ")}. ${defaultSentence} ${allowlistSentence}`.trim();
}
