import type { CommandDefinition, InteractionRequest } from "@pie/agent-framework";

export interface SharedCapabilityExtensionContribution {
	name: string;
	description?: string;
}

export interface SharedCapabilityDefinition<TTool = unknown> {
	id: string;
	description: string;
	tools?: readonly TTool[];
	commands?: readonly CommandDefinition[];
	extensions?: readonly SharedCapabilityExtensionContribution[];
	requiredInteractions?: readonly InteractionRequest["type"][];
	systemPromptAdditions?: readonly string[];
}

export function defineSharedCapability<TTool = unknown>(
	definition: SharedCapabilityDefinition<TTool>,
): SharedCapabilityDefinition<TTool> {
	return definition;
}

export function collectSharedCapabilityPromptAdditions<TTool extends { name?: string }>(
	definitions: readonly SharedCapabilityDefinition<TTool>[],
	activeToolNames?: readonly string[],
): string[] {
	const activeTools = activeToolNames ? new Set(activeToolNames) : null;
	const additions = new Set<string>();

	for (const definition of definitions) {
		if (!definition.systemPromptAdditions?.length) continue;
		if (activeTools && definition.tools?.length) {
			const hasActiveTool = definition.tools.some((tool) => {
				return typeof tool?.name === "string" && activeTools.has(tool.name);
			});
			if (!hasActiveTool) continue;
		}
		for (const addition of definition.systemPromptAdditions) {
			const trimmed = addition.trim();
			if (trimmed) additions.add(trimmed);
		}
	}

	return [...additions];
}
