import { createLogger, setLogger, type LogSink, type Logger } from "@pie/platform";

interface UnityBridgeLike {
  log(level: "info" | "warn" | "error", message: string): void;
}

class UnityBridgeSink implements LogSink {
  constructor(private readonly bridge: UnityBridgeLike) {}

  log(entry: import("@pie/platform").LogEntry): void {
    const moduleName = String(entry.context?.module || "unity");
    const payload = entry.context ? ` ${JSON.stringify(entry.context)}` : "";
    const line = `[${entry.level.toUpperCase()}] [${moduleName}] ${entry.message}${payload}`;
    if (entry.level === "error" || entry.level === "fatal") {
      this.bridge.log("error", line);
    } else if (entry.level === "warn") {
      this.bridge.log("warn", line);
    } else {
      this.bridge.log("info", line);
    }
  }
}

export function initializeUnityLogger(bridge: UnityBridgeLike): Logger {
  const logger = createLogger({
    mode: "unity_host",
    sinks: [new UnityBridgeSink(bridge)],
    minLevel: "info",
  });
  setLogger(logger);
  return logger;
}
