import type { ExecutionState } from "./execution-state.js";

export type LoopMode = "todo_closure";
export type LoopStatus = "active" | "completed" | "aborted" | "failed" | "stalled";

export interface LoopBreakoutCondition {
	type: "todo_empty";
}

export interface LoopSuccessSignal {
	type: "todo_cleared";
}

export interface LoopState {
	goal: string;
	mode: LoopMode;
	breakoutCondition: LoopBreakoutCondition;
	continuePrompt: string;
	successSignal: LoopSuccessSignal;
	status: LoopStatus;
	attemptCount: number;
	maxAttempts: number;
	stagnationCount: number;
	lastProgressMarker: string | null;
	updatedAt: string;
}

export interface LoopProgressSample {
	completedCount: number;
	remainingCount: number;
	currentStepId: number | null;
	hasSuccessfulToolResult: boolean;
	hasAssistantText: boolean;
	hasCompletionText: boolean;
}

export interface LoopContinuationDecision {
	loop: LoopState | null;
	action: "none" | "continue" | "clear_completed" | "clear_aborted" | "clear_failed" | "clear_stalled";
	reason:
		| "already_terminal"
		| "todo_empty"
		| "todo_completed"
		| "progressed"
		| "stagnated"
		| "max_attempts"
		| "failed_turn"
		| "aborted"
		| "not_todo";
	followUpPrompt?: string;
}

function nowIso(): string {
	return new Date().toISOString();
}

function countCompleted(state: ExecutionState): number {
	return state.steps.filter((step) => step.status === "completed").length;
}

function buildProgressMarker(state: ExecutionState): string {
	return JSON.stringify({
		completed: countCompleted(state),
		currentStepId: state.currentStepId,
		remaining: state.steps.filter((step) => step.status !== "completed").map((step) => step.id),
	});
}

function hasTextualProgress(sample: LoopProgressSample): boolean {
	return sample.hasSuccessfulToolResult || sample.hasCompletionText;
}

export function buildTodoClosureContinuePrompt(state: ExecutionState): string {
	const current = state.steps.find((step) => step.id === state.currentStepId);
	const remaining = state.steps.filter((step) => step.status !== "completed");
	const lines = [
		"[Todo follow-up]",
		"An active todo list exists and must be closed out before this task can finish.",
		"Continue executing the remaining todo items.",
		"Do not stop with a partially completed or in-progress todo list.",
		"After finishing the current item, call manage_todo_list with action=complete_current; the tool will advance to the next item or clear the list after the final item.",
		"Only call complete_current after the current item is actually satisfied. If the latest required install, build, test, or verification command failed, do not mark that item complete; inspect the error, retry or fix it, or clear the todo list with a reason if blocked.",
		"If the task cannot continue, explicitly explain the failure or abort condition and call manage_todo_list with action=clear and a reason.",
	];
	if (current) {
		lines.push(`Current todo item: ${current.title}`);
	}
	if (remaining.length > 0) {
		lines.push(`Remaining todo items: ${remaining.map((step) => step.title).join("; ")}`);
	}
	return lines.join("\n");
}

export function createTodoClosureLoop(state: ExecutionState): LoopState | null {
	if (state.mode !== "todo" || state.steps.length === 0 || state.lifecycle !== "active") {
		return null;
	}
	const maxAttempts = state.steps.length >= 5 ? 10 : 6;
	return {
		goal: "Drive the active todo list to a terminal cleared state.",
		mode: "todo_closure",
		breakoutCondition: { type: "todo_empty" },
		continuePrompt: buildTodoClosureContinuePrompt(state),
		successSignal: { type: "todo_cleared" },
		status: "active",
		attemptCount: 0,
		maxAttempts,
		stagnationCount: 0,
		lastProgressMarker: buildProgressMarker(state),
		updatedAt: nowIso(),
	};
}

export function restoreLoopState(raw: unknown): LoopState | null {
	if (!raw || typeof raw !== "object") return null;
	const value = raw as Partial<LoopState>;
	if (value.mode !== "todo_closure") return null;
	const status = value.status === "active" || value.status === "completed" || value.status === "aborted"
		|| value.status === "failed" || value.status === "stalled"
		? value.status
		: "active";
	return {
		goal: typeof value.goal === "string" && value.goal.trim().length > 0
			? value.goal
			: "Drive the active todo list to a terminal cleared state.",
		mode: "todo_closure",
		breakoutCondition: { type: "todo_empty" },
		continuePrompt: typeof value.continuePrompt === "string" && value.continuePrompt.trim().length > 0
			? value.continuePrompt
			: "",
		successSignal: { type: "todo_cleared" },
		status,
		attemptCount: Number.isInteger(value.attemptCount) && (value.attemptCount as number) >= 0 ? value.attemptCount as number : 0,
		maxAttempts: Number.isInteger(value.maxAttempts) && (value.maxAttempts as number) > 0 ? value.maxAttempts as number : 6,
		stagnationCount: Number.isInteger(value.stagnationCount) && (value.stagnationCount as number) >= 0 ? value.stagnationCount as number : 0,
		lastProgressMarker: typeof value.lastProgressMarker === "string" ? value.lastProgressMarker : null,
		updatedAt: typeof value.updatedAt === "string" && value.updatedAt.length > 0 ? value.updatedAt : nowIso(),
	};
}

export function evaluateTodoClosureAfterCompletedTurn(
	state: ExecutionState,
	loop: LoopState | null,
	sample: LoopProgressSample,
): LoopContinuationDecision {
	if (state.mode !== "todo") {
		return { loop: null, action: "none", reason: "not_todo" };
	}
	if (!loop || loop.status !== "active") {
		return { loop, action: "none", reason: "already_terminal" };
	}
	if (state.steps.length === 0) {
		return {
			loop: { ...loop, status: "completed", updatedAt: nowIso() },
			action: "clear_completed",
			reason: "todo_empty",
		};
	}
	if (state.lifecycle === "completed") {
		return {
			loop: { ...loop, status: "completed", updatedAt: nowIso() },
			action: "clear_completed",
			reason: "todo_completed",
		};
	}

	const nextMarker = buildProgressMarker(state);
	const progressed = loop.lastProgressMarker !== nextMarker || hasTextualProgress(sample);
	const nextLoop: LoopState = {
		...loop,
		continuePrompt: buildTodoClosureContinuePrompt(state),
		attemptCount: loop.attemptCount + 1,
		stagnationCount: progressed ? 0 : loop.stagnationCount + 1,
		lastProgressMarker: nextMarker,
		updatedAt: nowIso(),
	};
	if (nextLoop.attemptCount >= nextLoop.maxAttempts) {
		return {
			loop: { ...nextLoop, status: "failed" },
			action: "clear_failed",
			reason: "max_attempts",
		};
	}
	if (nextLoop.stagnationCount >= 2) {
		return {
			loop: { ...nextLoop, status: "stalled" },
			action: "clear_stalled",
			reason: "stagnated",
		};
	}
	return {
		loop: nextLoop,
		action: "continue",
		reason: progressed ? "progressed" : "stagnated",
		followUpPrompt: nextLoop.continuePrompt,
	};
}

export function evaluateTodoClosureAfterFailedTurn(loop: LoopState | null): LoopContinuationDecision {
	if (!loop || loop.status !== "active") {
		return { loop, action: "none", reason: "already_terminal" };
	}
	return {
		loop: { ...loop, status: "failed", updatedAt: nowIso() },
		action: "clear_failed",
		reason: "failed_turn",
	};
}

export function evaluateTodoClosureAfterAbort(loop: LoopState | null): LoopContinuationDecision {
	if (!loop || loop.status !== "active") {
		return { loop, action: "none", reason: "already_terminal" };
	}
	return {
		loop: { ...loop, status: "aborted", updatedAt: nowIso() },
		action: "clear_aborted",
		reason: "aborted",
	};
}
