import type { AgentMessage } from "@pie/agent-core";
import {
  createSessionManager,
  flattenTreeToMessages,
  type SessionData,
  type SessionMetadata,
} from "@pie/agent-framework";
import type { TodoItem } from "@pie/shared-headless-capabilities";
import { FileSystemGateway, getPlatformConfig } from "@pie/platform";

export interface SessionSummary {
  id: string;
  title: string;
  createdAt: string;
  updatedAt: string;
  parentSessionId?: string;
  provider: string;
  modelId: string;
  messageCount: number;
}

export interface SessionRecord extends SessionSummary {
  messages: AgentMessage[];
  todoState: TodoItem[];
}

interface UnitySessionMetadata extends SessionMetadata {
  provider?: string;
  modelId?: string;
  parentSessionId?: string;
  todoState?: TodoItem[];
}

export function getSessionsDir(projectRoot: string): string {
  const fromBridge = (globalThis as { pieBridge?: { getSessionsDirectory?: () => unknown } }).pieBridge?.getSessionsDirectory?.();
  if (typeof fromBridge === "string" && fromBridge.length > 0) {
    return fromBridge;
  }
  return getPlatformConfig().sessionsPath;
}

function getSessionGateway(projectRoot: string): FileSystemGateway {
  const sessionsDir = getSessionsDir(projectRoot);
  return new FileSystemGateway({
    allowedRoots: [sessionsDir, getPlatformConfig().dataPath],
  });
}

function ensureSessionsDir(projectRoot: string): string {
  const dir = getSessionsDir(projectRoot);
  const gateway = getSessionGateway(projectRoot);
  if (!gateway.exists(dir)) {
    gateway.mkdir(dir, { recursive: true });
  }
  return dir;
}

function getSessionPath(projectRoot: string, sessionId: string): string {
  const safeId = sessionId.replace(/[^a-zA-Z0-9_-]/g, "_");
  return getSessionGateway(projectRoot).join(getSessionsDir(projectRoot), `${safeId}.json`);
}

function isoNow(): string {
  return new Date().toISOString();
}

function createSessionId(): string {
  return `sess_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 8)}`;
}

function deriveTitle(messages: AgentMessage[]): string {
  const firstUser = messages.find((message) => {
    return typeof message === "object" && message !== null && "role" in message && message.role === "user";
  });
  if (!firstUser) return "New Session";

  const contentValue = typeof firstUser === "object" && firstUser !== null && "content" in firstUser
    ? firstUser.content
    : undefined;
  const content = Array.isArray(contentValue)
    ? contentValue
        .filter((block): block is { type: "text"; text: string } => {
          return !!block
            && typeof block === "object"
            && (block as { type?: unknown }).type === "text"
            && typeof (block as { text?: unknown }).text === "string";
        })
        .map((block) => block.text)
        .join(" ")
    : "";
  const compact = String(content || "New Session").replace(/\s+/g, " ").trim();
  return compact.slice(0, 48) || "New Session";
}

function toIsoString(value: unknown): string {
  if (typeof value === "string" && value.length > 0) {
    return value;
  }
  if (typeof value === "number" && Number.isFinite(value)) {
    return new Date(value).toISOString();
  }
  return isoNow();
}

function toTimestamp(value: unknown, fallback: number): number {
  if (typeof value === "number" && Number.isFinite(value)) {
    return value;
  }
  if (typeof value === "string") {
    const parsed = Date.parse(value);
    if (!Number.isNaN(parsed)) {
      return parsed;
    }
  }
  return fallback;
}

function normalizeTodoState(value: unknown): TodoItem[] {
  return Array.isArray(value) ? value : [];
}

function isFrameworkSessionData(value: unknown): value is SessionData {
  return !!value
    && typeof value === "object"
    && "metadata" in value
    && "entries" in value
    && Array.isArray((value as { entries?: unknown }).entries);
}

function isLegacySessionRecord(value: unknown): value is SessionRecord {
  return !!value
    && typeof value === "object"
    && typeof (value as { id?: unknown }).id === "string"
    && Array.isArray((value as { messages?: unknown }).messages);
}

function normalizeLegacySessionRecord(record: SessionRecord): SessionRecord {
  const messages = Array.isArray(record.messages) ? record.messages : [];
  const todoState = normalizeTodoState(record.todoState);
  const title = deriveTitle(messages);

  return {
    id: record.id,
    title,
    createdAt: toIsoString(record.createdAt),
    updatedAt: toIsoString(record.updatedAt),
    parentSessionId: record.parentSessionId,
    provider: record.provider || "openai",
    modelId: record.modelId || "unknown",
    messageCount: messages.length,
    messages,
    todoState,
  };
}

function toSessionRecordFromFramework(data: SessionData): SessionRecord {
  const metadata = (data.metadata || {}) as UnitySessionMetadata;
  const messages = data.messages || flattenTreeToMessages(data.entries || [], data.metadata.activeEntryId ?? null);
  const title = typeof metadata.name === "string" && metadata.name.length > 0
    ? metadata.name
    : deriveTitle(messages);

  return {
    id: data.metadata.id,
    title,
    createdAt: toIsoString(data.metadata.createdAt),
    updatedAt: toIsoString(data.metadata.updatedAt),
    parentSessionId: typeof metadata.parentSessionId === "string" ? metadata.parentSessionId : undefined,
    provider: typeof metadata.provider === "string" ? metadata.provider : "openai",
    modelId: typeof metadata.modelId === "string" ? metadata.modelId : "unknown",
    messageCount: messages.length,
    messages,
    todoState: normalizeTodoState(metadata.todoState),
  };
}

function readRawStoredSession(projectRoot: string, sessionId: string): SessionData | SessionRecord | null {
  const gateway = getSessionGateway(projectRoot);
  const path = getSessionPath(projectRoot, sessionId);
  if (!gateway.exists(path)) {
    return null;
  }

  try {
    return JSON.parse(gateway.readFile(path, "utf-8"));
  } catch {
    return null;
  }
}

function listSessionIds(projectRoot: string): string[] {
  const gateway = getSessionGateway(projectRoot);
  const dir = ensureSessionsDir(projectRoot);
  return gateway.readdir(dir)
    .filter((file) => file.endsWith(".json"))
    .filter((file) => !file.endsWith("-files.json"))
    .map((file) => file.replace(/\.json$/i, ""));
}

function createManager(projectRoot: string) {
  return createSessionManager({
    sessionsDir: getSessionsDir(projectRoot),
    autoSaveInterval: 0,
  });
}

export function createSessionRecord(params: {
  sessionId?: string;
  parentSessionId?: string;
  provider: string;
  modelId: string;
  messages: AgentMessage[];
  todoState: TodoItem[];
}): SessionRecord {
  const now = isoNow();
  return {
    id: params.sessionId || createSessionId(),
    title: deriveTitle(params.messages),
    createdAt: now,
    updatedAt: now,
    parentSessionId: params.parentSessionId,
    provider: params.provider,
    modelId: params.modelId,
    messageCount: params.messages.length,
    messages: params.messages,
    todoState: normalizeTodoState(params.todoState),
  };
}

export function isSessionEmpty(record: Pick<SessionRecord, "messages" | "todoState"> | null | undefined): boolean {
  if (!record) return true;
  const messageCount = Array.isArray(record.messages) ? record.messages.length : 0;
  const todoCount = Array.isArray(record.todoState) ? record.todoState.length : 0;
  return messageCount === 0 && todoCount === 0;
}

export async function saveSession(projectRoot: string, record: SessionRecord): Promise<SessionRecord> {
  ensureSessionsDir(projectRoot);

  const existing = await loadSession(projectRoot, record.id);
  const normalized: SessionRecord = {
    ...record,
    createdAt: existing?.createdAt || toIsoString(record.createdAt),
    updatedAt: isoNow(),
    title: deriveTitle(record.messages || []),
    messageCount: Array.isArray(record.messages) ? record.messages.length : 0,
    todoState: normalizeTodoState(record.todoState),
  };

  if (isSessionEmpty(normalized)) {
    await deleteSession(projectRoot, normalized.id);
    return normalized;
  }

  const manager = createManager(projectRoot);
  try {
    await manager.createSession(normalized.title, undefined, normalized.id);
    manager.updateMessages(normalized.messages);
    const active = manager.getActiveSession();
    if (active) {
      const metadata = active.metadata as UnitySessionMetadata;
      metadata.name = normalized.title;
      metadata.createdAt = toTimestamp(normalized.createdAt, Date.now());
      metadata.updatedAt = toTimestamp(normalized.updatedAt, Date.now());
      metadata.parentSessionId = normalized.parentSessionId;
      metadata.provider = normalized.provider;
      metadata.modelId = normalized.modelId;
      metadata.todoState = normalizeTodoState(normalized.todoState);
    }
    await manager.save();
  } finally {
    manager.dispose();
  }

  return normalized;
}

export async function deleteSession(projectRoot: string, sessionId: string): Promise<void> {
  const manager = createManager(projectRoot);
  try {
    await manager.deleteSession(sessionId);
  } finally {
    manager.dispose();
  }
}

export async function loadSession(projectRoot: string, sessionId: string): Promise<SessionRecord | null> {
  const raw = readRawStoredSession(projectRoot, sessionId);
  if (!raw) {
    return null;
  }

  if (isLegacySessionRecord(raw) && !isFrameworkSessionData(raw)) {
    return normalizeLegacySessionRecord(raw);
  }

  const manager = createManager(projectRoot);
  try {
    const loaded = await manager.loadSession(sessionId);
    if (!loaded) {
      return null;
    }
    const active = manager.getActiveSession();
    if (!active) {
      return null;
    }
    return toSessionRecordFromFramework({
      version: 2,
      metadata: active.metadata,
      entries: active.entries,
      messages: manager.getMessages(),
    });
  } finally {
    manager.dispose();
  }
}

export async function listSessions(projectRoot: string): Promise<SessionSummary[]> {
  const sessions: SessionSummary[] = [];

  for (const sessionId of listSessionIds(projectRoot)) {
    const session = await loadSession(projectRoot, sessionId);
    if (!session || isSessionEmpty(session)) {
      continue;
    }
    sessions.push({
      id: session.id,
      title: session.title,
      createdAt: session.createdAt,
      updatedAt: session.updatedAt,
      parentSessionId: session.parentSessionId,
      provider: session.provider,
      modelId: session.modelId,
      messageCount: session.messageCount,
    });
  }

  sessions.sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));
  return sessions;
}

export async function formatSessionTree(projectRoot: string): Promise<string> {
  const sessions = await listSessions(projectRoot);
  if (sessions.length === 0) return "No saved sessions.";

  const children = new Map<string, SessionSummary[]>();
  const roots: SessionSummary[] = [];

  for (const session of sessions) {
    if (!session.parentSessionId) {
      roots.push(session);
      continue;
    }
    const bucket = children.get(session.parentSessionId) || [];
    bucket.push(session);
    children.set(session.parentSessionId, bucket);
  }

  const lines: string[] = [];
  function render(node: SessionSummary, depth: number) {
    const indent = "  ".repeat(depth);
    lines.push(`${indent}- ${node.id} | ${node.title} | ${node.modelId} | ${node.updatedAt}`);
    const childSessions = children.get(node.id) || [];
    childSessions.sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));
    for (const child of childSessions) render(child, depth + 1);
  }

  roots.sort((a, b) => String(b.updatedAt).localeCompare(String(a.updatedAt)));
  for (const root of roots) render(root, 0);

  return lines.join("\n");
}
