import {
	type SessionTraceFile,
	SessionTraceSnapshotWriter,
} from "@pie/shared-headless-capabilities";
import { getSessionsDir } from "./session-store.js";

type UnityFileApi = {
	Exists(path: string): boolean;
	ReadAllText(path: string): string;
	WriteAllText(path: string, content: string): void;
};

type UnityDirectoryApi = {
	CreateDirectory(path: string): unknown;
};

type UnityPathApi = {
	Combine(left: string, right: string): string;
};

declare const CS: {
	System: {
		IO: {
			Path: UnityPathApi;
			File: UnityFileApi;
			Directory: UnityDirectoryApi;
		};
	};
};

function normalizePath(value: string): string {
	return String(value || "").replace(/\\/g, "/");
}

export class UnitySessionTraceWriter extends SessionTraceSnapshotWriter {
	constructor(
		private readonly projectRoot: string,
		private readonly getSessionId: () => string | null | undefined,
	) {
		super({
			getSessionId: () => getSessionId(),
			loadTrace: (sessionId) => {
				const tracePath = normalizePath(CS.System.IO.Path.Combine(getSessionsDir(projectRoot), `${sessionId}.trace.json`));
				if (!CS.System.IO.File.Exists(tracePath)) return null;
				try {
					return JSON.parse(String(CS.System.IO.File.ReadAllText(tracePath) ?? "")) as SessionTraceFile;
				} catch {
					return null;
				}
			},
			saveTrace: (trace) => {
				const sessionsDir = getSessionsDir(projectRoot);
				CS.System.IO.Directory.CreateDirectory(sessionsDir);
				const tracePath = normalizePath(CS.System.IO.Path.Combine(sessionsDir, `${trace.sessionId}.trace.json`));
				CS.System.IO.File.WriteAllText(tracePath, JSON.stringify(trace, null, 2));
			},
		});
	}
}
