// Side-effect import: registers openai-completions + anthropic-messages providers
import "@pie/ai";
import { Agent }              from "@pie/agent-core";
import type { AgentMessage }     from "@pie/agent-core";
import {
  createTodoClosureLoop,
  type LoopState,
} from "@pie/shared-headless-capabilities";
import { setHttpClient }      from "@pie/platform";
import { UnityHttpClient }    from "./unity-http-client.js";
import { initializeUnityLogger } from "./unity-logger.js";
import { createManageTodoListTool } from "./tools/manage-todo-list.js";
import { buildFileToolPathOptions } from "./file-tool-roots.js";
import { createUnityAgentSurface } from "./agent-surface.js";
import { registerUnityInteractionBinding } from "./interaction-binding.js";
import { getAvailableSkills } from "./skills.js";
import { createSessionRecord, loadSession, type SessionRecord } from "./session-store.js";
import { createSessionRuntime } from "./session-runtime.js";
import { createUnityAgentSessionController } from "./session-controller-adapter.js";
import { loadProjectExtensions } from "./extensions/load-project-extensions.js";
import { installUnityScriptHost } from "./unity-script-host.js";
import { UnitySessionTraceWriter } from "./session-trace.js";
import { getPieBridge, installDevRpcBridge } from "./pie-bridge.js";
import { createRuntimeConfiguredModel, createUnconfiguredModel, getDefaultSelection, getEndpointProfiles, resolveConfiguredModel } from "./model-profiles.js";
import { bindUnityAgentEventForwarding } from "./agent-event-forwarding.js";
import { installUnityPublicApi } from "./unity-public-api.js";
import { runUnitySelfCheck as runUnitySelfCheckImpl } from "./unity-self-check.js";
import { createUnityLocalCommandHandler } from "./unity-local-commands.js";
import { createUnityFetchAdapter } from "./unity-fetch-adapter.js";
import { createUnityReadFileUnderstanding } from "./read-file-understanding-adapter.js";
import { createUnityToolModelRuntime } from "./unity-tool-model-runtime.js";
import { createUnitySubagentTool } from "./unity-subagent-tool.js";
import { createUnityWebTools } from "./unity-web-tools.js";

const bridge = getPieBridge();
installDevRpcBridge(bridge);

installUnityScriptHost(bridge);
initializeUnityLogger(bridge);

const projectRoot: string = bridge.getProjectRoot();
const isEditor: boolean = bridge.isEditor === true;
const persistentDataPath: string = typeof bridge.getPersistentDataPath === "function"
  ? String(bridge.getPersistentDataPath() || "").replace(/\\/g, "/")
  : "";

// Replace the default HTTP client with one backed by PieHttpBridge.cs (true SSE streaming)
const httpClient = new UnityHttpClient();
setHttpClient(httpClient);
const unityFetch = createUnityFetchAdapter(httpClient);

const _initialSelection = getDefaultSelection(bridge, getEndpointProfiles(bridge));

let _provider = _initialSelection?.provider || "";
let _modelId  = _initialSelection?.modelId || "";
let _baseUrlOverride = "";
let _runtimeApiKeyOverride = "";
let _verboseLogs = false;
let _currentSession: SessionRecord = createSessionRecord({
  provider: _provider,
  modelId: _modelId,
  messages: [],
  todoState: [],
});
const sessionTrace = new UnitySessionTraceWriter(projectRoot, () => _currentSession?.id);

const todoTool = createManageTodoListTool();
let todoLoopState: LoopState | null = null;
const fileToolPathOptions = buildFileToolPathOptions();

function getActiveResolvedModel() {
  return resolveModelWithRuntimeOverrides(_provider, _modelId);
}

function getActiveModel() {
  return getActiveResolvedModel()?.model || createUnconfiguredModel();
}

const toolModelRuntime = createUnityToolModelRuntime({ bridge, getActiveModel });

function getActiveApiKey(): string | undefined {
  return getActiveResolvedModel()?.apiKey || toolModelRuntime.getRuntimeApiKeyFor(_provider, _modelId);
}

function resolveModelWithRuntimeOverrides(provider: string, modelId: string) {
  const resolved = resolveConfiguredModel(bridge, provider, modelId, { allowMissingApiKey: !!_runtimeApiKeyOverride });
  const baseUrl = _baseUrlOverride.trim();
  if (!resolved) return createRuntimeConfiguredModel(provider, modelId, baseUrl);
  if (!baseUrl) return resolved;
  return {
    ...resolved,
    model: {
      ...resolved.model,
      baseUrl,
    },
  };
}

const { webSearchTool, webFetchTool, webResearchTool } = createUnityWebTools({
  getActiveModel,
  getActiveApiKey,
  resolveToolModelCandidates: toolModelRuntime.resolveCandidates,
  fetch: unityFetch,
});

const understandFile = createUnityReadFileUnderstanding({
  getAgentModel: () => getActiveModel(),
  getSessionId: () => _currentSession?.id,
  fetch: unityFetch,
  resolveToolModel: toolModelRuntime.resolvePreferred,
});

const subagentTool = createUnitySubagentTool({
  projectRoot,
  getActiveModel,
  getActiveApiKey,
  getSkills: () => getAvailableSkills(projectRoot),
  getRuntimeTools: () => getCurrentAgentSurface().tools,
  getParentTools: () => getCurrentAgentSurface().tools,
  trace: sessionTrace,
});

function getCurrentAgentSurface() {
  return createUnityAgentSurface({
    projectRoot,
    isEditor,
    persistentDataPath,
    fileToolPathOptions,
    todoTool,
    webResearchTool,
    webSearchTool,
    webFetchTool,
    subagentTool,
    understandFile,
  });
}

function rebuildAgentSurface() {
  const surface = getCurrentAgentSurface();
  agent.setTools(surface.tools);
  agent.setHooks(surface.hooks);
  agent.setSystemPrompt(surface.systemPrompt);
  agentSessionController?.updateRuntimeContext({ systemPrompt: surface.systemPrompt, tools: surface.tools });
}

const initialSurface = getCurrentAgentSurface();
const initialResolvedModel = getActiveResolvedModel();

const agent = new Agent({
  initialState: {
    systemPrompt: initialSurface.systemPrompt,
    model: initialResolvedModel?.model || createUnconfiguredModel(),
    tools: initialSurface.tools,
  },
  sessionId: _currentSession.id,
  getApiKey: () => getActiveApiKey(),
});

registerUnityInteractionBinding({ bridge, isEditor });

function refreshTodoLoopState(): void {
  const executionState = todoTool.getExecutionState();
  if (!executionState || executionState.mode !== "todo" || executionState.steps.length === 0 || executionState.lifecycle !== "active") {
    todoLoopState = null;
    return;
  }
  todoLoopState = executionState.loop ?? createTodoClosureLoop(executionState);
}

const sessionRuntime = createSessionRuntime({
  agent,
  projectRoot,
  getProvider: () => _provider,
  getModelId: () => _modelId,
  getCurrentSession: () => _currentSession,
  setCurrentSession: (record) => {
    _currentSession = record;
  },
  getTodoState: () => todoTool.getState(),
  resetAgentForSessionSwitch: () => cancelActivePromptForSessionSwitch(),
  rebuildAgentSurface,
  setAgentModel: () => agent.setModel(getActiveModel()),
  emitSessionSync: () => emitSessionSync(),
});

const agentSessionController = createUnityAgentSessionController({
  agent,
  projectRoot,
  getCurrentSession: () => _currentSession,
  setCurrentSession: (record) => {
    _currentSession = record;
  },
  saveCurrentSession: async () => {
    await persistCurrentSession();
  },
});

function hasConfiguredModelSelection(): boolean {
  return !!getActiveResolvedModel();
}

function getModelSelectionWarning(): string {
  return "No model is configured. Select a profile/model from ~/.pie/models.json, or enter provider, model, Base URL, and API key in Pie Chat settings before sending messages.";
}

function verboseLog(message: string) {
  if (_verboseLogs) {
    bridge.log("info", message);
  }
}

function reloadProjectExtensions() {
  const result = loadProjectExtensions({
    projectRoot,
    isEditor,
    log: verboseLog,
  });
  rebuildAgentSurface();
  return result;
}

async function runUnitySelfCheck(): Promise<string> {
  return runUnitySelfCheckImpl({
    agent,
    bridge,
    isEditor,
    modelLabel: hasConfiguredModelSelection() ? `${_provider}/${_modelId}` : "(unconfigured)",
    projectRoot,
    getToolRouteSummaries: toolModelRuntime.describeRoutes,
    reloadProjectExtensions,
    todoTool,
  });
}

async function persistCurrentSession() {
  await sessionRuntime.persistCurrentSession();
}

async function persistCurrentSessionForRecovery() {
  await sessionRuntime.persistCurrentSessionForRecovery();
}

async function persistCurrentSessionForRecoveryWithPendingUserMessage(content: string) {
  await sessionRuntime.persistCurrentSessionForRecoveryWithPendingUserMessage(content);
}

function cancelActivePromptForSessionSwitch() {
  agent.abort();
  agent.resetProcessingState();
}

function isAgentActivelyProcessing(): boolean {
  if (agent.state.isStreaming === true) {
    return true;
  }

  const snapshot = agent.getStatusSnapshot();
  const phase = String(snapshot?.phase || "").toLowerCase();
  const turnState = String(snapshot?.turnState || "").toLowerCase();

  return phase === "responding"
    || phase === "running_tool"
    || turnState === "continuing";
}

function isStalePromptLockError(error: unknown): boolean {
  const message = error instanceof Error ? error.message : String(error || "");
  return /already processing a prompt/i.test(message)
    && !isAgentActivelyProcessing();
}

async function promptAgentWithRecovery(input: string): Promise<void> {
  let recoveredStaleLock = false;

  while (true) {
    try {
      await agentSessionController.prompt(input, { source: "unity" });
      return;
    } catch (error) {
      if (!recoveredStaleLock && isStalePromptLockError(error)) {
        recoveredStaleLock = true;
        bridge.log("warn", "[pie/index] Clearing stale agent prompt lock after a failed turn.");
        agentSessionController.abort();
        agent.resetProcessingState();
        continue;
      }
      throw error;
    }
  }
}

function startFreshSession(parentSessionId?: string) {
  sessionRuntime.startFreshSession(parentSessionId);
  agentSessionController.syncFromActiveSession();
  todoTool.reset();
  todoLoopState = null;
}

function restoreSessionRecord(record: SessionRecord) {
  _provider = record.provider || "";
  _modelId = record.modelId || "";
  const resolved = getActiveResolvedModel();
  agent.setModel(resolved?.model || createUnconfiguredModel());
  sessionRuntime.restoreSessionRecord(record);
  agentSessionController.syncFromActiveSession();
  todoTool.restore(record.todoState || []);
  refreshTodoLoopState();
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return !!value && typeof value === "object" && !Array.isArray(value);
}

function cloneMessage(message: AgentMessage): AgentMessage {
  if (!message || typeof message !== "object") return message;
  return JSON.parse(JSON.stringify(message)) as AgentMessage;
}

function trimInterruptedTail(record: SessionRecord, lastUserText?: string): SessionRecord {
  const messages = Array.isArray(record.messages)
    ? record.messages.map((message) => cloneMessage(message))
    : [];

  const normalizedLastUser = String(lastUserText || "").trim();
  if (normalizedLastUser.length > 0) {
    if (messages.length > 0) {
      const last = messages[messages.length - 1];
      if (String(last?.role || "") === "assistant") {
        messages.pop();
      }
    }

    if (messages.length > 0) {
      const last = messages[messages.length - 1];
      if (String(last?.role || "") === "user" && collectMessageText(last).trim() === normalizedLastUser) {
        messages.pop();
      }
    }
  }

  return {
    ...record,
    messageCount: messages.length,
    messages,
  };
}

async function forkFromRecord(record: SessionRecord) {
  await sessionRuntime.forkFromRecord(record);
}

function emitLocalAssistantMessage(text: string) {
  bridge.sendToUnity("message_update", { type: "text_full", text });
  bridge.sendToUnity("turn_end", { role: "assistant", stopReason: "stop" });
  bridge.sendToUnity("agent_end", {});
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function runDebugLocalStream(commandText: string, promptText: string): Promise<void> {
  const visibleUserText = (promptText || "").trim() || commandText;
  const userMessage = {
    role: "user" as const,
    content: [{ type: "text" as const, text: visibleUserText }],
    timestamp: Date.now(),
  };
  const baseMessages = agent.state.messages.slice();
  agent.replaceMessages([...baseMessages, userMessage]);
  emitSessionSync();
  await persistCurrentSessionForRecovery();

  bridge.sendToUnity("state_event", { name: "agent_start", detail: "debug local stream started" });
  bridge.sendToUnity("state_event", { name: "turn_start", detail: "debug local stream" });
  bridge.sendToUnity("state_event", { name: "message_start", detail: "debug local stream" });

  const slowMode = /interrupt|slow|long/i.test(promptText || "");
  const chunks = slowMode
    ? Array.from({ length: 40 }, (_, i) => `Line ${i + 1}\n`)
    : [
        "One\n",
        "Two\n",
        "Three\n",
        "Four\n",
        "Five\n",
        "Six\n",
        "Seven\n",
        "Eight\n",
        "Nine\n",
        "Ten",
      ];
  const chunkDelayMs = slowMode ? 400 : 250;

  for (const chunk of chunks) {
    bridge.sendToUnity("message_update", { type: "text_delta", delta: chunk });
    await sleep(chunkDelayMs);
  }

  const assistantText = chunks.join("");
  const assistantMessage = {
    role: "assistant" as const,
    content: [{ type: "text" as const, text: assistantText }],
    api: agent.state.model.api,
    provider: agent.state.model.provider,
    model: agent.state.model.id,
    usage: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, totalTokens: 0, cost: { input: 0, output: 0, cacheRead: 0, cacheWrite: 0, total: 0 } },
    stopReason: "stop" as const,
    timestamp: Date.now(),
  } satisfies AgentMessage;
  agent.replaceMessages([...baseMessages, userMessage, assistantMessage]);
  await persistCurrentSession();
  emitSessionSync();

  bridge.sendToUnity("state_event", { name: "message_end", detail: "debug local stream complete" });
  bridge.sendToUnity("turn_end", { role: "assistant", stopReason: "stop" });
  bridge.sendToUnity("agent_end", {});
}

function hasRealUsage(usage: unknown): boolean {
  if (!isRecord(usage)) return false;
  return Number(usage.input || 0) > 0
    || Number(usage.output || 0) > 0
    || Number(usage.cacheRead || 0) > 0
    || Number(usage.cacheWrite || 0) > 0
    || Number(usage.totalTokens || 0) > 0;
}

function estimateTokensFromText(text: string): number {
  const normalized = (text || "").trim();
  if (!normalized) return 0;
  return Math.max(1, Math.ceil(normalized.length / 4));
}

function collectMessageText(message: unknown): string {
  if (!message) return "";
  if (!isRecord(message)) return "";
  const content = message.content;
  if (typeof content === "string") return content;
  if (!Array.isArray(content)) return "";

  return content.map((block: unknown) => {
    if (!isRecord(block)) return "";
    if (block.type === "text") return typeof block.text === "string" ? block.text : "";
    if (block.type === "thinking") return typeof block.thinking === "string" ? block.thinking : "";
    if (block.type === "toolCall") {
      const name = typeof block.name === "string" ? block.name : "";
      const args = block.arguments !== undefined ? JSON.stringify(block.arguments) : "";
      return `${name}${args}`;
    }
    return "";
  }).join("");
}

function buildUsagePayload(messages: AgentMessage[], message: AgentMessage, fallbackIndex?: number) {
  const messageRecord = isRecord(message) ? message : {};
  const usage = messageRecord.usage;
  if (hasRealUsage(usage) && isRecord(usage)) {
    return {
      input: Number(usage.input || 0),
      output: Number(usage.output || 0),
      cacheRead: Number(usage.cacheRead || 0),
      cacheWrite: Number(usage.cacheWrite || 0),
      totalTokens: Number(usage.totalTokens || 0),
      estimated: false,
    };
  }

  if ((messageRecord.role || "") !== "assistant") {
    return null;
  }

  const resolvedIndex = typeof fallbackIndex === "number"
    ? fallbackIndex
    : Math.max(0, messages.lastIndexOf(message));
  let inputTokens = 0;
  for (let i = resolvedIndex - 1; i >= 0; i--) {
    const candidate = messages[i];
    if ((candidate?.role || "") !== "user") continue;
    inputTokens = estimateTokensFromText(collectMessageText(candidate));
    if (inputTokens > 0) break;
  }
  const outputTokens = estimateTokensFromText(collectMessageText(message));
  const totalTokens = inputTokens + outputTokens;
  if (totalTokens <= 0) return null;

  return {
    input: inputTokens,
    output: outputTokens,
    cacheRead: 0,
    cacheWrite: 0,
    totalTokens,
    estimated: true,
  };
}

function emitSessionSync(record?: SessionRecord) {
  const sourceRecord = record || _currentSession;
  const stateMessages = Array.isArray(sourceRecord?.messages)
    ? sourceRecord.messages
    : (agent.state.messages || []);
  const messages = stateMessages.map((message: AgentMessage, index: number) => {
    const messageRecord = isRecord(message) ? message : {};
    return {
    role: String(messageRecord.role || "assistant"),
    content: Array.isArray(messageRecord.content)
      ? messageRecord.content
          .filter((block: unknown) => isRecord(block))
          .map((block) => ({
            type: String(block.type || "text"),
            text: typeof block.text === "string" ? block.text : "",
          }))
      : [],
    errorMessage: typeof messageRecord.errorMessage === "string" ? messageRecord.errorMessage : "",
    stopReason: typeof messageRecord.stopReason === "string" ? messageRecord.stopReason : "",
    usage: buildUsagePayload(stateMessages, message, index),
  };
  });

  bridge.sendToUnity("session_sync", {
    id: sourceRecord.id,
    title: sourceRecord.title,
    messageCount: messages.length,
    messages,
    todoState: Array.isArray(sourceRecord.todoState) ? sourceRecord.todoState : todoTool.getState(),
  });
}

function emitSkillsList() {
  const skills = getAvailableSkills(projectRoot).map((skill) => ({
    name: skill.name,
    description: skill.description,
    source: skill.source,
    path: skill.path || "",
  }));
  bridge.sendToUnity("skills_list", { skills });
}

function persistCurrentSessionSafely() {
  persistCurrentSession().catch((err: unknown) => {
    bridge.log("error", `[pie/index] Failed to persist session: ${err instanceof Error ? err.message : String(err)}`);
  });
}

async function applyModelSelection(provider: string, modelId: string) {
  const resolved = resolveModelWithRuntimeOverrides(provider, modelId);
  _provider = provider;
  _modelId = modelId;
  agent.setModel(resolved?.model || createUnconfiguredModel());
  rebuildAgentSurface();
  await persistCurrentSession();
}

function applyModelSelectionSync(provider: string, modelId: string) {
  const resolved = resolveModelWithRuntimeOverrides(provider, modelId);
  _provider = provider;
  _modelId = modelId;
  agent.setModel(resolved?.model || createUnconfiguredModel());
  rebuildAgentSurface();
}

function extractToolText(result: unknown): string {
  if (!result) return "";
  if (typeof result === "string") return result;
  if (isRecord(result) && Array.isArray(result.content)) {
    return result.content
      .filter((item: unknown): item is Record<string, unknown> => isRecord(item) && item.type === "text")
      .map((item) => String(item.text ?? ""))
      .join("\n")
      .trim();
  }
  return "";
}

function extractEffectiveArgs(toolName: string, args: unknown, details: unknown): Record<string, unknown> {
  const argRecord = isRecord(args) ? args : {};
  const detailRecord = isRecord(details) ? details : {};
  if (toolName === "find_files") {
    return {
      rawPattern: detailRecord.rawPattern ?? argRecord.pattern ?? argRecord.query ?? argRecord.name ?? argRecord.file_name ?? "",
      pattern: detailRecord.effectivePattern ?? argRecord.pattern ?? argRecord.query ?? argRecord.name ?? argRecord.file_name ?? "",
      path: detailRecord.searchPath ?? argRecord.path ?? ".",
      limit: argRecord.limit,
    };
  }

  if (toolName === "grep_text") {
    return {
      pattern: detailRecord.effectivePattern ?? argRecord.pattern ?? "",
      glob: detailRecord.glob ?? argRecord.glob ?? "",
      path: detailRecord.searchPath ?? argRecord.path ?? ".",
      literal: detailRecord.literal ?? argRecord.literal,
      ignoreCase: detailRecord.ignoreCase ?? argRecord.ignoreCase,
      limit: argRecord.limit,
    };
  }

  return argRecord;
}

const handleLocalCommand = createUnityLocalCommandHandler({
  agent,
  agentSessionController,
  bridge,
  isEditor,
  projectRoot,
  todoTool,
  applyModelSelection,
  buildCurrentAgentSurface: getCurrentAgentSurface,
  emitLocalAssistantMessage,
  emitSkillsList,
  forkFromRecord,
  getCurrentSession: () => _currentSession,
  getModelId: () => _modelId,
  getModelSelectionWarning,
  getProvider: () => _provider,
  hasConfiguredModelSelection,
  rebuildAgentSurface,
  reloadProjectExtensions,
  restoreSessionRecord,
  runDebugLocalStream,
  runUnitySelfCheck,
  setAgentSystemPrompt: (systemPrompt) => agent.setSystemPrompt(systemPrompt),
  startFreshSession,
  persistCurrentSession,
  persistCurrentSessionForRecovery,
});

// ─── Event forwarding: Agent → C# ─────────────────────────────────────────────

reloadProjectExtensions();
emitSessionSync();
bindUnityAgentEventForwarding({
  agent,
  bridge,
  sessionTrace,
  todoTool,
  getTodoLoopState: () => todoLoopState,
  setTodoLoopState: (loop) => { todoLoopState = loop; },
  buildUsagePayload,
  collectMessageText,
  extractEffectiveArgs,
  extractToolText,
  emitSessionSync,
  persistCurrentSessionSafely,
  refreshTodoLoopState,
  verboseLog,
});

// ─── Public API: C# → JS ──────────────────────────────────────────────────────

installUnityPublicApi({
  agent,
  agentSessionController,
  bridge,
  sessionTrace,
  todoTool,
  applyModelSelectionSync,
  emitSessionSync,
  emitSkillsList,
  getModelStatus: () => {
    const resolved = getActiveResolvedModel();
    return {
      provider: _provider,
      modelId: _modelId,
      baseUrl: _baseUrlOverride || resolved?.model.baseUrl || "",
      configured: !!resolved,
      verboseLogs: _verboseLogs,
    };
  },
  getModelSelectionWarning,
  handleLocalCommand,
  hasConfiguredModelSelection,
  loadSession,
  persistCurrentSession,
  persistCurrentSessionForRecovery,
  persistCurrentSessionForRecoveryWithPendingUserMessage,
  persistCurrentSessionSafely,
  projectRoot,
  promptAgentWithRecovery,
  rebuildAgentSurface,
  restoreSessionRecord,
  startFreshSession,
  trimInterruptedTail,
  getTodoLoopState: () => todoLoopState,
  setTodoLoopState: (loop) => { todoLoopState = loop; },
  setVerboseLogs: (value) => {
    _verboseLogs = value;
    (globalThis as { __pieVerboseLogs?: boolean }).__pieVerboseLogs = _verboseLogs;
  },
  setModelSelection: (provider, modelId, apiKey, baseUrl) => {
    const nextProvider = provider !== undefined ? String(provider || "") : _provider;
    const nextModelId = modelId !== undefined ? String(modelId || "") : _modelId;
    if (apiKey !== undefined) {
      _runtimeApiKeyOverride = String(apiKey || "");
      toolModelRuntime.setRuntimeCredential(nextProvider, nextModelId, _runtimeApiKeyOverride);
    }
    if (baseUrl !== undefined) _baseUrlOverride = String(baseUrl || "");
    _provider = nextProvider;
    _modelId = nextModelId;
  },
});
