import type { AgentTool } from "@pie/agent-core";
import { completeSimple, type Api, type Model, type TextContent } from "@pie/ai";
import { Type, type Static } from "@sinclair/typebox";

const webFetchSchema = Type.Object({
	url: Type.String({ description: "The http(s) URL to fetch and read." }),
	prompt: Type.Optional(Type.String({ description: "Optional extraction prompt to run on the fetched content." })),
});

export type WebFetchInput = Static<typeof webFetchSchema>;

export type WebFetchFailureCategory =
	| "invalid_url"
	| "blocked_private_host"
	| "http_error"
	| "timeout"
	| "too_large"
	| "unsupported_content"
	| "requires_browser"
	| "provider_error";

export interface WebFetchDetails {
	url: string;
	sourceUrl?: string;
	finalUrl?: string;
	status?: number;
	contentType?: string;
	charset?: string;
	decodeWarning?: "unsupported_charset_fallback" | "manual_utf8_fallback" | "replacement_chars_detected";
	bytes?: number;
	title?: string;
	truncated?: boolean;
	redirectChain?: string[];
	extractionMethod?: "html_readability" | "plain_text" | "pdf_text" | "model_extraction";
	readabilityScore?: number;
	citationAnchors?: Array<{ url: string; title?: string; startOffset: number; endOffset: number }>;
	truncationReason?: "max_chars" | "max_bytes";
	requiresBrowser?: boolean;
	routeModel?: string;
	routeSource?: "current_model" | "none";
	failureCategory?: WebFetchFailureCategory;
	durationMs: number;
}

export interface WebFetchDeps {
	fetch?: typeof fetch;
	getModel?: () => Model<Api> | undefined;
	getApiKey?: () => string | undefined;
	timeoutMs?: number;
	maxBytes?: number;
	maxChars?: number;
	allowPrivateHosts?: () => boolean;
}

const DEFAULT_TIMEOUT_MS = 45_000;
const DEFAULT_MAX_BYTES = 2_000_000;
const DEFAULT_MAX_CHARS = 100_000;

function modelLabel(model: Model<Api> | undefined): string | undefined {
	return model ? `${model.provider}/${model.id}` : undefined;
}

function isPrivateHostname(hostname: string): boolean {
	const host = hostname.toLowerCase();
	if (host === "localhost" || host.endsWith(".localhost")) return true;
	if (host === "0.0.0.0") return true;
	if (host.startsWith("127.")) return true;
	if (host.startsWith("10.")) return true;
	if (host.startsWith("192.168.")) return true;
	if (/^172\.(1[6-9]|2\d|3[01])\./.test(host)) return true;
	if (host === "::1" || host === "[::1]") return true;
	if (host === "169.254.169.254") return true;
	return false;
}

function charsetFromContentType(contentType: string): string {
	return contentType.match(/charset=([^;\s]+)/i)?.[1]?.trim().replace(/^"|"$/g, "") || "utf-8";
}

function decodeUtf8Manually(bytes: ArrayBuffer): string {
	const view = new Uint8Array(bytes);
	let output = "";
	for (let i = 0; i < view.length; i++) {
		const first = view[i];
		if (first <= 0x7f) {
			output += String.fromCharCode(first);
			continue;
		}
		if (first >= 0xc0 && first <= 0xdf && i + 1 < view.length) {
			const second = view[++i] & 0x3f;
			output += String.fromCharCode(((first & 0x1f) << 6) | second);
			continue;
		}
		if (first >= 0xe0 && first <= 0xef && i + 2 < view.length) {
			const second = view[++i] & 0x3f;
			const third = view[++i] & 0x3f;
			output += String.fromCharCode(((first & 0x0f) << 12) | (second << 6) | third);
			continue;
		}
		if (first >= 0xf0 && first <= 0xf7 && i + 3 < view.length) {
			const second = view[++i] & 0x3f;
			const third = view[++i] & 0x3f;
			const fourth = view[++i] & 0x3f;
			const codePoint = ((first & 0x07) << 18) | (second << 12) | (third << 6) | fourth;
			output += String.fromCodePoint(codePoint);
			continue;
		}
		output += "\uFFFD";
	}
	return output;
}

function decodeBytes(bytes: ArrayBuffer, contentType = ""): { text: string; charset: string; decodeWarning?: WebFetchDetails["decodeWarning"] } {
	const charset = charsetFromContentType(contentType);
	try {
		const decoded = new TextDecoder(charset, { fatal: false }).decode(bytes);
		if (decoded !== "[object ArrayBuffer]") {
			return {
				text: decoded,
				charset,
				decodeWarning: decoded.includes("\uFFFD") ? "replacement_chars_detected" : undefined,
			};
		}
	} catch {
		// Unity/PuerTS does not always expose a standard TextDecoder, and its
		// Buffer polyfills can stringify ArrayBuffer objects. Keep a host-neutral
		// UTF-8 path before falling back to Node's Buffer.
	}
	try {
		return {
			text: decodeUtf8Manually(bytes),
			charset,
			decodeWarning: charset.toLowerCase() === "utf-8" ? "manual_utf8_fallback" : "unsupported_charset_fallback",
		};
	} catch {
		return {
			text: Buffer.from(bytes).toString("utf8"),
			charset,
			decodeWarning: charset.toLowerCase() === "utf-8" ? "manual_utf8_fallback" : "unsupported_charset_fallback",
		};
	}
}

function extractTitle(html: string): string | undefined {
	const match = html.match(/<title[^>]*>([\s\S]*?)<\/title>/i);
	return match?.[1]?.replace(/\s+/g, " ").trim();
}

function decodeHtmlEntities(input: string): string {
	return input
		.replace(/&nbsp;/g, " ")
		.replace(/&amp;/g, "&")
		.replace(/&lt;/g, "<")
		.replace(/&gt;/g, ">")
		.replace(/&quot;/g, "\"")
		.replace(/&#39;/g, "'");
}

function htmlToReadableMarkdown(input: string): { text: string; readabilityScore: number } {
	const body = input.match(/<article[\s\S]*?<\/article>/i)?.[0]
		?? input.match(/<main[\s\S]*?<\/main>/i)?.[0]
		?? input.match(/<body[\s\S]*?<\/body>/i)?.[0]
		?? input;
	const markdown = body
		.replace(/<script[\s\S]*?<\/script>/gi, " ")
		.replace(/<style[\s\S]*?<\/style>/gi, " ")
		.replace(/<noscript[\s\S]*?<\/noscript>/gi, " ")
		.replace(/<(nav|footer|aside|form|svg|canvas)[\s\S]*?<\/\1>/gi, " ")
		.replace(/<h([1-6])[^>]*>([\s\S]*?)<\/h\1>/gi, (_match, level, text) => `${"#".repeat(Number(level))} ${decodeHtmlEntities(String(text).replace(/<[^>]+>/g, " "))}\n\n`)
		.replace(/<li[^>]*>/gi, "- ")
		.replace(/<a[^>]*href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi, (_match, href, text) => `${decodeHtmlEntities(String(text).replace(/<[^>]+>/g, " ").trim())} (${href})`)
		.replace(/<\/(p|div|section|article|li|h[1-6]|tr)>/gi, "\n")
		.replace(/<br\s*\/?>/gi, "\n")
		.replace(/<[^>]+>/g, " ")
		.replace(/[ \t]+/g, " ")
		.replace(/\n\s+/g, "\n")
		.replace(/\n{3,}/g, "\n\n")
		.trim();
	const text = decodeHtmlEntities(markdown);
	const rawText = decodeHtmlEntities(input.replace(/<script[\s\S]*?<\/script>/gi, " ").replace(/<style[\s\S]*?<\/style>/gi, " ").replace(/<[^>]+>/g, " ")).replace(/\s+/g, " ").trim();
	const readabilityScore = rawText.length === 0 ? 0 : Math.min(1, Math.max(0, text.length / rawText.length));
	return { text, readabilityScore };
}

function compactPdfText(raw: string): string {
	const literalStrings = [...raw.matchAll(/\(([^()]{2,})\)\s*Tj/g)]
		.map((match) => match[1])
		.join(" ");
	return (literalStrings.length > 64 ? literalStrings : raw)
		.replace(/[^\x09\x0a\x0d\x20-\x7e\u00a0-\uffff]+/g, " ")
		.replace(/\s+/g, " ")
		.trim();
}

function looksJavaScriptHeavy(raw: string, text: string): boolean {
	const lower = raw.slice(0, 100_000).toLowerCase();
	if (/enable javascript|requires javascript|please enable js/.test(lower)) return true;
	if (/<script\b/gi.test(raw) && text.length < 500) return true;
	if (/(id=["']root["']|id=["']__next["']|__next_data__|data-reactroot|vite)/i.test(raw) && text.length < 1500) return true;
	return false;
}

function buildCitationAnchors(url: string, title: string | undefined, text: string): WebFetchDetails["citationAnchors"] {
	const anchors: NonNullable<WebFetchDetails["citationAnchors"]> = [];
	const chunkSize = Math.max(1200, Math.min(5000, Math.ceil(text.length / 5)));
	for (let start = 0; start < text.length && anchors.length < 5; start += chunkSize) {
		anchors.push({ url, title, startOffset: start, endOffset: Math.min(text.length, start + chunkSize) });
	}
	return anchors;
}

function createTimeoutSignal(parentSignal: AbortSignal | undefined, timeoutMs: number): { signal: AbortSignal; dispose: () => void; didTimeout: () => boolean } {
	const controller = new AbortController();
	let timedOut = false;
	const timer = setTimeout(() => {
		timedOut = true;
		controller.abort(new Error(`web_fetch timed out after ${Math.ceil(timeoutMs / 1000)} seconds`));
	}, timeoutMs);
	const onAbort = () => controller.abort(parentSignal?.reason);
	if (parentSignal) {
		if (parentSignal.aborted) onAbort();
		else parentSignal.addEventListener("abort", onAbort, { once: true });
	}
	return {
		signal: controller.signal,
		dispose: () => {
			clearTimeout(timer);
			parentSignal?.removeEventListener("abort", onAbort);
		},
		didTimeout: () => timedOut,
	};
}

function assistantText(message: Awaited<ReturnType<typeof completeSimple>>): string {
	return message.content
		.filter((block): block is TextContent => block.type === "text")
		.map((block) => block.text)
		.join("\n")
		.trim();
}

async function withAbort<T>(promise: Promise<T>, signal?: AbortSignal): Promise<T> {
	if (!signal) return promise;
	if (signal.aborted) throw signal.reason ?? new Error("operation aborted");
	return await new Promise<T>((resolve, reject) => {
		const onAbort = () => reject(signal.reason ?? new Error("operation aborted"));
		signal.addEventListener("abort", onAbort, { once: true });
		promise.then(resolve, reject).finally(() => signal.removeEventListener("abort", onAbort));
	});
}

async function applyPromptWithModel(deps: WebFetchDeps, prompt: string, url: string, content: string, signal?: AbortSignal): Promise<{ text: string; model?: string; isError?: boolean }> {
	const model = deps.getModel?.();
	const apiKey = deps.getApiKey?.();
	if (!model || !apiKey) {
		return {
			text: [
				`Fetched ${url}.`,
				"",
				"Model-routed extraction was unavailable, so returning fetched content excerpt:",
				content,
			].join("\n"),
			model: modelLabel(model),
		};
	}
	try {
		const response = await withAbort(
			completeSimple(
				model,
				{
					systemPrompt: "You are a web_fetch extraction tool. Answer only from the fetched page content. Include uncertainty if the page does not contain the requested information.",
					messages: [{
						role: "user",
						timestamp: Date.now(),
						content: [{
							type: "text",
							text: [`URL: ${url}`, `Task: ${prompt}`, "", "Fetched content:", content].join("\n"),
						}],
					}],
				},
				{
					apiKey,
					maxTokens: Math.min(model.maxTokens || 4096, 4096),
					signal,
				},
			),
			signal,
		);
		const text = assistantText(response) || response.errorMessage || "(web_fetch extraction model returned no text)";
		return { text, model: modelLabel(model), isError: response.stopReason === "error" || response.stopReason === "aborted" };
	} catch (error) {
		return {
			text: `web_fetch extraction failed: ${error instanceof Error ? error.message : String(error)}`,
			model: modelLabel(model),
			isError: true,
		};
	}
}

export function createSharedWebFetchTool(deps: WebFetchDeps = {}): AgentTool<typeof webFetchSchema, WebFetchDetails> {
	return {
		name: "web_fetch",
		label: "web_fetch",
		description: "Fetch and read a specific public web URL. Use web_search to discover sources, then web_fetch to inspect a chosen URL. Do not use bash/curl/Python as a fallback for web page fetching.",
		parameters: webFetchSchema,
		capabilityMetadata: {
			riskClass: "network",
			concurrencySafe: true,
			permissionScope: "network",
			readsNetwork: true,
			availableInPlanMode: true,
			allowedForSubagentByDefault: true,
			maxOutputChars: DEFAULT_MAX_CHARS,
		},
		execute: async (_toolCallId, params: unknown, signal?: AbortSignal) => {
			const start = Date.now();
			const { url, prompt } = params as WebFetchInput;
			let parsed: URL;
			try {
				parsed = new URL(url);
			} catch {
				return {
					content: [{ type: "text", text: `Invalid URL: ${url}` }],
					details: { url: String(url || ""), sourceUrl: String(url || ""), durationMs: Date.now() - start, failureCategory: "invalid_url" },
					isError: true,
				};
			}
			if (parsed.protocol !== "http:" && parsed.protocol !== "https:") {
				return {
					content: [{ type: "text", text: `web_fetch only supports http(s) URLs: ${url}` }],
					details: { url, sourceUrl: url, durationMs: Date.now() - start, failureCategory: "invalid_url" },
					isError: true,
				};
			}
			if (!deps.allowPrivateHosts?.() && isPrivateHostname(parsed.hostname)) {
				return {
					content: [{ type: "text", text: `Blocked private or local URL: ${url}` }],
					details: { url, sourceUrl: url, durationMs: Date.now() - start, failureCategory: "blocked_private_host" },
					isError: true,
				};
			}

			const timeout = createTimeoutSignal(signal, deps.timeoutMs ?? DEFAULT_TIMEOUT_MS);
			try {
				const response = await (deps.fetch ?? fetch)(url, {
					method: "GET",
					redirect: "follow",
					signal: timeout.signal,
					headers: {
						"user-agent": "Pie web_fetch/1.0",
						accept: "text/html,application/xhtml+xml,text/plain,application/pdf,*/*;q=0.8",
					},
				});
				const contentType = response.headers.get("content-type") || "";
				const bytes = await response.arrayBuffer();
				const maxBytes = deps.maxBytes ?? DEFAULT_MAX_BYTES;
				if (bytes.byteLength > maxBytes) {
					return {
						content: [{ type: "text", text: `Fetched content is too large (${bytes.byteLength} bytes; max ${maxBytes}).` }],
						details: { url, sourceUrl: url, finalUrl: response.url || url, status: response.status, contentType, bytes: bytes.byteLength, truncated: true, truncationReason: "max_bytes", durationMs: Date.now() - start, failureCategory: "too_large" },
						isError: true,
					};
				}
				if (!response.ok) {
					return {
						content: [{ type: "text", text: `web_fetch failed with HTTP ${response.status} for ${url}` }],
						details: { url, sourceUrl: url, finalUrl: response.url || url, status: response.status, contentType, bytes: bytes.byteLength, durationMs: Date.now() - start, failureCategory: "http_error" },
						isError: true,
					};
				}
					const decoded = decodeBytes(bytes, contentType);
					const raw = decoded.text;
					const isHtml = /html/i.test(contentType) || /<\/?[a-z][\s\S]*>/i.test(raw.slice(0, 2000));
					const isPdf = /pdf/i.test(contentType) || raw.startsWith("%PDF");
					const title = isHtml ? extractTitle(raw) : undefined;
					const htmlExtraction = isHtml ? htmlToReadableMarkdown(raw) : undefined;
					let text = htmlExtraction?.text ?? (isPdf ? compactPdfText(raw) : raw.trim());
					const extractionMethod: WebFetchDetails["extractionMethod"] = isHtml ? "html_readability" : isPdf ? "pdf_text" : "plain_text";
					if (isHtml && looksJavaScriptHeavy(raw, text)) {
						return {
							content: [{ type: "text", text: `web_fetch could not read meaningful content from ${url}; this page appears to require JavaScript. Use Playwright browser tools for browser-rendered content.` }],
							details: {
								url,
								sourceUrl: url,
								finalUrl: response.url || url,
								status: response.status,
								contentType,
								charset: decoded.charset,
								decodeWarning: decoded.decodeWarning,
								bytes: bytes.byteLength,
								title,
								requiresBrowser: true,
								extractionMethod,
								readabilityScore: htmlExtraction?.readabilityScore,
								durationMs: Date.now() - start,
								failureCategory: "requires_browser",
							},
							isError: true,
						};
					}
					if (!text) {
						return {
							content: [{ type: "text", text: `web_fetch could not extract readable text from ${url}` }],
							details: { url, sourceUrl: url, finalUrl: response.url || url, status: response.status, contentType, charset: decoded.charset, decodeWarning: decoded.decodeWarning, bytes: bytes.byteLength, extractionMethod, durationMs: Date.now() - start, failureCategory: "unsupported_content" },
							isError: true,
						};
					}
					const maxChars = deps.maxChars ?? DEFAULT_MAX_CHARS;
					const truncated = text.length > maxChars;
					if (truncated) text = text.slice(0, maxChars) + "\n\n[web_fetch content truncated]";
					const extraction = prompt?.trim()
						? await applyPromptWithModel(deps, prompt.trim(), response.url || url, text, timeout.signal)
						: { text, model: modelLabel(deps.getModel?.()) };
					const finalUrl = response.url || url;
					return {
						content: [{ type: "text", text: extraction.text }],
						details: {
							url,
							sourceUrl: url,
							finalUrl,
							status: response.status,
							contentType,
							charset: decoded.charset,
							decodeWarning: decoded.decodeWarning,
							bytes: bytes.byteLength,
							title,
							truncated,
							redirectChain: finalUrl !== url ? [url, finalUrl] : [url],
							extractionMethod: prompt?.trim() ? "model_extraction" : extractionMethod,
							readabilityScore: htmlExtraction?.readabilityScore,
							citationAnchors: buildCitationAnchors(finalUrl, title, text),
							truncationReason: truncated ? "max_chars" : undefined,
							requiresBrowser: false,
							routeModel: extraction.model,
						routeSource: extraction.model ? "current_model" : "none",
						durationMs: Date.now() - start,
						failureCategory: extraction.isError ? "provider_error" : undefined,
					},
					isError: extraction.isError,
				};
			} catch (error) {
				return {
					content: [{ type: "text", text: `web_fetch failed: ${error instanceof Error ? error.message : String(error)}` }],
					details: { url, sourceUrl: url, durationMs: Date.now() - start, failureCategory: timeout.didTimeout() ? "timeout" : "provider_error" },
					isError: true,
				};
			} finally {
				timeout.dispose();
			}
		},
	} as AgentTool<typeof webFetchSchema, WebFetchDetails>;
}
