import type { HttpClient } from "@pie/platform";

type FetchLike = typeof fetch;

function headersToRecord(headers: HeadersInit | undefined): Record<string, string> {
  if (!headers) return {};
  if (Array.isArray(headers)) {
    return Object.fromEntries(headers.map(([key, value]) => [key, value]));
  }
  if (typeof Headers !== "undefined" && headers instanceof Headers) {
    const record: Record<string, string> = {};
    headers.forEach((value, key) => {
      record[key] = value;
    });
    return record;
  }
  return { ...(headers as Record<string, string>) };
}

function createHeaders(record: Record<string, string>) {
  return {
    get(name: string): string | null {
      const wanted = name.toLowerCase();
      for (const [key, value] of Object.entries(record)) {
        if (key.toLowerCase() === wanted) return value;
      }
      return null;
    },
    forEach(callback: (value: string, key: string) => void): void {
      for (const [key, value] of Object.entries(record)) callback(value, key);
    },
  };
}

function encodeUtf8(text: string): ArrayBuffer {
  if (typeof TextEncoder !== "undefined") {
    const bytes = new TextEncoder().encode(text);
    return bytes.buffer.slice(bytes.byteOffset, bytes.byteOffset + bytes.byteLength) as ArrayBuffer;
  }

  const bytes: number[] = [];
  for (let i = 0; i < text.length; i++) {
    let codePoint = text.charCodeAt(i);
    if (codePoint >= 0xd800 && codePoint <= 0xdbff && i + 1 < text.length) {
      const next = text.charCodeAt(i + 1);
      if (next >= 0xdc00 && next <= 0xdfff) {
        codePoint = 0x10000 + ((codePoint - 0xd800) << 10) + (next - 0xdc00);
        i++;
      }
    }

    if (codePoint <= 0x7f) {
      bytes.push(codePoint);
    } else if (codePoint <= 0x7ff) {
      bytes.push(0xc0 | (codePoint >> 6), 0x80 | (codePoint & 0x3f));
    } else if (codePoint <= 0xffff) {
      bytes.push(0xe0 | (codePoint >> 12), 0x80 | ((codePoint >> 6) & 0x3f), 0x80 | (codePoint & 0x3f));
    } else {
      bytes.push(
        0xf0 | (codePoint >> 18),
        0x80 | ((codePoint >> 12) & 0x3f),
        0x80 | ((codePoint >> 6) & 0x3f),
        0x80 | (codePoint & 0x3f),
      );
    }
  }

  return new Uint8Array(bytes).buffer;
}

export function createUnityFetchAdapter(client: HttpClient): FetchLike {
  return (async (input: RequestInfo | URL, init?: RequestInit) => {
    const url = typeof input === "string" ? input : input instanceof URL ? input.toString() : String(input.url);
    const body = typeof init?.body === "string" ? init.body : init?.body ? String(init.body) : undefined;
    const response = await client.request(url, {
      method: init?.method || "GET",
      headers: headersToRecord(init?.headers),
      body,
      signal: init?.signal ?? undefined,
    });
    const text = await response.text();
    return {
      ok: response.ok,
      status: response.status,
      statusText: response.statusText,
      headers: createHeaders(response.headers || {}),
      url,
      arrayBuffer: async () => encodeUtf8(text),
      text: async () => text,
      json: async () => JSON.parse(text),
    } as Response;
  }) as FetchLike;
}
