/**
 * Write tool - Write content to a file.
 */

import type { AgentTool } from "@pie/agent-core";
import { Type } from "@sinclair/typebox";
import { getFileSystem } from "@pie/platform";
import { resolveToCwd, type PathResolutionOptions } from "./path-utils.js";
import { buildPathResolutionDescription, buildRootParameterSchema } from "./schema-utils.js";

export interface WriteToolInput {
	path: string;
	root?: string;
	content: string;
}

export function createWriteTool(
	cwd: string,
	options?: PathResolutionOptions,
): AgentTool<any> {
	const fs = getFileSystem();
	const rootSchema = buildRootParameterSchema(cwd, options);
	const writeSchema = Type.Object({
		path: Type.String({ description: "Path to the file to write." }),
		...(rootSchema ? { root: rootSchema } : {}),
		content: Type.String({ description: "Content to write to the file" }),
	});
	const pathResolutionDescription = buildPathResolutionDescription(cwd, options);

	return {
		name: "write",
		label: "write",
		description:
			`Write content to a file. Creates the file if it doesn't exist, overwrites if it does. Automatically creates parent directories. ${pathResolutionDescription}`,
		parameters: writeSchema,
		execute: async (
			_toolCallId: string,
			params: any,
			signal?: AbortSignal,
		) => {
			const { path: filePath, root, content } = params;
			const absolutePath = resolveToCwd(filePath, cwd, options, root);
			const dir = fs.dirname(absolutePath);

			return new Promise<{ content: Array<{ type: "text"; text: string }>; details: undefined }>(
				(resolve, reject) => {
					if (signal?.aborted) {
						reject(new Error("Operation aborted"));
						return;
					}

					let aborted = false;
					const onAbort = () => {
						aborted = true;
						reject(new Error("Operation aborted"));
					};

					if (signal) {
						signal.addEventListener("abort", onAbort, { once: true });
					}

					(async () => {
						try {
							await fs.mkdir(dir, { recursive: true });

							if (aborted) return;

							await fs.writeFile(absolutePath, content, "utf-8");

							if (aborted) return;

							if (signal) {
								signal.removeEventListener("abort", onAbort);
							}

							resolve({
								content: [{ type: "text", text: `Successfully wrote ${content.length} bytes to ${filePath}` }],
								details: undefined,
							});
						} catch (error: any) {
							if (signal) {
								signal.removeEventListener("abort", onAbort);
							}
							if (!aborted) {
								reject(error);
							}
						}
					})();
				},
			);
		},
	};
}
