import type { Agent, AgentMessage } from "@pie/agent-core";
import { AgentSessionController } from "@pie/agent-framework";
import type { SessionManager } from "@pie/agent-framework";
import type { SessionRecord } from "./session-store.js";

export interface UnityAgentSessionControllerOptions {
  agent: Agent;
  projectRoot: string;
  getCurrentSession: () => SessionRecord;
  setCurrentSession: (record: SessionRecord) => void;
  saveCurrentSession: () => Promise<void>;
}

function withMessages(record: SessionRecord, messages: AgentMessage[]): SessionRecord {
  return {
    ...record,
    messages,
    messageCount: messages.length,
  };
}

export function createUnityAgentSessionController(options: UnityAgentSessionControllerOptions): AgentSessionController {
  const sessionManagerAdapter = {
    getActiveSession() {
      const current = options.getCurrentSession();
      return {
        id: current.id,
        metadata: {
          id: current.id,
          name: current.title,
          createdAt: current.createdAt,
          updatedAt: current.updatedAt,
          activeEntryId: null,
          todoState: current.todoState,
          provider: current.provider,
          modelId: current.modelId,
          parentSessionId: current.parentSessionId,
        },
        isDirty: false,
      };
    },
    getMessages() {
      return (options.getCurrentSession().messages || []).slice();
    },
    addMessage(message: AgentMessage) {
      const current = options.getCurrentSession();
      const messages = (current.messages || []).slice();
      const last = messages[messages.length - 1];
      if (message.role === "user" && last?.role === "user") {
        messages[messages.length - 1] = message;
      } else {
        messages.push(message);
      }
      options.setCurrentSession(withMessages(current, messages));
    },
    updateMessages(messages: AgentMessage[]) {
      options.setCurrentSession(withMessages(options.getCurrentSession(), messages.slice()));
    },
    async save() {
      await options.saveCurrentSession();
    },
    appendCompaction() {},
    getActiveEntryId() {
      return undefined;
    },
    getPathToEntry() {
      return [];
    },
  };

  return new AgentSessionController({
    agent: options.agent,
    sessionManager: sessionManagerAdapter as unknown as SessionManager,
    cwd: options.projectRoot,
    baseSystemPrompt: options.agent.state.systemPrompt,
  });
}
