import type { SkillRegistryEntry } from "@pie/agent-framework";
import { Type } from "@sinclair/typebox";
import { defineSharedCapability } from "./capability.js";
import type { SkillResourceReference } from "./read-resource.js";

export interface ResolvedSkillContent {
	name: string;
	content: string;
	resources?: SkillResourceReference[];
}

export interface ReadSkillCapabilityDeps {
	resolveSkill?(name: string): ResolvedSkillContent | null | Promise<ResolvedSkillContent | null>;
	skillLoader?: {
		getSkill?(name: string): SkillRegistryEntry | null | undefined;
		loadSkill?(name: string): SkillRegistryEntry | null | undefined;
	};
}

export const ReadSkillParamsSchema = Type.Object({
	name: Type.String({ description: "Exact skill name from the available_skills list." }),
});

function validateSkillNameArgument(name: string): string | null {
	if (name.includes("<|tool")) {
		return "The skill name must be only an exact name from the available_skills list, not tool-call markup.";
	}
	if (name.includes("\n")) {
		return "The skill name must be a single exact name from the available_skills list, not multi-line text.";
	}
	return null;
}

function formatSkillResources(resources: SkillResourceReference[] | undefined): string {
	if (!Array.isArray(resources) || resources.length === 0) return "";
	const lines = resources.map((resource) => {
		const path = String(resource.path || "").trim();
		const kind = String(resource.kind || "").trim();
		return kind ? `- ${path} (${kind})` : `- ${path}`;
	});
	return `\n\n## Skill Resources\n${lines.join("\n")}`;
}

export function createReadSkillCapability(deps: ReadSkillCapabilityDeps) {
	async function resolveSkill(name: string): Promise<ResolvedSkillContent | null> {
		if (deps.resolveSkill) {
			return deps.resolveSkill(name);
		}

		const skill = deps.skillLoader?.getSkill?.(name) ?? deps.skillLoader?.loadSkill?.(name);
		if (!skill) {
			return null;
		}

		return {
			name: skill.name,
			content: skill.prompt,
			resources: skill.resourceRefs,
		};
	}

	const tool = {
		name: "read_skill",
		label: "read_skill",
		description: "Load the full contents of a skill by exact name from the available_skills list only. Do not pass tool names.",
		parameters: ReadSkillParamsSchema,
		async execute(toolCallIdOrArgs: string | { name: string }, maybeArgs?: { name: string }) {
			const args = typeof toolCallIdOrArgs === "string" ? maybeArgs : toolCallIdOrArgs;
			const skillName = String(args?.name || "").trim();
			const validationError = validateSkillNameArgument(skillName);
			if (validationError) {
				return {
					content: [{ type: "text" as const, text: `Invalid skill name: ${validationError}` }],
					details: { found: false, name: skillName || undefined },
					isError: true,
				};
			}
			const skill = await resolveSkill(skillName);
			if (!skill?.content) {
				return {
					content: [{ type: "text" as const, text: `Skill not found: ${skillName || "(empty)"}` }],
					details: { found: false, name: skillName || undefined },
					isError: true,
				};
			}

			return {
				content: [{
					type: "text" as const,
					text: `# ${skill.name}\n\n${skill.content}${formatSkillResources(skill.resources)}`,
				}],
				details: {
					found: true,
					name: skill.name,
					...(Array.isArray(skill.resources) ? { resources: skill.resources } : {}),
				},
			};
		},
	};

	return {
		...defineSharedCapability({
			id: "read-skill",
			description: "Shared capability for loading full skill contents through a host-provided skill resolver.",
			tools: [tool],
		}),
		tool,
	};
}
