import type { Agent, AgentTool } from "@pie/agent-core";
import type { AgentSessionController } from "@pie/agent-framework";
import { getAvailableSkills } from "./skills.js";
import { getUnityContextSnapshot } from "./tools/inspect-unity-context.js";
import { buildInitialProjectMemory, createWriteProjectMemoryTool, readProjectMemory } from "./tools/project-memory.js";
import { createSessionRecord, formatSessionTree, listSessions, loadSession, saveSession, type SessionRecord } from "./session-store.js";
import { getLoadedExtensions } from "./extensions/registry.js";
import type { PieBridge } from "./pie-bridge.js";
import { createManageTodoListTool } from "./tools/manage-todo-list.js";
import { getEndpointProfiles } from "./model-profiles.js";

type UnityLocalCommandCS = {
	System: {
		Environment: {
			GetFolderPath(folder: unknown): string;
			SpecialFolder: { UserProfile: unknown };
		};
		IO: {
			Directory: { Exists(path: string): boolean; GetFiles(path: string, pattern: string): { Length: number; [index: number]: string } };
			File: { Exists(path: string): boolean; ReadAllText(path: string): string };
			Path: { Combine(...parts: string[]): string };
		};
	};
};

declare const CS: UnityLocalCommandCS;

type RegistryEntry = { id?: string; name?: string; path?: string };
type SessionFileMetadata = { id?: string; name?: string; title?: string; updatedAt?: string | number };

function isRecord(value: unknown): value is Record<string, unknown> {
	return !!value && typeof value === "object" && !Array.isArray(value);
}

export interface UnityLocalCommandHost {
	agent: Agent;
	agentSessionController: AgentSessionController;
	bridge: PieBridge;
	isEditor: boolean;
	projectRoot: string;
	todoTool: ReturnType<typeof createManageTodoListTool>;
	applyModelSelection(provider: string, modelId: string): Promise<void>;
	buildCurrentAgentSurface(): { systemPrompt: string; tools: AgentTool[] };
	emitLocalAssistantMessage(text: string): void;
	emitSkillsList(): void;
	forkFromRecord(record: SessionRecord): Promise<void>;
	getCurrentSession(): SessionRecord;
	getModelId(): string;
	getModelSelectionWarning(): string;
	getProvider(): string;
	hasConfiguredModelSelection(): boolean;
	rebuildAgentSurface(): void;
	reloadProjectExtensions(): { errors: string[] };
	restoreSessionRecord(record: SessionRecord): void;
	runDebugLocalStream(commandText: string, promptText: string): Promise<void>;
	runUnitySelfCheck(): Promise<string>;
	setAgentSystemPrompt(systemPrompt: string): void;
	startFreshSession(parentSessionId?: string): void;
	persistCurrentSession(): Promise<void>;
	persistCurrentSessionForRecovery(): Promise<void>;
}

function tryExplainExternalSessionId(host: UnityLocalCommandHost, sessionId: string): string | null {
	const trimmed = String(sessionId || "").trim();
	if (!trimmed) return null;

	const registryPath = CS.System.IO.Path.Combine(
		CS.System.Environment.GetFolderPath(CS.System.Environment.SpecialFolder.UserProfile),
		".unity_skills",
		"registry.json",
	);

	if (!CS.System.IO.File.Exists(registryPath)) {
		return null;
	}

	try {
		const registry = JSON.parse(String(CS.System.IO.File.ReadAllText(registryPath) || "{}"));
		const entries = Object.values(isRecord(registry) ? registry : {}) as RegistryEntry[];
		const matched = entries.find((entry) => String(entry.id || "") === trimmed);
		if (!matched) {
			return null;
		}

		const sessionsDir = host.bridge.getSessionsDirectory?.();
		const availableSessions: string[] = [];
		if (typeof sessionsDir === "string" && sessionsDir.length > 0 && CS.System.IO.Directory.Exists(sessionsDir)) {
			const files = CS.System.IO.Directory.GetFiles(sessionsDir, "*.json");
			for (let index = 0; index < Math.min(files.Length, 8); index += 1) {
				try {
					const parsed = JSON.parse(String(CS.System.IO.File.ReadAllText(files[index]) || "{}"));
					const metadata = isRecord(parsed) && isRecord(parsed.metadata) ? parsed.metadata as SessionFileMetadata : parsed as SessionFileMetadata;
					const id = String(metadata.id || "").trim();
					if (!id) continue;
					const title = String(metadata.name || metadata.title || "Untitled Session");
					const updatedAtRaw = metadata.updatedAt ?? "";
					const updatedAt = typeof updatedAtRaw === "number"
						? new Date(updatedAtRaw).toISOString()
						: String(updatedAtRaw || "");
					availableSessions.push(`- ${id} | ${title} | ${updatedAt}`);
				} catch {
					// Ignore malformed session files in diagnostic helper.
				}
			}
		}
		const availableText = availableSessions.length > 0
			? `\n\nAvailable Pie sessions:\n${availableSessions.join("\n")}`
			: "\n\nNo Pie chat sessions have been saved yet.";

		return [
			`\`${trimmed}\` is a UnitySkills instance ID for project \`${matched.name || matched.path || "unknown"}\`, not a pie-unity chat session ID.`,
			"pie-unity chat sessions use IDs like `sess_xxx` and are stored separately under Application.persistentDataPath/Pie/sessions.",
			"Use `/resume` with one of the Pie session IDs shown in the Sessions panel or returned by `/resume` with no arguments.",
			availableText,
		].join("\n");
	} catch {
		return null;
	}
}

export function createUnityLocalCommandHandler(host: UnityLocalCommandHost): (content: string) => Promise<boolean> {
	return async function handleLocalCommand(content: string): Promise<boolean> {
		const trimmed = content.trim();
		if (!trimmed.startsWith("/")) return false;

		const [command, ...rest] = trimmed.split(/\s+/);
		if (command === "/new") {
			await host.persistCurrentSession();
			host.startFreshSession();
			await host.persistCurrentSessionForRecovery();
			host.emitLocalAssistantMessage(`Started new session: ${host.getCurrentSession().id}`);
			return true;
		}

		if (command === "/resume") {
			const silent = rest.includes("--silent");
			const args = rest.filter((arg) => arg !== "--silent");
			const sessionId = args[0];
			if (!sessionId) {
				const sessions = await listSessions(host.projectRoot);
				const text = sessions.length === 0
					? "No saved sessions."
					: sessions.map((session) => `${session.id} | ${session.title} | ${session.modelId} | ${session.updatedAt}`).join("\n");
				host.emitLocalAssistantMessage(text);
				return true;
			}

			const loaded = await loadSession(host.projectRoot, sessionId);
			if (!loaded) {
				const explanation = tryExplainExternalSessionId(host, sessionId);
				host.emitLocalAssistantMessage(explanation || `Session not found: ${sessionId}`);
				return true;
			}

			host.restoreSessionRecord(loaded);
			if (!silent) {
				host.emitLocalAssistantMessage(`Resumed session ${loaded.id}\nTitle: ${loaded.title}\nMessages: ${loaded.messageCount}`);
			}
			return true;
		}

		if (command === "/tree") {
			host.emitLocalAssistantMessage(await formatSessionTree(host.projectRoot));
			return true;
		}

		if (command === "/session-check") {
			const probeMessages = host.agent.state.messages.length > 0
				? host.agent.state.messages.slice()
				: [{ role: "user" as const, content: [{ type: "text" as const, text: "session-check probe" }], timestamp: Date.now() }];
			const probe = createSessionRecord({
				sessionId: `probe_${Date.now().toString(36)}`,
				provider: host.getProvider(),
				modelId: host.getModelId(),
				messages: probeMessages,
				todoState: host.todoTool.getState(),
			});
			const saved = await saveSession(host.projectRoot, probe);
			const loaded = await loadSession(host.projectRoot, saved.id);
			const ok = !!loaded
				&& loaded.id === saved.id
				&& loaded.provider === saved.provider
				&& loaded.modelId === saved.modelId
				&& (loaded.messages?.length || 0) === saved.messages.length
				&& (loaded.todoState?.length || 0) === saved.todoState.length;
			host.emitLocalAssistantMessage(
				ok
					? `Session self-check passed.\nSession: ${saved.id}\nMessages: ${saved.messages.length}\nTodos: ${saved.todoState.length}`
					: `Session self-check failed.\nSaved: ${saved.id}\nLoaded: ${loaded ? loaded.id : "(missing)"}`,
			);
			return true;
		}

		if (command === "/self-check") {
			host.emitLocalAssistantMessage(await host.runUnitySelfCheck());
			return true;
		}

		if (command === "/debug-stream") {
			const promptText = rest.length > 0 ? rest.join(" ") : "Count to ten, one per line.";
			host.runDebugLocalStream(trimmed, promptText).catch((err: unknown) => {
				const msg = err instanceof Error ? err.message : String(err);
				host.bridge.sendToUnity("error", { message: `debug local stream failed: ${msg}` });
			});
			return true;
		}

		if (command === "/fork") {
			const sessionId = rest[0];
			if (sessionId) {
				const source = await loadSession(host.projectRoot, sessionId);
				if (!source) {
					const explanation = tryExplainExternalSessionId(host, sessionId);
					host.emitLocalAssistantMessage(explanation || `Session not found: ${sessionId}`);
					return true;
				}
				await host.forkFromRecord(source);
				host.emitLocalAssistantMessage(`Forked new session ${host.getCurrentSession().id} from ${source.id}`);
				return true;
			}

			await host.persistCurrentSession();
			const source = await loadSession(host.projectRoot, host.getCurrentSession().id) || host.getCurrentSession();
			await host.forkFromRecord(source);
			host.emitLocalAssistantMessage(`Forked new session ${host.getCurrentSession().id} from ${source.id}`);
			return true;
		}

		if (command === "/memory") {
			const memory = readProjectMemory(host.projectRoot);
			host.emitLocalAssistantMessage(memory ? `Project memory loaded from Assets/Pie/AGENTS.md\n\n${memory}` : "No project memory found. Use /init to create an initial AGENTS.md.");
			return true;
		}

		if (command === "/model") {
			if (rest.length === 0) {
				const configured = Object.entries(getEndpointProfiles(host.bridge)).flatMap(([provider, profile]) =>
					(profile.models || []).map((model) => `${provider}/${model.id}`),
				);
				const current = host.hasConfiguredModelSelection() ? `${host.getProvider()}/${host.getModelId()}` : "(unconfigured)";
				host.emitLocalAssistantMessage(configured.length > 0 ? `Current model: ${current}\n\nConfigured models:\n${configured.join("\n")}` : host.getModelSelectionWarning());
				return true;
			}
			const [provider, modelId] = rest.length === 1 ? rest[0].split("/", 2) : [rest[0], rest.slice(1).join(" ")];
			if (!provider || !modelId) {
				host.emitLocalAssistantMessage(`Unknown model selection: ${rest[0]}`);
				return true;
			}
			await host.applyModelSelection(provider, modelId);
			host.emitLocalAssistantMessage(host.hasConfiguredModelSelection() ? `Switched model to ${provider}/${modelId}` : host.getModelSelectionWarning());
			return true;
		}

		if (command === "/skills") {
			const subcommand = rest[0] || "list";
			if (subcommand === "reload") {
				host.rebuildAgentSurface();
				const skills = getAvailableSkills(host.projectRoot);
				host.emitSkillsList();
				host.emitLocalAssistantMessage(`Reloaded ${skills.length} skill(s).`);
				return true;
			}
			const skills = getAvailableSkills(host.projectRoot);
			host.emitSkillsList();
			host.emitLocalAssistantMessage(skills.length === 0 ? "No skills available." : skills.map((skill) => `${skill.name} [${skill.source}] - ${skill.description}`).join("\n"));
			return true;
		}

		if (command === "/extensions") {
			const subcommand = rest[0] || "list";
			if (subcommand === "reload") {
				const result = host.reloadProjectExtensions();
				const loaded = getLoadedExtensions();
				const loadedText = loaded.length > 0 ? loaded.join("\n") : "(none)";
				const errorText = result.errors.length > 0 ? `\n\nErrors:\n${result.errors.join("\n")}` : "";
				host.emitLocalAssistantMessage(`Reloaded ${loaded.length} extension(s).\n\n${loadedText}${errorText}`);
				return true;
			}
			const loaded = getLoadedExtensions();
			host.emitLocalAssistantMessage(loaded.length > 0 ? `Loaded extensions:\n${loaded.join("\n")}` : "No project extensions loaded. Add .js files under Assets/Pie/Extensions or configure additional search paths in Pie Settings.");
			return true;
		}

		if (command === "/init") {
			const snapshot = getUnityContextSnapshot(host.projectRoot, host.isEditor);
			const initialMemory = buildInitialProjectMemory(snapshot);
			const writeTool = createWriteProjectMemoryTool(host.projectRoot);
			await writeTool.execute("local-init", { content: initialMemory });
			const surface = host.buildCurrentAgentSurface();
			host.setAgentSystemPrompt(surface.systemPrompt);
			host.agentSessionController.updateRuntimeContext({ systemPrompt: surface.systemPrompt, tools: surface.tools });
			host.emitLocalAssistantMessage(`Initialized project memory at Assets/Pie/AGENTS.md\n\n${initialMemory}`);
			return true;
		}

		return false;
	};
}
