export interface MarkdownKnowledgeMetadata {
	title?: string;
	description?: string;
}

export interface KnowledgeIndexHeading {
	level: number;
	text: string;
}

export interface KnowledgeIndexEntry {
	path: string;
	title: string;
	description: string;
	headings: KnowledgeIndexHeading[];
}

function parseFrontmatterBlock(yaml: string): MarkdownKnowledgeMetadata {
	const result: MarkdownKnowledgeMetadata = {};
	const lines = yaml.split("\n");
	for (const line of lines) {
		const trimmed = line.trim();
		if (!trimmed || trimmed.startsWith("#")) continue;
		const colonIndex = trimmed.indexOf(":");
		if (colonIndex === -1) continue;
		const key = trimmed.slice(0, colonIndex).trim();
		let value = trimmed.slice(colonIndex + 1).trim();
		if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
			value = value.slice(1, -1);
		}
		switch (key) {
			case "title":
				result.title = value;
				break;
			case "desc":
			case "description":
				result.description = value;
				break;
		}
	}
	return result;
}

function stripFrontmatter(content: string): { metadata: MarkdownKnowledgeMetadata; body: string } {
	const match = content.match(/^---\s*\n([\s\S]*?)\n---\s*\n?/);
	if (!match) {
		return { metadata: {}, body: content };
	}
	return {
		metadata: parseFrontmatterBlock(match[1]),
		body: content.slice(match[0].length),
	};
}

function extractHeadings(body: string, maxLevel = 3): KnowledgeIndexHeading[] {
	const headings: KnowledgeIndexHeading[] = [];
	const lines = body.split("\n");
	for (const rawLine of lines) {
		const line = rawLine.trim();
		const match = line.match(/^(#{1,6})\s+(.+?)\s*#*\s*$/);
		if (!match) continue;
		const level = match[1].length;
		if (level > maxLevel) continue;
		headings.push({ level, text: match[2].trim() });
	}
	return headings;
}

function extractTitle(metadata: MarkdownKnowledgeMetadata, headings: KnowledgeIndexHeading[]): string {
	if (metadata.title && metadata.title.trim()) return metadata.title.trim();
	const firstHeading = headings.find((heading) => heading.level === 1) || headings[0];
	return firstHeading?.text?.trim() || "";
}

function extractDescription(metadata: MarkdownKnowledgeMetadata, body: string): string {
	const explicit = metadata.description;
	if (explicit && explicit.trim()) {
		return explicit.trim();
	}

	const lines = body.split("\n");
	for (const rawLine of lines.slice(0, 24)) {
		const line = rawLine.trim();
		if (!line) continue;
		const descriptionMatch = line.match(/^description:\s*(.+)$/i);
		if (descriptionMatch) {
			return descriptionMatch[1].trim();
		}
	}

	let seenHeading = false;
	let paragraphLines: string[] = [];
	for (const rawLine of body.split("\n")) {
		const line = rawLine.trim();
		if (!line) {
			if (seenHeading && paragraphLines.length > 0) {
				break;
			}
			continue;
		}
		if (/^#{1,6}\s+/.test(line)) {
			if (seenHeading && paragraphLines.length > 0) {
				break;
			}
			seenHeading = true;
			continue;
		}
		if (!seenHeading) {
			continue;
		}
		if (/^description:\s*/i.test(line)) {
			continue;
		}
		paragraphLines.push(line);
	}
	if (paragraphLines.length > 0) {
		return paragraphLines.join(" ").trim();
	}

	return "";
}

export function buildKnowledgeIndexEntry(path: string, content: string): KnowledgeIndexEntry | null {
	const trimmed = String(content || "").trim();
	if (!trimmed) return null;

	const { metadata, body } = stripFrontmatter(trimmed);
	const headings = extractHeadings(body, 3);
	const title = extractTitle(metadata, headings);
	const description = extractDescription(metadata, body);

	return {
		path,
		title,
		description,
		headings,
	};
}

function formatHeadings(headings: KnowledgeIndexHeading[]): string {
	if (headings.length === 0) return "(none)";
	return headings
		.map((heading) => `${"#".repeat(heading.level)} ${heading.text}`)
		.join(" | ");
}

export function buildKnowledgeIndexSection(entries: readonly KnowledgeIndexEntry[], heading = "Project Knowledge Index"): string {
	const filtered = entries.filter((entry) => entry && (entry.title || entry.description || entry.headings.length > 0));
	if (filtered.length === 0) return "";

	const lines = [`[${heading}]`];
	for (const entry of filtered) {
		lines.push(`- path: ${entry.path}`);
		if (entry.title) lines.push(`  title: ${entry.title}`);
		if (entry.description) lines.push(`  description: ${entry.description}`);
		lines.push(`  headings: ${formatHeadings(entry.headings)}`);
	}
	return lines.join("\n");
}
