import { InteractionUnavailableError, registerInteractionHandler, type InteractionRequest } from "@pie/agent-framework";
import type { PieBridge } from "./pie-bridge.js";

export interface UnityInteractionBindingParams {
  bridge: PieBridge;
  isEditor: boolean;
}

interface InteractionState {
  completed?: boolean;
  responseJson?: string;
}

interface InteractionResponsePayload {
  unavailable?: boolean;
  message?: string;
}

function asInteractionState(value: unknown): InteractionState {
  return value && typeof value === "object" ? value as InteractionState : {};
}

function asInteractionResponse(value: unknown): InteractionResponsePayload {
  return value && typeof value === "object" ? value as InteractionResponsePayload : {};
}

export function registerUnityInteractionBinding(params: UnityInteractionBindingParams): void {
  registerInteractionHandler(async (request: InteractionRequest) => {
    if (params.isEditor && params.bridge.devRpc?.call) {
      params.bridge.devRpc.call("interaction.begin", request);
      while (true) {
        const state = asInteractionState(params.bridge.devRpc.call("interaction.get_state", { id: request.id }));
        if (state?.completed) {
          const response = asInteractionResponse(state.responseJson ? JSON.parse(state.responseJson) : null);
          params.bridge.devRpc.call("interaction.consume_completed", { id: request.id });
          if (response?.unavailable) {
            throw new InteractionUnavailableError(
              String(response.message || `Host does not support interaction request: ${request.type}`),
              request,
            );
          }
          return response;
        }
        await new Promise((resolve) => setTimeout(resolve, 50));
      }
    }

    const raw = params.bridge.callHost?.("pie.interaction", request);
    const response = asInteractionResponse(typeof raw === "string" ? JSON.parse(raw || "null") : raw);

    if (response?.unavailable) {
      throw new InteractionUnavailableError(
        String(response.message || `Host does not support interaction request: ${request.type}`),
        request,
      );
    }

    return response;
  });
}
