import type { AgentTool } from "@pie/agent-core";
import { createReadResourceCapability, createReadSkillCapability, createResolveResourceCapability } from "@pie/shared-headless-capabilities";
import { createUnitySkillLoader, readSkillResource } from "../skills.js";

export function createReadSkillTool(projectRoot: string): AgentTool {
  const loader = createUnitySkillLoader(projectRoot);
  const capability = createReadSkillCapability({
    skillLoader: loader,
  });
  return capability.tool;
}

export function createReadResourceTool(projectRoot: string): AgentTool {
  return createReadResourceCapability({
    resolveResource(owner, resourcePath) {
      return readSkillResource(projectRoot, owner, resourcePath);
    },
  }).tool as AgentTool;
}

export function createResolveResourceTool(projectRoot: string): AgentTool {
  return createResolveResourceCapability({
    resolveResource(owner, resourcePath) {
      const resource = readSkillResource(projectRoot, owner, resourcePath);
      if (!resource?.resolvedPath) {
        return null;
      }
      return {
        owner: resource.owner,
        path: resource.path,
        resolvedPath: resource.resolvedPath,
      };
    },
  }).tool as AgentTool;
}
