/**
 * Platform configuration
 * Provides unified access to platform-specific paths and settings
 */

import { detectPlatform } from "./detector.js";
import { createRequire } from "node:module";
import { fileURLToPath } from "node:url";

// Create require function for ESM compatibility
// @ts-ignore - import.meta.url is available in ESM
const __filename = fileURLToPath(import.meta.url);
const require = createRequire(__filename);

/**
 * Platform-specific configuration
 */
export interface PlatformConfig {
  /** Platform type */
  platform: "node" | "puerts" | "unknown";

  /** Root data directory for all Pie data */
  dataPath: string;

  /** Skills directory */
  skillsPath: string;

  /** Sessions directory */
  sessionsPath: string;

  /** Extensions directory */
  extensionsPath: string;

  /** Prompts/templates directory */
  promptsPath: string;

  /** Config directory */
  configPath: string;

  /** Path separator for current platform */
  sep: string;

  /** API keys (optional, from config file or environment) */
  apiKeys?: Record<string, string>;
}

/** Global CS namespace for PuerTS Unity interop */
declare const CS: any;

/**
 * Cached platform config
 */
let cachedConfig: PlatformConfig | null = null;

/**
 * Get the platform configuration
 * Returns a cached singleton instance
 */
export function getPlatformConfig(): PlatformConfig {
  if (cachedConfig) {
    return cachedConfig;
  }

  const platform = detectPlatform();
  let config: PlatformConfig;

  if (platform === "puerts" && typeof CS !== "undefined") {
    // Unity/PuerTS environment
    config = createUnityConfig();
  } else if (platform === "node") {
    // Node.js environment
    config = createNodeConfig();
  } else {
    // Unknown platform - use current directory
    config = createFallbackConfig();
  }

  cachedConfig = config;
  return config;
}

/**
 * Create configuration for Unity environment
 */
function createUnityConfig(): PlatformConfig {
  const UnityEngine = CS.UnityEngine;
  const Path = CS.System.IO.Path;
  const Directory = CS.System.IO.Directory;

  // Use persistentDataPath for cross-platform compatibility
  // - Windows: C:\Users\{user}\AppData\LocalLow\{company}\{product}
  // - macOS: ~/Library/Application Support/{company}/{product}
  // - Android: /storage/emulated/0/Android/data/{package}/files
  // - iOS: Application/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx/Documents
  // - Quest: Same as Android
  const dataPath = UnityEngine.Application.persistentDataPath;

  // Ensure base directory exists
  const pieDir = Path.Combine(dataPath, ".pie");
  if (!Directory.Exists(pieDir)) {
    Directory.CreateDirectory(pieDir);
  }

  return {
    platform: "puerts",
    dataPath,
    skillsPath: Path.Combine(pieDir, "skills"),
    sessionsPath: Path.Combine(pieDir, "sessions"),
    extensionsPath: Path.Combine(pieDir, "extensions"),
    promptsPath: Path.Combine(pieDir, "prompts"),
    configPath: Path.Combine(pieDir, "config"),
    sep: "/", // Unity uses forward slashes
  };
}

/**
 * Create configuration for Node.js environment
 */
function createNodeConfig(): PlatformConfig {
  const path = require("path");
  const fs = require("fs");

  // Use home directory for Node.js
  const homeDir = process.env.HOME || process.env.USERPROFILE || ".";
  const pieDir = path.join(homeDir, ".pie");

  // Ensure base directory exists
  if (!fs.existsSync(pieDir)) {
    fs.mkdirSync(pieDir, { recursive: true });
  }

  return {
    platform: "node",
    dataPath: homeDir,
    skillsPath: path.join(pieDir, "skills"),
    sessionsPath: path.join(pieDir, "sessions"),
    extensionsPath: path.join(pieDir, "extensions"),
    promptsPath: path.join(pieDir, "prompts"),
    configPath: path.join(pieDir, "config"),
    sep: path.sep,
  };
}

/**
 * Create fallback configuration for unknown platforms
 */
function createFallbackConfig(): PlatformConfig {
  return {
    platform: "unknown",
    dataPath: ".",
    skillsPath: ".pie/skills",
    sessionsPath: ".pie/sessions",
    extensionsPath: ".pie/extensions",
    promptsPath: ".pie/prompts",
    configPath: ".pie/config",
    sep: "/",
  };
}

/**
 * Reset cached config (mainly for testing)
 */
export function resetPlatformConfig(): void {
  cachedConfig = null;
}
