import type { AgentTool } from "@pie/agent-core";
import type { PathResolutionOptions } from "@pie/shared-headless-capabilities";
import { createInspectUnityContextTool } from "../tools/inspect-unity-context.js";
import { createNativeFindFilesTool } from "../tools/native-find-files.js";
import { createNativeGrepTextTool } from "../tools/native-grep-text.js";
import { createReadProjectMemoryTool, createWriteProjectMemoryTool } from "../tools/project-memory.js";
import { createUnityRuntimeTools } from "../tools/unity-dev-rpc.js";

export interface UnityHostCapabilityDefinition {
	id: string;
	description: string;
	tools: AgentTool[];
}

export interface UnityHostCapabilityAssembly {
	capabilities: UnityHostCapabilityDefinition[];
	tools: AgentTool[];
}

export interface UnityHostCapabilityOptions {
	filesystemSearchRoot: string;
	filesystemPathOptions?: PathResolutionOptions;
}

export function createUnityHostCapabilities(
	projectRoot: string,
	isEditor: boolean,
	options: UnityHostCapabilityOptions,
): UnityHostCapabilityAssembly {
	const inspectUnityContextTool = createInspectUnityContextTool(projectRoot, isEditor);
	const readProjectMemoryTool = createReadProjectMemoryTool(projectRoot);
	const writeProjectMemoryTool = createWriteProjectMemoryTool(projectRoot);
	const nativeFindTool = createNativeFindFilesTool(options.filesystemSearchRoot, options.filesystemPathOptions);
	const nativeGrepTool = createNativeGrepTextTool(options.filesystemSearchRoot, options.filesystemPathOptions);
	const unityRuntimeTools = createUnityRuntimeTools();

	const capabilities: UnityHostCapabilityDefinition[] = [
		{
			id: "inspect-unity-context",
			description: "Unity host capability for inspecting the live editor/runtime context.",
			tools: [inspectUnityContextTool, ...unityRuntimeTools],
		},
		{
			id: "project-memory-adapter",
			description: "Unity host adapter for the shared project-memory contract. Current disposition: future shared capability with host-specific executor.",
			tools: [readProjectMemoryTool, writeProjectMemoryTool],
		},
		{
			id: "filesystem-search-executor",
			description: "Unity host executor for shared filesystem search semantics (`find_files` / `grep_text`) backed by native file bridge calls.",
			tools: [nativeFindTool, nativeGrepTool],
		},
	];

	return {
		capabilities,
		tools: capabilities.flatMap((capability) => capability.tools),
	};
}
