/**
 * PuerTS (Unity) FileSystem implementation
 * Uses CS.System.IO for file operations
 */

import type { FileSystem, FileSystemEntry, PlatformType } from "./types.js";

/** Declare CS global for PuerTS Unity interop */
declare const CS: any;
declare const puer: any;

/**
 * Get CS.System.IO namespace
 */
function getSystemIO(): any {
  if (typeof CS === "undefined" || !CS?.System?.IO) {
    throw new Error("CS.System.IO not available - not running in PuerTS environment");
  }
  return CS.System.IO;
}

function getPieFileBridge(): any {
  if (typeof CS === "undefined" || !CS?.Pie?.PieFileBridge) {
    throw new Error("CS.Pie.PieFileBridge not available - runtime file bridge is missing");
  }
  return CS.Pie.PieFileBridge;
}

async function taskToPromise<T>(task: any): Promise<T> {
  const promiseFactory = (globalThis as any)?.puer?.$promise ?? (typeof puer !== "undefined" ? puer?.$promise : undefined);
  if (typeof promiseFactory === "function") {
    return await promiseFactory(task);
  }
  if (task && typeof task.then === "function") {
    return await task;
  }
  return task as T;
}

function toJsStringArray(value: any): string[] {
  if (Array.isArray(value)) {
    return value.map((entry) => String(entry ?? ""));
  }
  if (value && typeof value.Length === "number") {
    const results: string[] = [];
    for (let i = 0; i < value.Length; i++) {
      const entry = typeof value.get_Item === "function" ? value.get_Item(i) : value[i];
      results.push(String(entry ?? ""));
    }
    return results;
  }
  return [];
}

function convertBridgeStatResult(result: any): FileSystemEntry {
  return {
    name: String(result?.Name || ""),
    isDirectory: !!result?.IsDirectory,
    isFile: !!result?.IsFile,
    size: Number(result?.Size || 0),
    mtime: new Date((Number(result?.LastWriteTicksUtc || 0) - 621355968000000000) / 10000),
  };
}

/**
 * Convert C# DateTime to JavaScript Date
 */
function convertDateTime(dateTime: any): Date {
  if (!dateTime) return new Date(0);
  // C# DateTime ticks to JS timestamp
  const ticks = dateTime.get_Ticks?.() || 0;
  // ticks are 100-nanosecond intervals since 0001-01-01
  // JS timestamp is milliseconds since 1970-01-01
  const epochTicks = 621355968000000000; // ticks at 1970-01-01
  const ms = (ticks - epochTicks) / 10000;
  return new Date(ms);
}

/**
 * Convert C# FileInfo/Dire ctoryInfo to FileSystemEntry
 */
function convertFileSystemInfo(info: any): FileSystemEntry {
  if (!info) {
    return {
      name: "",
      isDirectory: false,
      isFile: false,
      size: 0,
      mtime: new Date(0),
    };
  }

  const isDir = info.Attributes !== undefined
    ? (info.Attributes & getSystemIO().FileAttributes.Directory) !== 0
    : false;

  return {
    name: info.Name || "",
    isDirectory: isDir,
    isFile: !isDir,
    size: info.Length || 0,
    mtime: info.LastWriteTimeUtc ? convertDateTime(info.LastWriteTimeUtc) : new Date(0),
  };
}

/**
 * PuerTS FileSystem implementation using CS.System.IO
 */
export class PuerTSFileSystem implements FileSystem {
  readonly platform: PlatformType = "puerts";
  sep: string = "/";

  constructor() {
    // Unity uses forward slashes for paths
    this.sep = "/";
  }

  private normalizePath(path: string): string {
    // Convert backslashes to forward slashes for Unity compatibility
    return path.replace(/\\/g, "/");
  }

  // File operations
  async readFile(path: string, encoding: BufferEncoding = "utf-8"): Promise<string> {
    const IO = getSystemIO();
    const bridge = getPieFileBridge();
    const normalizedPath = this.normalizePath(path);

    if (!IO.File.Exists(normalizedPath)) {
      throw new Error(`ENOENT: no such file or directory, open '${path}'`);
    }

    if (encoding === "base64") {
      if (typeof bridge.ReadAllBytesBase64Async === "function") {
        const content = await taskToPromise<any>(bridge.ReadAllBytesBase64Async(normalizedPath));
        return String(content ?? "");
      }
      const content = CS.System.Convert.ToBase64String(IO.File.ReadAllBytes(normalizedPath));
      return String(content ?? "");
    }

    const content = await taskToPromise<any>(bridge.ReadAllTextAsync(normalizedPath));
    return String(content ?? "");
  }

  readFileSync(path: string, encoding: BufferEncoding = "utf-8"): string {
    const IO = getSystemIO();
    const normalizedPath = this.normalizePath(path);
    
    if (!IO.File.Exists(normalizedPath)) {
      throw new Error(`ENOENT: no such file or directory, open '${path}'`);
    }

    if (encoding === "base64") {
      return String(CS.System.Convert.ToBase64String(IO.File.ReadAllBytes(normalizedPath)) ?? "");
    }

    return IO.File.ReadAllText(normalizedPath);
  }

  async writeFile(path: string, data: string, encoding: BufferEncoding = "utf-8"): Promise<void> {
    const bridge = getPieFileBridge();
    const normalizedPath = this.normalizePath(path);
    await taskToPromise<void>(bridge.WriteAllTextAsync(normalizedPath, data));
  }

  writeFileSync(path: string, data: string, encoding: BufferEncoding = "utf-8"): void {
    const IO = getSystemIO();
    const normalizedPath = this.normalizePath(path);
    
    // Ensure directory exists
    const dir = IO.Path.GetDirectoryName(normalizedPath);
    if (dir && !IO.Directory.Exists(dir)) {
      IO.Directory.CreateDirectory(dir);
    }

    IO.File.WriteAllText(normalizedPath, data);
  }

  // Directory operations
  async mkdir(path: string, options?: { recursive?: boolean }): Promise<void> {
    const IO = getSystemIO();
    const bridge = getPieFileBridge();
    const normalizedPath = this.normalizePath(path);

    if (IO.Directory.Exists(normalizedPath)) {
      return;
    }

    if (!options?.recursive) {
      const parent = IO.Path.GetDirectoryName(normalizedPath);
      if (parent && !IO.Directory.Exists(parent)) {
        throw new Error(`ENOENT: no such file or directory, mkdir '${path}'`);
      }
    }

    await taskToPromise<void>(bridge.CreateDirectoryAsync(normalizedPath));
  }

  mkdirSync(path: string, options?: { recursive?: boolean }): void {
    const IO = getSystemIO();
    const normalizedPath = this.normalizePath(path);

    if (IO.Directory.Exists(normalizedPath)) {
      return;
    }

    if (options?.recursive) {
      IO.Directory.CreateDirectory(normalizedPath);
    } else {
      const parent = IO.Path.GetDirectoryName(normalizedPath);
      if (parent && !IO.Directory.Exists(parent)) {
        throw new Error(`ENOENT: no such file or directory, mkdir '${path}'`);
      }
      IO.Directory.CreateDirectory(normalizedPath);
    }
  }

  async readdir(path: string): Promise<string[]> {
    const IO = getSystemIO();
    const bridge = getPieFileBridge();
    const normalizedPath = this.normalizePath(path);

    if (!IO.Directory.Exists(normalizedPath)) {
      throw new Error(`ENOENT: no such file or directory, scandir '${path}'`);
    }

    const entries = await taskToPromise<any>(bridge.ReadDirectoryAsync(normalizedPath));
    return toJsStringArray(entries);
  }

  readdirSync(path: string): string[] {
    const IO = getSystemIO();
    const normalizedPath = this.normalizePath(path);

    if (!IO.Directory.Exists(normalizedPath)) {
      throw new Error(`ENOENT: no such file or directory, scandir '${path}'`);
    }

    const entries: string[] = [];
    
    // Get files
    const files = IO.Directory.GetFiles(normalizedPath);
    for (let i = 0; i < files.Length; i++) {
      entries.push(IO.Path.GetFileName(files.get_Item(i)));
    }

    // Get directories
    const dirs = IO.Directory.GetDirectories(normalizedPath);
    for (let i = 0; i < dirs.Length; i++) {
      entries.push(IO.Path.GetFileName(dirs.get_Item(i)));
    }

    return entries;
  }

  // Path checks
  async exists(path: string): Promise<boolean> {
    const bridge = getPieFileBridge();
    const normalizedPath = this.normalizePath(path);
    return !!(await taskToPromise<any>(bridge.ExistsAsync(normalizedPath)));
  }

  existsSync(path: string): boolean {
    const IO = getSystemIO();
    const normalizedPath = this.normalizePath(path);
    return IO.File.Exists(normalizedPath) || IO.Directory.Exists(normalizedPath);
  }

  async stat(path: string): Promise<FileSystemEntry> {
    const IO = getSystemIO();
    const bridge = getPieFileBridge();
    const normalizedPath = this.normalizePath(path);

    if (!IO.File.Exists(normalizedPath) && !IO.Directory.Exists(normalizedPath)) {
      throw new Error(`ENOENT: no such file or directory, stat '${path}'`);
    }

    const result = await taskToPromise<any>(bridge.StatAsync(normalizedPath));
    return convertBridgeStatResult(result);
  }

  statSync(path: string): FileSystemEntry {
    const IO = getSystemIO();
    const normalizedPath = this.normalizePath(path);

    if (IO.File.Exists(normalizedPath)) {
      const info = new IO.FileInfo(normalizedPath);
      return convertFileSystemInfo(info);
    }

    if (IO.Directory.Exists(normalizedPath)) {
      const info = new IO.DirectoryInfo(normalizedPath);
      return convertFileSystemInfo(info);
    }

    throw new Error(`ENOENT: no such file or directory, stat '${path}'`);
  }

  async access(path: string, mode?: number): Promise<void> {
    const IO = getSystemIO();
    const normalizedPath = this.normalizePath(path);

    if (!IO.File.Exists(normalizedPath) && !IO.Directory.Exists(normalizedPath)) {
      throw new Error(`ENOENT: no such file or directory, access '${path}'`);
    }

    // Unity doesn't have explicit permission checks like Node.js
    // For now, just check existence
  }

  // File manipulation
  async unlink(path: string): Promise<void> {
    const IO = getSystemIO();
    const bridge = getPieFileBridge();
    const normalizedPath = this.normalizePath(path);

    if (!IO.File.Exists(normalizedPath)) {
      throw new Error(`ENOENT: no such file or directory, unlink '${path}'`);
    }

    await taskToPromise<void>(bridge.DeleteFileAsync(normalizedPath));
  }

  unlinkSync(path: string): void {
    const IO = getSystemIO();
    const normalizedPath = this.normalizePath(path);

    if (IO.File.Exists(normalizedPath)) {
      IO.File.Delete(normalizedPath);
    } else {
      throw new Error(`ENOENT: no such file or directory, unlink '${path}'`);
    }
  }

  // Path utilities - pure JavaScript implementation
  join(...paths: string[]): string {
    return paths
      .map(p => p.replace(/\\/g, "/"))
      .join("/")
      .replace(/\/+/g, "/");
  }

  dirname(path: string): string {
    const normalized = path.replace(/\\/g, "/");
    const lastSlash = normalized.lastIndexOf("/");
    if (lastSlash === -1) return ".";
    if (lastSlash === 0) return "/";
    return normalized.slice(0, lastSlash);
  }

  basename(path: string, ext?: string): string {
    const normalized = path.replace(/\\/g, "/");
    const lastSlash = normalized.lastIndexOf("/");
    const name = lastSlash === -1 ? normalized : normalized.slice(lastSlash + 1);
    if (ext && name.endsWith(ext)) {
      return name.slice(0, -ext.length);
    }
    return name;
  }

  extname(path: string): string {
    const base = this.basename(path);
    const lastDot = base.lastIndexOf(".");
    if (lastDot === -1 || lastDot === 0) return "";
    return base.slice(lastDot);
  }

  resolve(...paths: string[]): string {
    let resolved = "";
    for (const p of paths) {
      const normalized = p.replace(/\\/g, "/");
      if (this.isAbsolute(normalized)) {
        resolved = normalized;
      } else {
        resolved = resolved ? this.join(resolved, normalized) : normalized;
      }
    }
    return resolved || ".";
  }

  normalize(path: string): string {
    const normalized = path.replace(/\\/g, "/");
    const parts = normalized.split("/");
    const result: string[] = [];
    
    for (const part of parts) {
      if (part === "..") {
        if (result.length > 0 && result[result.length - 1] !== "..") {
          result.pop();
        } else {
          result.push("..");
        }
      } else if (part !== "." && part !== "") {
        result.push(part);
      }
    }
    
    const joined = result.join("/");
    return normalized.startsWith("/") ? "/" + joined : joined;
  }

  isAbsolute(path: string): boolean {
    const normalized = path.replace(/\\/g, "/");
    return normalized.startsWith("/") || /^[a-zA-Z]:/.test(normalized);
  }

  relative(from: string, to: string): string {
    const fromNormalized = this.normalize(from);
    const toNormalized = this.normalize(to);
    
    const fromParts = fromNormalized.split("/").filter(p => p);
    const toParts = toNormalized.split("/").filter(p => p);
    
    let commonIndex = 0;
    while (commonIndex < fromParts.length && 
           commonIndex < toParts.length && 
           fromParts[commonIndex] === toParts[commonIndex]) {
      commonIndex++;
    }
    
    const upCount = fromParts.length - commonIndex;
    const result = [...Array(upCount).fill(".."), ...toParts.slice(commonIndex)];
    
    return result.join("/") || ".";
  }
}
