import type { Api, FileUnderstandingKind, Model } from "./types.js";

export type ToolModelPurpose =
	| "web_search"
	| "read_file.image"
	| "read_file.video"
	| "read_file.audio"
	| "read_file.document";

export type ToolModelRouteSource =
	| "explicit"
	| "current_model"
	| "model_class"
	| "configured_model"
	| "unavailable";

export interface ToolModelRoute {
	provider?: string;
	modelId?: string;
}

export interface ToolModelRouteDecision {
	purpose: ToolModelPurpose;
	requiredCapability: "webSearch" | FileUnderstandingKind;
	routeSource: ToolModelRouteSource;
	model?: Model<Api>;
	apiKey?: string;
	fallbackReason?: string;
}

export const MODEL_CLASS_FALLBACK_ORDER: Array<"balanced" | "light" | "strong"> = ["balanced", "light", "strong"];

const WEB_SEARCH_CAPABILITY_PRIORITY: Record<string, number> = {
	anthropic_server_tool: 0,
	openai_responses: 1,
	chat_completions_web_search: 2,
};

function fileCapabilityIsSupported(value: unknown): boolean {
	if (value === true) return true;
	if (!value || typeof value !== "object") return false;
	return (value as { supported?: boolean }).supported !== false;
}

export function fileKindForToolModelPurpose(purpose: ToolModelPurpose): FileUnderstandingKind | undefined {
	if (purpose === "read_file.image") return "image";
	if (purpose === "read_file.video") return "video";
	if (purpose === "read_file.audio") return "audio";
	if (purpose === "read_file.document") return "document";
	return undefined;
}

export function requiredCapabilityForToolPurpose(purpose: ToolModelPurpose): "webSearch" | FileUnderstandingKind {
	return purpose === "web_search" ? "webSearch" : fileKindForToolModelPurpose(purpose)!;
}

export function modelSupportsToolPurpose(model: Model<Api>, purpose: ToolModelPurpose): boolean {
	if (purpose === "web_search") return Boolean(model.webSearch);
	const kind = fileKindForToolModelPurpose(purpose);
	if (!kind) return false;
	if (fileCapabilityIsSupported(model.fileCapabilities?.[kind])) return true;
	if (kind !== "document" && model.input.includes(kind)) return true;
	return false;
}

export function sortToolModelCandidatesByCapability(
	purpose: ToolModelPurpose,
	candidates: ToolModelRouteDecision[],
): ToolModelRouteDecision[] {
	if (purpose !== "web_search") return candidates;
	return [...candidates].sort((a, b) => {
		const aType = a.model?.webSearch?.type;
		const bType = b.model?.webSearch?.type;
		const aRank = aType ? WEB_SEARCH_CAPABILITY_PRIORITY[aType] ?? 99 : 99;
		const bRank = bType ? WEB_SEARCH_CAPABILITY_PRIORITY[bType] ?? 99 : 99;
		return aRank - bRank;
	});
}
