/**
 * Edit tool - Edit a file by replacing exact text.
 */

import type { AgentTool } from "@pie/agent-core";
import { Type } from "@sinclair/typebox";
import { getFileSystem } from "@pie/platform";
import { resolveToCwd, type PathResolutionOptions } from "./path-utils.js";
import { buildPathResolutionDescription, buildRootParameterSchema } from "./schema-utils.js";
import {
	detectLineEnding,
	fuzzyFindText,
	generateDiffString,
	normalizeForFuzzyMatch,
	normalizeToLF,
	restoreLineEndings,
	stripBom,
} from "./edit-diff.js";

export interface EditToolInput {
	path: string;
	root?: string;
	oldText: string;
	newText: string;
}

export interface EditToolDetails {
	diff: string;
	firstChangedLine?: number;
}

function validateEditArgs(path: unknown, oldText: unknown, newText: unknown): void {
	const filePath = typeof path === "string" ? path.trim() : "";
	if (!filePath) {
		throw new Error("Invalid edit_file arguments: path cannot be empty. Pass the file path in path and the exact text to replace in oldText.");
	}
	if (typeof oldText !== "string" || oldText.length === 0) {
		throw new Error("Invalid edit_file arguments: oldText cannot be empty. Read the file and pass the exact text to replace.");
	}
	if (typeof newText !== "string") {
		throw new Error("Invalid edit_file arguments: newText must be a string.");
	}
	if (oldText === newText) {
		throw new Error("Invalid edit_file arguments: oldText and newText are identical, so the edit would make no change.");
	}
	if (filePath.includes("<|tool") || oldText.includes("<|tool") || newText.includes("<|tool")) {
		throw new Error("Invalid edit_file arguments: path, oldText, and newText must be real edit values, not tool-call markup.");
	}
}

function countOccurrences(content: string, needle: string): number {
	if (needle.length === 0) return 0;
	let count = 0;
	let index = 0;
	while (true) {
		const nextIndex = content.indexOf(needle, index);
		if (nextIndex === -1) break;
		count++;
		index = nextIndex + needle.length;
	}
	return count;
}

export function createEditTool(
	cwd: string,
	options?: PathResolutionOptions,
): AgentTool<any> {
	const fs = getFileSystem();
	const rootSchema = buildRootParameterSchema(cwd, options);
	const editSchema = Type.Object({
		path: Type.String({ description: "Path to the file to edit." }),
		...(rootSchema ? { root: rootSchema } : {}),
		oldText: Type.String({ description: "Exact text to find and replace (must match exactly)" }),
		newText: Type.String({ description: "New text to replace the old text with" }),
	});
	const pathResolutionDescription = buildPathResolutionDescription(cwd, options);

	return {
		name: "edit",
		label: "edit",
		description:
			`Edit a file by replacing exact text. The oldText must match exactly (including whitespace). Use this for precise, surgical edits. ${pathResolutionDescription}`,
		parameters: editSchema,
		execute: async (
			_toolCallId: string,
			params: any,
			signal?: AbortSignal,
		) => {
			const { path, root, oldText, newText } = params;
			validateEditArgs(path, oldText, newText);
			const absolutePath = resolveToCwd(path, cwd, options, root);

			return new Promise<{
				content: Array<{ type: "text"; text: string }>;
				details: EditToolDetails | undefined;
			}>((resolve, reject) => {
				if (signal?.aborted) {
					reject(new Error("Operation aborted"));
					return;
				}

				let aborted = false;
				const onAbort = () => {
					aborted = true;
					reject(new Error("Operation aborted"));
				};

				if (signal) {
					signal.addEventListener("abort", onAbort, { once: true });
				}

				(async () => {
					try {
						try {
							await fs.access(absolutePath);
						} catch {
							if (signal) signal.removeEventListener("abort", onAbort);
							reject(new Error(`File not found: ${path}`));
							return;
						}

						if (aborted) return;

						const rawContent = await fs.readFile(absolutePath, "utf-8");

						if (aborted) return;

						// Strip BOM before matching
						const { bom, text: content } = stripBom(rawContent);

						const originalEnding = detectLineEnding(content);
						const normalizedContent = normalizeToLF(content);
						const normalizedOldText = normalizeToLF(oldText);
						const normalizedNewText = normalizeToLF(newText);

						// Find the old text using fuzzy matching
						const matchResult = fuzzyFindText(normalizedContent, normalizedOldText);

						if (!matchResult.found) {
							if (signal) signal.removeEventListener("abort", onAbort);
							reject(
								new Error(
									`Could not find the exact text in ${path}. The old text must match exactly including all whitespace and newlines.`,
								),
							);
							return;
						}

						// Count occurrences after the same normalization used for fuzzy matches.
						const fuzzyContent = normalizeForFuzzyMatch(normalizedContent);
						const fuzzyOldText = normalizeForFuzzyMatch(normalizedOldText);
						const occurrences = countOccurrences(fuzzyContent, fuzzyOldText);

						if (occurrences > 1) {
							if (signal) signal.removeEventListener("abort", onAbort);
							reject(
								new Error(
									`Found ${occurrences} occurrences of the text in ${path}. The text must be unique. Please provide more context to make it unique.`,
								),
							);
							return;
						}

						if (aborted) return;

						// Perform replacement
						const baseContent = matchResult.contentForReplacement;
						const newContent =
							baseContent.substring(0, matchResult.index) +
							normalizedNewText +
							baseContent.substring(matchResult.index + matchResult.matchLength);

						if (baseContent === newContent) {
							if (signal) signal.removeEventListener("abort", onAbort);
							reject(
								new Error(
									`No changes made to ${path}. The replacement produced identical content.`,
								),
							);
							return;
						}

						const finalContent = bom + restoreLineEndings(newContent, originalEnding);
						await fs.writeFile(absolutePath, finalContent, "utf-8");

						if (aborted) return;

						if (signal) {
							signal.removeEventListener("abort", onAbort);
						}

						const diffResult = generateDiffString(content, finalContent);
						resolve({
							content: [
								{
									type: "text",
									text: `Successfully replaced text in ${path}.`,
								},
								{ type: "text", text: diffResult.diff },
							],
							details: { diff: diffResult.diff, firstChangedLine: diffResult.firstChangedLine },
						});
					} catch (error: any) {
						if (signal) {
							signal.removeEventListener("abort", onAbort);
						}
						if (!aborted) {
							reject(error);
						}
					}
				})();
			});
		},
	};
}
