import type { AgentTool, AgentToolResult } from "@pie/agent-core";
import type { Api, Model, ToolModelRouteDecision } from "@pie/ai";
import { Type, type Static } from "@sinclair/typebox";
import {
	createSharedWebFetchTool,
	type WebFetchDetails,
} from "./web-fetch.js";
import {
	createSharedWebSearchTool,
	type WebSearchDetails,
	type WebSearchInput,
	type WebSearchProviderAttempt,
	type WebSearchSource,
	type WebSearchToolDeps,
} from "./web-search.js";

const webResearchSchema = Type.Object({
	query: Type.String({
		minLength: 2,
		description: "The research question or topic. Use for end-to-end public web research.",
	}),
	allowed_domains: Type.Optional(Type.Array(Type.String({
		description: "Only include sources from these domains. Use only when the user explicitly asks to limit sources.",
	}))),
	blocked_domains: Type.Optional(Type.Array(Type.String({
		description: "Exclude sources from these domains. Use only when the user explicitly asks to avoid sources.",
	}))),
	max_sources: Type.Optional(Type.Number({
		minimum: 1,
		maximum: 8,
		description: "Maximum credible sources to fetch and cite. Defaults to 3.",
	})),
});

export type WebResearchInput = Static<typeof webResearchSchema>;

export interface RenderedPageReaderRequest {
	url: string;
	query: string;
}

export interface RenderedPageReaderResult {
	url: string;
	finalUrl?: string;
	title?: string;
	text: string;
	citationAnchors?: Array<{ url: string; title?: string; startOffset: number; endOffset: number }>;
	screenshotPath?: string;
	consoleMessages?: string[];
	networkRequests?: string[];
}

export type RenderedPageReader = (request: RenderedPageReaderRequest, signal?: AbortSignal) => Promise<RenderedPageReaderResult>;

export interface WebResearchSourceScore {
	source: WebSearchSource;
	score: number;
	reasons: string[];
}

export interface WebResearchFetchedSource {
	url: string;
	finalUrl?: string;
	title?: string;
	textExcerpt?: string;
	score: number;
	scoreReasons: string[];
	extractionMethod?: WebFetchDetails["extractionMethod"] | "browser_rendered";
	citationAnchors?: WebFetchDetails["citationAnchors"];
	requiresBrowser?: boolean;
	failureCategory?: WebFetchDetails["failureCategory"];
	browserReadSummary?: {
		screenshotPath?: string;
		consoleMessageCount?: number;
		networkRequestCount?: number;
	};
}

export interface WebResearchAttempt {
	phase: "search" | "fetch" | "browser";
	query?: string;
	url?: string;
	status: "completed" | "failed";
	failureCategory?: string;
	warnings?: string[];
	durationMs?: number;
}

export interface WebResearchProviderHealth {
	routeKey: string;
	attempts: number;
	successes: number;
	failures: number;
	lowQuality: number;
	rateLimited: number;
	timeouts: number;
	totalDurationMs: number;
	totalSources: number;
	updatedAt: number;
}

export interface WebResearchDetails {
	query: string;
	actualQueries: string[];
	sources: WebSearchSource[];
	fetchedSources: WebResearchFetchedSource[];
	providerAttempts: WebSearchProviderAttempt[];
	attempts: WebResearchAttempt[];
	qualityScore: number;
	warnings: string[];
	browserRequiredSources: WebResearchFetchedSource[];
	providerHealth?: WebResearchProviderHealth[];
	routeRankReason?: string[];
	latencyMetrics?: {
		totalDurationMs: number;
		searchDurationMs: number;
		fetchDurationMs: number;
		browserDurationMs: number;
		p95SourceReadMs?: number;
	};
	costEstimate?: {
		status: "unknown";
		reason: string;
	};
}

export interface WebResearchDeps {
	getModel: () => Model<Api> | undefined;
	getApiKey: () => string | undefined;
	getMode?: WebSearchToolDeps["getMode"];
	resolveToolModel?: WebSearchToolDeps["resolveToolModel"];
	resolveToolModelCandidates?: (purpose: "web_search") => ToolModelRouteDecision[] | undefined;
	timeoutMs?: number;
	maxBytes?: number;
	maxChars?: number;
	allowPrivateHosts?: () => boolean;
	fetch?: typeof fetch;
	webSearchTool?: AgentTool<any, WebSearchDetails>;
	webFetchTool?: AgentTool<any, WebFetchDetails>;
	renderedPageReader?: RenderedPageReader;
	loadProviderHealth?: () => WebResearchProviderHealth[] | undefined;
	saveProviderHealth?: (entries: WebResearchProviderHealth[]) => void | Promise<void>;
	getCurrentDateContext?: WebSearchToolDeps["getCurrentDateContext"];
	searchAttemptTimeoutMs?: number;
	fetchAttemptTimeoutMs?: number;
	browserAttemptTimeoutMs?: number;
}

const DEFAULT_WEB_RESEARCH_SEARCH_ATTEMPT_TIMEOUT_MS = 45_000;
const DEFAULT_WEB_RESEARCH_FETCH_ATTEMPT_TIMEOUT_MS = 30_000;
const DEFAULT_WEB_RESEARCH_BROWSER_ATTEMPT_TIMEOUT_MS = 45_000;

function isRecord(value: unknown): value is Record<string, unknown> {
	return !!value && typeof value === "object" && !Array.isArray(value);
}

function textFromResult(result: AgentToolResult<any>): string {
	return result.content
		.filter((item): item is { type: "text"; text: string } => item.type === "text" && typeof item.text === "string")
		.map((item) => item.text)
		.join("\n")
		.trim();
}

function clamp(value: number, min: number, max: number): number {
	return Math.min(max, Math.max(min, value));
}

type ParsedResearchUrl = {
	href: string;
	hostname: string;
	pathname: string;
	search: string;
	hasSearchParam(name: string): boolean;
};

function normalizeHost(hostname: string): string {
	return hostname.toLowerCase().replace(/^www\./, "");
}

function parseResearchUrl(value: string): ParsedResearchUrl | null {
	const trimmed = value.trim();
	const match = /^(https?):\/\/([^/?#]+)([^?#]*)?(\?[^#]*)?(#.*)?$/i.exec(trimmed);
	if (!match) return null;
	const protocol = match[1].toLowerCase();
	const rawHost = match[2].replace(/^[^@]+@/, "");
	const hostname = rawHost.startsWith("[") ? rawHost : rawHost.split(":")[0];
	const pathname = match[3] && match[3].startsWith("/") ? match[3] : "/";
	const search = match[4] || "";
	const href = `${protocol}://${rawHost}${pathname}${search}`;
	return {
		href,
		hostname,
		pathname,
		search,
		hasSearchParam(name: string): boolean {
			const escaped = name.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
			return new RegExp(`(?:^\\?|&)${escaped}(?:=|&|$)`, "i").test(search);
		},
	};
}

function sourceKey(url: string): string {
	const parsed = parseResearchUrl(url);
	if (!parsed) return url.trim();
	return parsed.href.replace(/\/$/, "");
}

function isSearchPage(url: ParsedResearchUrl): boolean {
	const host = normalizeHost(url.hostname);
	if (/(google|bing|duckduckgo|baidu|yahoo|yandex)\./.test(host)) return true;
	return /(^|\/)(search|results)(\/|$)/i.test(url.pathname) || url.hasSearchParam("q");
}

function isHomepage(url: ParsedResearchUrl): boolean {
	return (url.pathname === "" || url.pathname === "/") && !url.search;
}

function looksOfficial(url: ParsedResearchUrl): boolean {
	const host = normalizeHost(url.hostname);
	return host.startsWith("docs.")
		|| host.startsWith("developer.")
		|| host.startsWith("developers.")
		|| host.startsWith("learn.")
		|| host.startsWith("api.")
		|| /(^|\.)gov$/.test(host)
		|| /(^|\.)edu$/.test(host)
		|| /\/(docs|documentation|reference|guide|guides|api|manual)\b/i.test(url.pathname);
}

function looksGithubAuthoritative(url: ParsedResearchUrl): boolean {
	const host = normalizeHost(url.hostname);
	if (host !== "github.com") return false;
	return /\/(releases|issues|pull|wiki|blob|tree|commit)\b/i.test(url.pathname);
}

function looksNewsAuthority(url: ParsedResearchUrl): boolean {
	const host = normalizeHost(url.hostname);
	return [
		"apnews.com",
		"reuters.com",
		"bbc.com",
		"pbs.org",
		"npr.org",
		"theguardian.com",
		"nytimes.com",
		"wsj.com",
		"chinadaily.com.cn",
		"xinhuanet.com",
	].some((domain) => host === domain || host.endsWith(`.${domain}`));
}

export function scoreWebResearchSource(source: WebSearchSource): WebResearchSourceScore {
	const reasons: string[] = [];
	let score = 45;
	const url = parseResearchUrl(source.url);
	if (!url) {
		score = 0;
		reasons.push("invalid_url");
		return { source, score, reasons };
	}
	if (looksOfficial(url)) {
		score += 35;
		reasons.push("official_or_docs");
	}
	if (looksGithubAuthoritative(url)) {
		score += 25;
		reasons.push("github_primary_source");
	}
	if (looksNewsAuthority(url)) {
		score += 20;
		reasons.push("news_authority");
	}
	if (isHomepage(url)) {
		score -= 35;
		reasons.push("homepage");
	}
	if (isSearchPage(url)) {
		score -= 60;
		reasons.push("search_page");
	}
	if (!source.title?.trim()) {
		score -= 15;
		reasons.push("missing_title");
	}
	if (/\.pdf($|\?)/i.test(url.pathname)) {
		score += 10;
		reasons.push("pdf_document");
	}
	return { source, score: clamp(score, 0, 100), reasons };
}

function dedupeSources(sources: WebSearchSource[]): WebSearchSource[] {
	const seen = new Set<string>();
	const deduped: WebSearchSource[] = [];
	for (const source of sources) {
		if (!source.url) continue;
		const key = sourceKey(source.url);
		if (seen.has(key)) continue;
		seen.add(key);
		deduped.push(source);
	}
	return deduped;
}

function hasChinese(text: string): boolean {
	return /[\u3400-\u9fff]/.test(text);
}

function isRecentQuery(text: string): boolean {
	return /\b(today|latest|current|recent|news|202[0-9]|release|changelog)\b/i.test(text)
		|| /(今天|最新|新闻|最近|当前|今日|发布|更新)/.test(text);
}

function isDocsQuery(text: string): boolean {
	return /\b(docs?|documentation|api|reference|guide|manual|release notes?|changelog|github|issue)\b/i.test(text)
		|| /(文档|官方|接口|指南|发布说明|更新日志|issue|问题)/i.test(text);
}

export function planWebResearchQueries(query: string, dateContext?: { currentDate?: string; timeZone?: string }): string[] {
	const trimmed = query.trim();
	const variants = new Set<string>([trimmed]);
	const year = dateContext?.currentDate?.slice(0, 4) || String(new Date().getFullYear());
	if (isRecentQuery(trimmed)) {
		variants.add(`${trimmed} ${year}`);
	}
	if (isDocsQuery(trimmed)) {
		variants.add(`${trimmed} official documentation`);
		variants.add(`${trimmed} GitHub release changelog issue`);
	} else {
		variants.add(`${trimmed} official sources documentation GitHub release changelog`);
	}
	if (hasChinese(trimmed)) {
		variants.add(`${trimmed} 官方 文档 来源`);
		if (isRecentQuery(trimmed)) variants.add(`${trimmed} ${year} today news`);
	}
	return [...variants].slice(0, 5);
}

function routeKeyFromAttempt(attempt: WebSearchProviderAttempt): string | undefined {
	if (!attempt.provider && !attempt.modelId && !attempt.providerMode) return undefined;
	return `${attempt.provider || "unknown"}/${attempt.modelId || "unknown"}:${attempt.providerMode}`;
}

function routeKeyFromDecision(route: ToolModelRouteDecision): string {
	const model = route.model as Model<Api> | undefined;
	const providerMode = model?.webSearch?.type || "unavailable";
	return `${model?.provider || "unknown"}/${model?.id || "unknown"}:${providerMode}`;
}

function healthPenalty(health: WebResearchProviderHealth | undefined): number {
	if (!health || health.attempts === 0) return 0;
	const failureRate = health.failures / health.attempts;
	const lowQualityRate = health.lowQuality / health.attempts;
	const rateLimitRate = health.rateLimited / health.attempts;
	return failureRate * 40 + lowQualityRate * 25 + rateLimitRate * 25;
}

function sortCandidatesByHealth(
	candidates: ToolModelRouteDecision[],
	healthEntries: WebResearchProviderHealth[] | undefined,
): ToolModelRouteDecision[] {
	if (!healthEntries?.length) return candidates;
	const healthByKey = new Map(healthEntries.map((entry) => [entry.routeKey, entry]));
	return [...candidates].sort((a, b) => healthPenalty(healthByKey.get(routeKeyFromDecision(a))) - healthPenalty(healthByKey.get(routeKeyFromDecision(b))));
}

function describeRouteRanking(
	candidates: ToolModelRouteDecision[],
	healthEntries: WebResearchProviderHealth[] | undefined,
): string[] {
	if (!candidates.length) return ["no configured web_search route candidates"];
	const healthByKey = new Map((healthEntries || []).map((entry) => [entry.routeKey, entry]));
	return candidates.slice(0, 5).map((candidate, index) => {
		const key = routeKeyFromDecision(candidate);
		const health = healthByKey.get(key);
		if (!health || health.attempts === 0) return `${index + 1}. ${key}: no prior health data`;
		const successRate = Math.round((health.successes / Math.max(1, health.attempts)) * 100);
		const lowQualityRate = Math.round((health.lowQuality / Math.max(1, health.attempts)) * 100);
		const medianLatencyMs = Math.round(health.totalDurationMs / Math.max(1, health.attempts));
		return `${index + 1}. ${key}: success=${successRate}%, lowQuality=${lowQualityRate}%, avgLatencyMs=${medianLatencyMs}, penalty=${Math.round(healthPenalty(health))}`;
	});
}

function updateProviderHealth(
	current: WebResearchProviderHealth[] | undefined,
	attempts: WebSearchProviderAttempt[],
): WebResearchProviderHealth[] {
	const byKey = new Map<string, WebResearchProviderHealth>((current || []).map((entry) => [entry.routeKey, { ...entry }]));
	for (const attempt of attempts) {
		const key = routeKeyFromAttempt(attempt);
		if (!key) continue;
		const entry = byKey.get(key) ?? {
			routeKey: key,
			attempts: 0,
			successes: 0,
			failures: 0,
			lowQuality: 0,
			rateLimited: 0,
			timeouts: 0,
			totalDurationMs: 0,
			totalSources: 0,
			updatedAt: Date.now(),
		};
		entry.attempts += 1;
		entry.totalDurationMs += Math.round(attempt.durationSeconds * 1000);
		entry.totalSources += attempt.sourceCount || 0;
		if (attempt.failureCategory) entry.failures += 1;
		else entry.successes += 1;
		if (attempt.failureCategory === "low_quality_result" || attempt.qualityWarnings?.length) entry.lowQuality += 1;
		if (attempt.failureCategory === "rate_limited") entry.rateLimited += 1;
		if (attempt.failureCategory === "timeout") entry.timeouts += 1;
		entry.updatedAt = Date.now();
		byKey.set(key, entry);
	}
	return [...byKey.values()].sort((a, b) => b.updatedAt - a.updatedAt).slice(0, 20);
}

function contentDetails(result: AgentToolResult<any>): Record<string, unknown> {
	return isRecord(result.details) ? result.details : {};
}

function excerpt(text: string, max = 1400): string {
	const clean = text.replace(/\s+/g, " ").trim();
	return clean.length > max ? `${clean.slice(0, max)}...` : clean;
}

function qualityScore(fetched: WebResearchFetchedSource[], scored: WebResearchSourceScore[]): number {
	if (!fetched.length) return 0;
	const fetchScore = Math.min(70, fetched.length * 25);
	const averageSourceScore = fetched.length
		? fetched.reduce((sum, item) => sum + item.score, 0) / fetched.length
		: scored.length
			? scored.slice(0, Math.max(1, fetched.length)).reduce((sum, item) => sum + item.score, 0) / Math.max(1, Math.min(scored.length, fetched.length))
		: 0;
	const citationBonus = fetched.some((item) => item.citationAnchors?.length) ? 10 : 0;
	return clamp(Math.round(fetchScore + averageSourceScore * 0.25 + citationBonus), 0, 100);
}

function percentile(values: number[], p: number): number | undefined {
	const sorted = values.filter((value) => Number.isFinite(value)).sort((a, b) => a - b);
	if (!sorted.length) return undefined;
	const index = Math.min(sorted.length - 1, Math.max(0, Math.ceil((p / 100) * sorted.length) - 1));
	return sorted[index];
}

function formatResearchPack(query: string, fetchedSources: WebResearchFetchedSource[], warnings: string[], browserRequiredSources: WebResearchFetchedSource[]): string {
	const lines = [
		`Web research pack for: ${query}`,
		"",
		"Use the fetched sources below for the final answer. Do not rely on snippets alone.",
		"If the fetched sources answer the user's request, answer directly; do not run another web_search or web_fetch loop for the same request.",
		"",
		"Fetched sources:",
	];
	fetchedSources.forEach((source, index) => {
		lines.push(`${index + 1}. ${source.title || source.finalUrl || source.url}`);
		lines.push(`   URL: ${source.finalUrl || source.url}`);
		lines.push(`   Excerpt: ${source.textExcerpt || "(no excerpt)"}`);
	});
	if (browserRequiredSources.length) {
		lines.push("");
		lines.push("Browser-required sources:");
		for (const source of browserRequiredSources) {
			lines.push(`- ${source.finalUrl || source.url}`);
		}
	}
	if (warnings.length) {
		lines.push("");
		lines.push("Warnings:");
		for (const warning of warnings) lines.push(`- ${warning}`);
	}
	lines.push("");
	lines.push("Sources:");
	for (const source of fetchedSources) lines.push(`- ${source.finalUrl || source.url}`);
	return lines.join("\n");
}

function createChildSignal(parentSignal: AbortSignal | undefined): { signal: AbortSignal; abort: (reason?: unknown) => void; dispose: () => void } {
	const controller = new AbortController();
	const onAbort = () => controller.abort(parentSignal?.reason);
	if (parentSignal?.aborted) onAbort();
	else parentSignal?.addEventListener("abort", onAbort, { once: true });
	return {
		signal: controller.signal,
		abort: (reason?: unknown) => controller.abort(reason),
		dispose: () => parentSignal?.removeEventListener("abort", onAbort),
	};
}

async function runWithDeadline<T>(
	operation: (signal: AbortSignal) => Promise<T>,
	timeoutMs: number,
	message: string,
	parentSignal?: AbortSignal,
): Promise<T> {
	const child = createChildSignal(parentSignal);
	let timer: NodeJS.Timeout | undefined;
	try {
		return await new Promise<T>((resolve, reject) => {
			timer = setTimeout(() => {
				const error = new Error(message);
				child.abort(error);
				reject(error);
			}, timeoutMs);
			operation(child.signal).then(resolve, reject);
		});
	} finally {
		if (timer) clearTimeout(timer);
		child.dispose();
	}
}

export function createSharedWebResearchTool(deps: WebResearchDeps): AgentTool<typeof webResearchSchema, WebResearchDetails> {
	const initialHealth = deps.loadProviderHealth?.();
	const initialCandidates = deps.resolveToolModelCandidates?.("web_search") ?? [];
	const webSearchTool = deps.webSearchTool ?? createSharedWebSearchTool({
		...deps,
		resolveToolModelCandidates: (purpose) => sortCandidatesByHealth(deps.resolveToolModelCandidates?.(purpose) ?? [], deps.loadProviderHealth?.() ?? initialHealth),
	});
	const webFetchTool = deps.webFetchTool ?? createSharedWebFetchTool(deps);

	return {
		name: "web_research",
		label: "web_research",
		description: "Run end-to-end public web research: plan search queries, search provider-native sources, fetch credible pages, and return a cited research pack. Use for general online research, current information, official docs, news, releases, issues, and webpage summaries. Use web_search/web_fetch directly only when you need precise low-level control. Do not use bash/curl/Python as a web research fallback.",
		parameters: webResearchSchema,
		capabilityMetadata: {
			riskClass: "network",
			concurrencySafe: true,
			permissionScope: "network",
			readsNetwork: true,
			availableInPlanMode: true,
			allowedForSubagentByDefault: true,
			maxOutputChars: 100_000,
		},
		execute: async (_toolCallId, rawParams, signal, onUpdate) => {
			const input = rawParams as WebResearchInput;
			const totalStartedAt = Date.now();
			const currentHealth = deps.loadProviderHealth?.() ?? initialHealth;
			const activeCandidates = deps.resolveToolModelCandidates?.("web_search") ?? initialCandidates;
			const rankedCandidates = sortCandidatesByHealth(activeCandidates, currentHealth);
			const routeRankReason = describeRouteRanking(rankedCandidates.length ? rankedCandidates : activeCandidates, currentHealth);
			const query = String(input.query || "").trim();
			const maxSources = clamp(Math.floor(input.max_sources ?? 3), 1, 8);
			const searchAttemptTimeoutMs = Math.max(1_000, deps.searchAttemptTimeoutMs ?? deps.timeoutMs ?? DEFAULT_WEB_RESEARCH_SEARCH_ATTEMPT_TIMEOUT_MS);
			const fetchAttemptTimeoutMs = Math.max(1_000, deps.fetchAttemptTimeoutMs ?? DEFAULT_WEB_RESEARCH_FETCH_ATTEMPT_TIMEOUT_MS);
			const browserAttemptTimeoutMs = Math.max(1_000, deps.browserAttemptTimeoutMs ?? DEFAULT_WEB_RESEARCH_BROWSER_ATTEMPT_TIMEOUT_MS);
			const attempts: WebResearchAttempt[] = [];
			const providerAttempts: WebSearchProviderAttempt[] = [];
			const warnings: string[] = [];
			const sourceReadDurations: number[] = [];
			const actualQueries: string[] = [];
			const allSources: WebSearchSource[] = [];
			const dateContext = deps.getCurrentDateContext?.();
			const queryVariants = planWebResearchQueries(query, dateContext);
			const minimumSearchQueries = 1;
			let searchedQueries = 0;
			let searchDurationMs = 0;
			let fetchDurationMs = 0;
			let browserDurationMs = 0;

			if (!query) {
				return {
					content: [{ type: "text", text: "web_research requires a non-empty query." }],
					details: {
						query,
						actualQueries: [],
						sources: [],
						fetchedSources: [],
						providerAttempts: [],
						attempts: [],
						qualityScore: 0,
						warnings: ["missing_query"],
						browserRequiredSources: [],
						routeRankReason,
						latencyMetrics: { totalDurationMs: Date.now() - totalStartedAt, searchDurationMs: 0, fetchDurationMs: 0, browserDurationMs: 0 },
						costEstimate: { status: "unknown", reason: "Provider usage is not yet normalized across web research search/fetch/browser routes." },
					},
					isError: true,
				};
			}

			for (const variant of queryVariants) {
				const startedAt = Date.now();
				const allowedDomains = input.allowed_domains?.length ? input.allowed_domains : undefined;
				const blockedDomains = allowedDomains ? undefined : input.blocked_domains;
				if (allowedDomains && input.blocked_domains?.length && warnings.length === 0) {
					warnings.push("Both allowed_domains and blocked_domains were provided; web_research used allowed_domains and ignored blocked_domains for provider compatibility.");
				}
				const searchInput: WebSearchInput = {
					query: variant,
					allowed_domains: allowedDomains,
					blocked_domains: blockedDomains,
				};
				onUpdate?.({
					content: [{ type: "text", text: `Searching web for: ${variant} (timeout ${Math.ceil(searchAttemptTimeoutMs / 1000)}s)` }],
					details: { query, actualQueries: [...actualQueries, variant], attempts, providerAttempts, fetchedSources: [], sources: dedupeSources(allSources), qualityScore: 0, warnings, browserRequiredSources: [] },
				});
				let result: AgentToolResult<WebSearchDetails>;
				try {
					result = await runWithDeadline(
						(childSignal) => webSearchTool.execute("web_research_search", searchInput, childSignal),
						searchAttemptTimeoutMs,
						`web_research search attempt timed out after ${Math.ceil(searchAttemptTimeoutMs / 1000)} seconds`,
						signal,
					);
				} catch (error) {
					const message = error instanceof Error ? error.message : String(error);
					attempts.push({
						phase: "search",
						query: variant,
						status: "failed",
						failureCategory: "timeout",
						warnings: [message],
						durationMs: Date.now() - startedAt,
					});
					searchDurationMs += Date.now() - startedAt;
					warnings.push(`${variant}: ${message}`);
					actualQueries.push(variant);
					break;
				}
				const details = contentDetails(result) as Partial<WebSearchDetails>;
				searchDurationMs += Date.now() - startedAt;
				attempts.push({
					phase: "search",
					query: variant,
					status: result.isError ? "failed" : "completed",
					failureCategory: details.failureCategory,
					warnings: details.qualityWarnings,
					durationMs: Date.now() - startedAt,
				});
				if (details.actualQueries?.length) actualQueries.push(...details.actualQueries);
				else actualQueries.push(variant);
				if (details.attempts?.length) providerAttempts.push(...details.attempts);
				if (details.qualityWarnings?.length) warnings.push(...details.qualityWarnings.map((warning) => `${variant}: ${warning}`));
				if (Array.isArray(details.sources)) allSources.push(...details.sources);
				searchedQueries += 1;
				const dedupedSoFar = dedupeSources(allSources);
				const scoredSoFar = dedupedSoFar.map(scoreWebResearchSource).sort((a, b) => b.score - a.score);
				const highQualitySources = scoredSoFar.filter((item) => item.score >= 70).length;
				const searchSourceTarget = Math.min(maxSources, 3);
				const enoughHighQuality = highQualitySources >= Math.min(searchSourceTarget, 2)
					|| (highQualitySources >= 1 && dedupedSoFar.length >= searchSourceTarget * 2)
					|| (highQualitySources >= 1 && maxSources === 1);
				if (searchedQueries >= minimumSearchQueries && enoughHighQuality && !result.isError) {
					warnings.push(`Fast path used after ${searchedQueries} search quer${searchedQueries === 1 ? "y" : "ies"}: high-quality source target reached.`);
					break;
				}
				if (searchedQueries >= minimumSearchQueries && dedupeSources(allSources).length >= maxSources * 3 && !result.isError) break;
			}

			const nextHealth = updateProviderHealth(deps.loadProviderHealth?.() ?? initialHealth, providerAttempts);
			await deps.saveProviderHealth?.(nextHealth);

			const dedupedSources = dedupeSources(allSources);
			const scoredSources = dedupedSources.map(scoreWebResearchSource).sort((a, b) => b.score - a.score);
			const fetchedSources: WebResearchFetchedSource[] = [];
			const browserRequiredSources: WebResearchFetchedSource[] = [];
			const minimumFetchedSources = Math.min(maxSources, 2);
			const targetFetchedSources = Math.min(maxSources, 3);
			const candidateSources = scoredSources.filter((scored) => {
				if (scored.score < 35) {
					warnings.push(`Filtered low-quality source: ${scored.source.url} (${scored.reasons.join(", ") || "low_score"})`);
					return false;
				}
				return true;
			});

			const fetchScoredSource = async (scored: WebResearchSourceScore): Promise<void> => {
				const startedAt = Date.now();
				onUpdate?.({
					content: [{ type: "text", text: `Fetching source: ${scored.source.url}` }],
					details: { query, actualQueries: [...new Set(actualQueries)], sources: dedupedSources, fetchedSources, providerAttempts, attempts, qualityScore: qualityScore(fetchedSources, scoredSources), warnings, browserRequiredSources },
				});
				const fetchResult = await runWithDeadline(
					(childSignal) => webFetchTool.execute("web_research_fetch", { url: scored.source.url }, childSignal),
					fetchAttemptTimeoutMs,
					`web_research fetch attempt timed out after ${Math.ceil(fetchAttemptTimeoutMs / 1000)} seconds`,
					signal,
				).catch((error): AgentToolResult<WebFetchDetails> => ({
					content: [{ type: "text", text: error instanceof Error ? error.message : String(error) }],
					details: {
						url: scored.source.url,
						sourceUrl: scored.source.url,
						durationMs: Date.now() - startedAt,
						failureCategory: "timeout",
					},
					isError: true,
				}));
				const details = contentDetails(fetchResult) as Partial<WebFetchDetails>;
				const text = textFromResult(fetchResult);
				fetchDurationMs += Date.now() - startedAt;
				sourceReadDurations.push(Date.now() - startedAt);
				attempts.push({
					phase: "fetch",
					url: scored.source.url,
					status: fetchResult.isError ? "failed" : "completed",
					failureCategory: details.failureCategory,
					durationMs: Date.now() - startedAt,
				});
				if (details.requiresBrowser) {
					const browserEntry: WebResearchFetchedSource = {
						url: scored.source.url,
						finalUrl: details.finalUrl,
						title: details.title || scored.source.title,
						score: scored.score,
						scoreReasons: scored.reasons,
						requiresBrowser: true,
						failureCategory: details.failureCategory,
					};
					if (deps.renderedPageReader) {
						let browserStartedAt = Date.now();
						try {
							onUpdate?.({
								content: [{ type: "text", text: `Reading browser-rendered source: ${details.finalUrl || scored.source.url}` }],
								details: { query, actualQueries: [...new Set(actualQueries)], sources: dedupedSources, fetchedSources, providerAttempts, attempts, qualityScore: qualityScore(fetchedSources, scoredSources), warnings, browserRequiredSources },
							});
							const rendered = await runWithDeadline(
								(childSignal) => deps.renderedPageReader!({ url: details.finalUrl || scored.source.url, query }, childSignal),
								browserAttemptTimeoutMs,
								`web_research browser reader timed out after ${Math.ceil(browserAttemptTimeoutMs / 1000)} seconds`,
								signal,
							);
							browserDurationMs += Date.now() - browserStartedAt;
							sourceReadDurations.push(Date.now() - browserStartedAt);
							attempts.push({ phase: "browser", url: rendered.finalUrl || rendered.url, status: "completed", durationMs: Date.now() - browserStartedAt });
							fetchedSources.push({
								url: scored.source.url,
								finalUrl: rendered.finalUrl || rendered.url,
								title: rendered.title || details.title || scored.source.title,
								textExcerpt: excerpt(rendered.text),
								score: scored.score,
								scoreReasons: scored.reasons,
								extractionMethod: "browser_rendered",
								citationAnchors: rendered.citationAnchors,
								requiresBrowser: false,
								browserReadSummary: {
									screenshotPath: rendered.screenshotPath,
									consoleMessageCount: rendered.consoleMessages?.length,
									networkRequestCount: rendered.networkRequests?.length,
								},
							});
							return;
						} catch (error) {
							browserDurationMs += Date.now() - browserStartedAt;
							attempts.push({ phase: "browser", url: details.finalUrl || scored.source.url, status: "failed", failureCategory: "requires_browser", durationMs: Date.now() - browserStartedAt });
							warnings.push(`Browser reader failed for ${details.finalUrl || scored.source.url}: ${error instanceof Error ? error.message : String(error)}`);
						}
					}
					browserRequiredSources.push(browserEntry);
					return;
				}
				if (fetchResult.isError || !text) {
					warnings.push(`Could not fetch ${scored.source.url}: ${details.failureCategory || "fetch_failed"}`);
					return;
				}
				fetchedSources.push({
					url: scored.source.url,
					finalUrl: details.finalUrl || scored.source.url,
					title: details.title || scored.source.title,
					textExcerpt: excerpt(text),
					score: scored.score,
					scoreReasons: scored.reasons,
					extractionMethod: details.extractionMethod,
					citationAnchors: details.citationAnchors,
					requiresBrowser: false,
					failureCategory: details.failureCategory,
				});
			};

			for (let index = 0; index < candidateSources.length && fetchedSources.length < maxSources; index += 3) {
				if (fetchedSources.length >= targetFetchedSources && qualityScore(fetchedSources, scoredSources) >= 75) {
					warnings.push(`Stopped after ${fetchedSources.length} credible fetched source(s); quality target reached before max_sources=${maxSources}.`);
					break;
				}
				const remaining = maxSources - fetchedSources.length;
				const batch = candidateSources
					.slice(index, index + Math.min(3, remaining))
					.filter((scored) => fetchedSources.length < minimumFetchedSources || scored.score >= 55);
				if (!batch.length) continue;
				await Promise.all(batch.map((scored) => fetchScoredSource(scored)));
			}

			const score = qualityScore(fetchedSources, scoredSources);
			const details: WebResearchDetails = {
				query,
				actualQueries: [...new Set(actualQueries)],
				sources: dedupedSources,
				fetchedSources,
				providerAttempts,
				attempts,
				qualityScore: score,
				warnings: [...new Set(warnings)],
				browserRequiredSources,
				providerHealth: nextHealth,
				routeRankReason,
				latencyMetrics: {
					totalDurationMs: Date.now() - totalStartedAt,
					searchDurationMs,
					fetchDurationMs,
					browserDurationMs,
					p95SourceReadMs: percentile(sourceReadDurations, 95),
				},
				costEstimate: {
					status: "unknown",
					reason: "Provider usage is not yet normalized across web research search/fetch/browser routes.",
				},
			};

			if (fetchedSources.length === 0) {
				const reason = browserRequiredSources.length
					? "web_research found candidate sources, but they require browser-rendered reading and no host browser reader completed."
					: "web_research could not fetch any credible source for this query.";
				return {
					content: [{ type: "text", text: `${reason}\n\nQueries tried: ${details.actualQueries.join("; ") || query}` }],
					details,
					isError: true,
				};
			}

			return {
				content: [{ type: "text", text: formatResearchPack(query, fetchedSources, details.warnings, browserRequiredSources) }],
				details,
			};
		},
	} as AgentTool<typeof webResearchSchema, WebResearchDetails>;
}
