import type { Agent } from "@pie/agent-core";
import type { TodoItem } from "@pie/shared-headless-capabilities";
import type { SessionRecord } from "./session-store.js";
import { createSessionRecord, deleteSession, isSessionEmpty, saveSession } from "./session-store.js";

export interface SessionRuntimeDeps {
  agent: Agent;
  projectRoot: string;
  getProvider: () => string;
  getModelId: () => string;
  getCurrentSession: () => SessionRecord;
  setCurrentSession: (record: SessionRecord) => void;
  getTodoState: () => TodoItem[];
  resetAgentForSessionSwitch: () => void;
  rebuildAgentSurface: () => void;
  setAgentModel: () => void;
  emitSessionSync: () => void;
}

export function createSessionRuntime(deps: SessionRuntimeDeps) {
  function syncSessionInfo() {
    deps.agent.sessionId = deps.getCurrentSession().id;
  }

  async function persistCurrentSession() {
    const currentSession = deps.getCurrentSession();
    const nextRecord: SessionRecord = {
      ...currentSession,
      provider: deps.getProvider(),
      modelId: deps.getModelId(),
      messages: deps.agent.state.messages.slice(),
      todoState: deps.getTodoState(),
    };
    if (isSessionEmpty(nextRecord)) {
      await deleteSession(deps.projectRoot, nextRecord.id);
      deps.setCurrentSession({
        ...nextRecord,
        title: "New Session",
        messageCount: 0,
      });
      syncSessionInfo();
      return;
    }

    deps.setCurrentSession(await saveSession(deps.projectRoot, nextRecord));
    syncSessionInfo();
  }

  async function persistCurrentSessionForRecovery() {
    const nextRecord: SessionRecord = {
      ...deps.getCurrentSession(),
      provider: deps.getProvider(),
      modelId: deps.getModelId(),
      messages: deps.agent.state.messages.slice(),
      todoState: deps.getTodoState(),
    };
    deps.setCurrentSession(await saveSession(deps.projectRoot, nextRecord));
    syncSessionInfo();
  }

  async function persistCurrentSessionForRecoveryWithPendingUserMessage(content: string) {
    const pendingMessage = {
      role: "user" as const,
      content: [{ type: "text" as const, text: content }],
      timestamp: Date.now(),
    };
    const nextRecord: SessionRecord = {
      ...deps.getCurrentSession(),
      provider: deps.getProvider(),
      modelId: deps.getModelId(),
      messages: [...deps.agent.state.messages.slice(), pendingMessage],
      todoState: deps.getTodoState(),
    };
    deps.setCurrentSession(await saveSession(deps.projectRoot, nextRecord));
    syncSessionInfo();
  }

  function startFreshSession(parentSessionId?: string) {
    deps.resetAgentForSessionSwitch();
    deps.setCurrentSession(createSessionRecord({
      parentSessionId,
      provider: deps.getProvider(),
      modelId: deps.getModelId(),
      messages: [],
      todoState: [],
    }));
    deps.agent.reset();
    deps.setAgentModel();
    deps.rebuildAgentSurface();
    syncSessionInfo();
    deps.emitSessionSync();
  }

  function restoreSessionRecord(record: SessionRecord) {
    deps.resetAgentForSessionSwitch();
    deps.setCurrentSession(record);
    deps.agent.replaceMessages(record.messages || []);
    deps.setAgentModel();
    deps.rebuildAgentSurface();
    syncSessionInfo();
    deps.emitSessionSync();
  }

  async function forkFromRecord(record: SessionRecord) {
    const forked = createSessionRecord({
      parentSessionId: record.id,
      provider: record.provider || deps.getProvider(),
      modelId: record.modelId || deps.getModelId(),
      messages: (record.messages || []).slice(),
      todoState: (record.todoState || []).slice(),
    });
    restoreSessionRecord(forked);
    await persistCurrentSession();
  }

  return {
    syncSessionInfo,
    persistCurrentSession,
    persistCurrentSessionForRecovery,
    persistCurrentSessionForRecoveryWithPendingUserMessage,
    startFreshSession,
    restoreSessionRecord,
    forkFromRecord,
  };
}
