/**
 * Sandbox-aware path resolution for filesystem tools.
 */

import { getFileSystem } from "@pie/platform";

export interface FileToolRoot {
	name: string;
	path: string;
	description?: string;
	defaultPrefixes?: string[];
}

export interface PathResolutionOptions {
	/** Allowlisted directories that can be accessed regardless of sandbox */
	allowlistedDirs?: string[];
	/** Named roots available to path-based tools */
	roots?: FileToolRoot[];
	/** Default root to use when root is omitted and no prefix rule matches */
	defaultRoot?: string;
}

/**
 * Check if a path is within any of the allowlisted directories
 */
function isInAllowlist(path: string, allowlistedDirs: string[]): boolean {
	const normalized = normalizeForComparison(path);
	for (const dir of allowlistedDirs) {
		const normalizedDir = normalizeForComparison(dir);
		const dirWithSlash = withTrailingSep(normalizedDir);
		if (normalized === normalizedDir || normalized.startsWith(dirWithSlash)) {
			return true;
		}
	}
	return false;
}

function normalizeForComparison(path: string): string {
	const normalized = path.replace(/\\/g, "/").replace(/\/+/g, "/");
	if (normalized === "/") return normalized;
	return normalized.replace(/\/+$/, "");
}

function validateToolPathArgument(filePath: string): void {
	const trimmed = filePath.trim();
	if (/^:\s*\d+\s*$/.test(trimmed)) {
		throw new Error(`Invalid path "${filePath}". Do not pass a line number as the path; pass the real file path and use offset for line numbers.`);
	}
	if (trimmed.includes("<|tool")) {
		throw new Error(`Invalid path "${filePath}". The path argument must be only a real file path, not tool-call markup.`);
	}
	if (trimmed.includes("\n")) {
		throw new Error(`Invalid path "${filePath}". The path argument must be a single file path, not multi-line text.`);
	}
}

function withTrailingSep(path: string): string {
	return path.endsWith("/") ? path : `${path}/`;
}

function isWithinRoot(path: string, root: string): boolean {
	const normalizedPath = normalizeForComparison(path);
	const normalizedRoot = normalizeForComparison(root);
	return normalizedPath === normalizedRoot || normalizedPath.startsWith(withTrailingSep(normalizedRoot));
}

function normalizePrefix(prefix: string): string {
	const normalized = normalizeForComparison(prefix);
	return normalized.startsWith("/") ? normalized.slice(1) : normalized;
}

export function getAvailableRoots(options?: PathResolutionOptions): FileToolRoot[] {
	if (!options?.roots || options.roots.length === 0) {
		return [];
	}

	const fs = getFileSystem();
	const seen = new Set<string>();
	const results: FileToolRoot[] = [];

	for (const root of options.roots) {
		if (!root || typeof root.name !== "string" || typeof root.path !== "string") {
			continue;
		}

		const name = root.name.trim();
		const path = root.path.trim();
		if (!name || !path || seen.has(name)) {
			continue;
		}

		seen.add(name);
		results.push({
			name,
			path: fs.normalize(path),
			description: root.description?.trim() || undefined,
			defaultPrefixes: Array.isArray(root.defaultPrefixes)
				? root.defaultPrefixes
					.map((prefix) => String(prefix || "").trim())
					.filter((prefix) => prefix.length > 0)
				: undefined,
		});
	}

	return results;
}

export function getDefaultRootName(
	sandboxRoot: string,
	options?: PathResolutionOptions,
): string | undefined {
	const roots = getAvailableRoots(options);
	if (roots.length === 0) {
		return undefined;
	}

	const configured = (options?.defaultRoot || "").trim();
	if (configured && roots.some((root) => root.name === configured)) {
		return configured;
	}

	const normalizedSandboxRoot = normalizeForComparison(sandboxRoot);
	const sandboxMatch = roots.find(
		(root) => normalizeForComparison(root.path) === normalizedSandboxRoot,
	);
	if (sandboxMatch) {
		return sandboxMatch.name;
	}

	return roots[0]?.name;
}

function getRootByName(
	name: string | undefined,
	sandboxRoot: string,
	options?: PathResolutionOptions,
): FileToolRoot | undefined {
	const roots = getAvailableRoots(options);
	if (roots.length === 0) {
		return undefined;
	}

	const resolvedName = (name || "").trim() || getDefaultRootName(sandboxRoot, options);
	if (!resolvedName) {
		return undefined;
	}

	return roots.find((root) => root.name === resolvedName);
}

function findPrefixMatchedRoot(
	filePath: string,
	options?: PathResolutionOptions,
): FileToolRoot | undefined {
	const normalizedPath = normalizeForComparison(filePath);
	for (const root of getAvailableRoots(options)) {
		for (const prefix of root.defaultPrefixes ?? []) {
			const normalizedPrefix = normalizePrefix(prefix);
			if (
				normalizedPath === normalizedPrefix ||
				normalizedPath.startsWith(withTrailingSep(normalizedPrefix))
			) {
				return root;
			}
		}
	}

	return undefined;
}

function getResolutionRoot(
	filePath: string,
	sandboxRoot: string,
	options?: PathResolutionOptions,
	rootName?: string,
): FileToolRoot | undefined {
	if (rootName) {
		return getRootByName(rootName, sandboxRoot, options);
	}

	return findPrefixMatchedRoot(filePath, options)
		?? getRootByName(undefined, sandboxRoot, options);
}

/**
 * Resolve a user-provided path within the sandbox root.
 * - Relative paths are resolved against sandboxRoot or the selected named root.
 * - Absolute paths are rejected unless inside the selected root, another named root, or allowlist.
 * - Path traversal (../) that escapes the chosen boundary is rejected.
 */
export function resolveInSandbox(
	filePath: string,
	sandboxRoot: string,
	options?: PathResolutionOptions,
	rootName?: string,
): string {
	const fs = getFileSystem();
	const allowlistedDirs = options?.allowlistedDirs ?? [];

	if (!filePath) {
		throw new Error("Path cannot be empty");
	}
	validateToolPathArgument(filePath);

	// Strip leading @ if present (pi-mono convention)
	const cleaned = filePath.trim().startsWith("@") ? filePath.trim().slice(1) : filePath.trim();

	if (fs.isAbsolute(cleaned)) {
		const normalized = fs.normalize(cleaned);
		const selectedRoot = rootName ? getRootByName(rootName, sandboxRoot, options) : undefined;

		if (rootName && !selectedRoot) {
			const available = getAvailableRoots(options).map((root) => root.name).join(", ");
			throw new Error(
				available
					? `Unknown root '${rootName}'. Available roots: ${available}`
					: `Unknown root '${rootName}'. No named roots are configured.`,
			);
		}

		if (selectedRoot) {
			if (!isWithinRoot(normalized, selectedRoot.path)) {
				throw new Error(`Absolute path outside root '${selectedRoot.name}': ${filePath}`);
			}
			return normalized;
		}

		for (const root of getAvailableRoots(options)) {
			if (isWithinRoot(normalized, root.path)) {
				return normalized;
			}
		}

		if (isInAllowlist(normalized, allowlistedDirs)) {
			return normalized;
		}

		if (!isWithinRoot(normalized, sandboxRoot)) {
			throw new Error(`Absolute path outside sandbox: ${filePath}`);
		}
		return normalized;
	}

	const selectedRoot = getResolutionRoot(cleaned, sandboxRoot, options, rootName);
	if (rootName && !selectedRoot) {
		const available = getAvailableRoots(options).map((root) => root.name).join(", ");
		throw new Error(
			available
				? `Unknown root '${rootName}'. Available roots: ${available}`
				: `Unknown root '${rootName}'. No named roots are configured.`,
		);
	}

	const resolvedBase = selectedRoot?.path ?? sandboxRoot;
	const resolved = fs.resolve(resolvedBase, cleaned);

	if (selectedRoot) {
		if (!isWithinRoot(resolved, selectedRoot.path)) {
			throw new Error(`Path escapes root '${selectedRoot.name}': ${filePath}`);
		}
		return resolved;
	}

	if (!isWithinRoot(resolved, sandboxRoot) && !isInAllowlist(resolved, allowlistedDirs)) {
		throw new Error(`Path escapes sandbox: ${filePath}`);
	}

	return resolved;
}

// Aliases for compatibility with pi-mono tool code
export const resolveToCwd = resolveInSandbox;
export const resolveReadPath = resolveInSandbox;
