/**
 * @pie/ai - LLM API abstraction layer
 * 
 * Registers the openai-completions and anthropic-messages providers and re-exports everything.
 */

// Re-export TypeBox for tool schema definitions
export type { Static, TSchema } from "@sinclair/typebox";
export { Type } from "@sinclair/typebox";

// Register providers
import { registerApiProvider } from "./api-registry.js";
import { streamOpenAICompletions, streamSimpleOpenAICompletions } from "./providers/openai-compat.js";
import { streamAnthropic, streamSimpleAnthropic } from "./providers/anthropic.js";

registerApiProvider({
	api: "openai-completions",
	stream: streamOpenAICompletions,
	streamSimple: streamSimpleOpenAICompletions,
});

registerApiProvider({
	api: "anthropic-messages",
	stream: streamAnthropic,
	streamSimple: streamSimpleAnthropic,
});

// Re-export public API
export * from "./api-registry.js";
export * from "./cache-capabilities.js";
export * from "./env-api-keys.js";
export * from "./models.js";
export type { ModelConfig } from "./models.js";
export * from "./models.builtins.js";
export * from "./providers/anthropic.js";
export * from "./providers/openai-compat.js";
export * from "./stream.js";
export * from "./tool-model-routing.js";
export * from "./types.js";
export * from "./utils/event-stream.js";
export * from "./utils/json-parse.js";
export * from "./utils/validation.js";
