import type { Api, Model, ToolModelRouteDecision } from "@pie/ai";
import {
  createSharedWebFetchTool,
  createSharedWebResearchTool,
  createSharedWebSearchTool,
} from "@pie/shared-headless-capabilities";
import type { AgentTool } from "@pie/agent-core";

export interface UnityWebTools {
  webSearchTool: AgentTool;
  webFetchTool: AgentTool;
  webResearchTool: AgentTool;
}

export function createUnityWebTools(params: {
  getActiveModel: () => Model<Api>;
  getActiveApiKey: () => string | undefined;
  resolveToolModelCandidates: (purpose: "web_search") => ToolModelRouteDecision[];
  fetch: typeof fetch;
}): UnityWebTools {
  const getCurrentDateContext = () => ({
    currentDate: new Date().toISOString().slice(0, 10),
    timeZone: "local",
  });
  const webSearchTool = createSharedWebSearchTool({
    getModel: params.getActiveModel,
    getApiKey: params.getActiveApiKey,
    getMode: () => "auto",
    resolveToolModelCandidates: params.resolveToolModelCandidates,
    getCurrentDateContext,
    fetch: params.fetch,
  });
  const webFetchTool = createSharedWebFetchTool({
    getModel: params.getActiveModel,
    getApiKey: params.getActiveApiKey,
    fetch: params.fetch,
  });
  const webResearchTool = createSharedWebResearchTool({
    getModel: params.getActiveModel,
    getApiKey: params.getActiveApiKey,
    getMode: () => "auto",
    resolveToolModelCandidates: params.resolveToolModelCandidates,
    timeoutMs: 90_000,
    searchAttemptTimeoutMs: 90_000,
    getCurrentDateContext,
    fetch: params.fetch,
    webFetchTool,
  });
  return { webSearchTool, webFetchTool, webResearchTool };
}
