import { Type } from "@sinclair/typebox";
import { defineSharedCapability } from "./capability.js";

export interface SkillResourceReference {
	path: string;
	kind?: string;
}

export interface ResolvedSkillResource {
	owner: string;
	path: string;
	content: string;
	kind?: string;
	mimeType?: string;
}

export interface ReadResourceCapabilityDeps {
	resolveResource?(
		owner: string,
		path: string,
	): ResolvedSkillResource | null | Promise<ResolvedSkillResource | null>;
}

export const ReadResourceParamsSchema = Type.Object({
	owner: Type.String({ description: "Exact skill name that owns the resource." }),
	path: Type.String({ description: "Relative path inside the skill package." }),
});

function inferKind(path: string): string | undefined {
	const lower = path.toLowerCase();
	if (lower.endsWith(".md")) return "document";
	if (lower.endsWith(".js") || lower.endsWith(".mjs") || lower.endsWith(".sh") || lower.endsWith(".py")) return "script";
	return undefined;
}

function inferMimeType(path: string): string | undefined {
	const lower = path.toLowerCase();
	if (lower.endsWith(".md")) return "text/markdown";
	if (lower.endsWith(".js") || lower.endsWith(".mjs")) return "application/javascript";
	if (lower.endsWith(".sh")) return "text/x-shellscript";
	if (lower.endsWith(".py")) return "text/x-python";
	if (lower.endsWith(".json")) return "application/json";
	if (lower.endsWith(".txt")) return "text/plain";
	return undefined;
}

function validateRelativeResourcePath(path: string): string {
	const trimmed = String(path || "").trim().replace(/\\/g, "/");
	if (!trimmed) {
		throw new Error("Resource path cannot be empty");
	}
	if (trimmed.startsWith("/") || /^[A-Za-z]:\//.test(trimmed)) {
		throw new Error("Resource path must be relative");
	}
	const segments = trimmed.split("/");
	if (segments.some((segment) => segment === "..")) {
		throw new Error("Resource path cannot escape the skill package");
	}
	return trimmed.replace(/^\.\/+/, "");
}

export function createReadResourceCapability(deps: ReadResourceCapabilityDeps) {
	const tool = {
		name: "read_resource",
		label: "read_resource",
		description: "Load a relative resource file from inside a skill package by owner and path.",
		parameters: ReadResourceParamsSchema,
		async execute(toolCallIdOrArgs: string | { owner: string; path: string }, maybeArgs?: { owner: string; path: string }) {
			const args = typeof toolCallIdOrArgs === "string" ? maybeArgs : toolCallIdOrArgs;
			const owner = String(args?.owner || "").trim();
			let resourcePath = "";
			try {
				resourcePath = validateRelativeResourcePath(args?.path || "");
			} catch (error) {
				return {
					content: [{ type: "text" as const, text: error instanceof Error ? error.message : String(error) }],
					details: { found: false, owner: owner || undefined, path: args?.path || undefined },
					isError: true,
				};
			}

			const resource = await deps.resolveResource?.(owner, resourcePath);
			if (!resource?.content) {
				return {
					content: [{ type: "text" as const, text: `Resource not found: ${owner || "(empty)"}/${resourcePath || "(empty)"}` }],
					details: { found: false, owner: owner || undefined, path: resourcePath || undefined },
					isError: true,
				};
			}

			const kind = resource.kind || inferKind(resource.path);
			const mimeType = resource.mimeType || inferMimeType(resource.path);
			return {
				content: [{
					type: "text" as const,
					text: `# ${resource.owner}/${resource.path}\n\n${resource.content}`,
				}],
				details: {
					found: true,
					owner: resource.owner,
					path: resource.path,
					kind,
					mimeType,
				},
			};
		},
	};

	return {
		...defineSharedCapability({
			id: "read-resource",
			description: "Shared capability for loading resources scoped to a skill package.",
			tools: [tool],
		}),
		tool,
	};
}
