import { requiredCapabilityForToolPurpose, type Api, type Model, type ToolModelPurpose, type ToolModelRouteDecision } from "@pie/ai";
import type { PieBridge } from "./pie-bridge.js";
import { describeUnityToolModelRoutes, resolveUnityToolModelCandidates, type UnityRuntimeModelCredential } from "./model-profiles.js";

export interface UnityToolModelRuntimeOptions {
  bridge: PieBridge;
  getActiveModel: () => Model<Api>;
}

export interface UnityToolModelRuntime {
  describeRoutes(): string[];
  getRuntimeApiKeyFor(provider: string, modelId: string): string | undefined;
  resolveCandidates(purpose: ToolModelPurpose): ToolModelRouteDecision[];
  resolvePreferred(purpose: ToolModelPurpose): ToolModelRouteDecision;
  setRuntimeCredential(provider: string, modelId: string, apiKey: string): void;
}

export function createUnityToolModelRuntime(options: UnityToolModelRuntimeOptions): UnityToolModelRuntime {
  let runtimeCredential: UnityRuntimeModelCredential | null = null;

  function getRuntimeCredential(): UnityRuntimeModelCredential | null {
    return runtimeCredential;
  }

  function getRuntimeApiKeyFor(provider: string, modelId: string): string | undefined {
    if (!runtimeCredential?.apiKey) return undefined;
    return runtimeCredential.provider === provider && runtimeCredential.modelId === modelId
      ? runtimeCredential.apiKey
      : undefined;
  }

  function resolveCandidates(purpose: ToolModelPurpose): ToolModelRouteDecision[] {
    return resolveUnityToolModelCandidates(options.bridge, purpose, options.getActiveModel(), {
      runtimeCredential: getRuntimeCredential(),
    });
  }

  return {
    describeRoutes: () => describeUnityToolModelRoutes(options.bridge, options.getActiveModel(), {
      runtimeCredential: getRuntimeCredential(),
    }),
    getRuntimeApiKeyFor,
    resolveCandidates,
    resolvePreferred: (purpose) => {
      const candidates = resolveCandidates(purpose);
      return candidates.find((candidate) => candidate.model && candidate.apiKey)
        || candidates[0]
        || {
          purpose,
          requiredCapability: requiredCapabilityForToolPurpose(purpose),
          routeSource: "unavailable",
          fallbackReason: `No configured model declares capability for ${purpose}.`,
        };
    },
    setRuntimeCredential(provider, modelId, apiKey) {
      const normalizedApiKey = String(apiKey || "");
      if (!normalizedApiKey) {
        if (runtimeCredential?.provider === provider && runtimeCredential.modelId === modelId) {
          runtimeCredential = null;
        }
        return;
      }
      runtimeCredential = { provider, modelId, apiKey: normalizedApiKey };
    },
  };
}
